window.STATE_SPECIAL["OR"] = {"code":"OR","name":"Oregon","agency":"Oregon DMV","agencyShort":"DMV","handbook":"https://www.oregon.gov/odot/dmv/pages/online_cdl_manual_2/section_i.aspx","links":{},"en":[{"q":"What is the maximum legal width for most commercial vehicles on Oregon highways without an over-dimension permit?","options":["8 feet (96 inches)","8 feet 6 inches (102 inches)","9 feet (108 inches)","10 feet (120 inches)"],"answer":1,"explanation":"Oregon limits total outside vehicle width to 8 feet 6 inches (102 inches) on public highways; anything wider requires an over-dimension permit. Source: ORS 818.080 (Maximum size limits) and Oregon DOT Commerce and Compliance Division, Legal Vehicle Dimensions.","handbook":"","hbref":""},{"q":"What is the maximum legal height, including load, for a vehicle operating on Oregon highways without a permit?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"answer":1,"explanation":"Oregon sets the maximum height, including any load, at 14 feet; exceeding this requires an over-dimension permit and route clearance. Source: ORS 818.080 and Oregon DOT Legal Vehicle Dimensions.","handbook":"","hbref":""},{"q":"Without a special length permit, what is the maximum overall length of most truck-tractor and semitrailer combinations on Oregon's general highways?","options":["50 feet","55 feet","60 feet","75 feet"],"answer":2,"explanation":"On Oregon's general highways the maximum overall length for a combination of vehicles is 60 feet; longer combinations are allowed only on designated routes or under permit. Source: ORS 818.080 and Oregon DOT Legal Vehicle Dimensions.","handbook":"","hbref":""},{"q":"On designated Oregon routes that allow unlimited overall length, what is the maximum length of a single semitrailer in a tractor-semitrailer combination?","options":["48 feet","53 feet","57 feet","60 feet"],"answer":1,"explanation":"Oregon allows a maximum semitrailer length of 53 feet; on designated routes overall combination length may be unlimited, but the semitrailer itself may not exceed 53 feet. Source: ORS 818.080 and Oregon DOT Legal Vehicle Dimensions.","handbook":"","hbref":""},{"q":"What is the maximum length of a single (solo) vehicle on Oregon highways without a permit?","options":["35 feet","40 feet","45 feet","53 feet"],"answer":1,"explanation":"A single vehicle operating alone in Oregon may not exceed 40 feet in length without a permit. Source: ORS 818.080 (Maximum size limits).","handbook":"","hbref":""},{"q":"In Oregon, what is the maximum allowable weight on any single axle without an overweight permit?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"answer":1,"explanation":"Oregon limits any single axle to 20,000 pounds. Source: ORS 818.010 (Maximum allowable weight).","handbook":"","hbref":""},{"q":"What is the maximum allowable weight on a tandem axle group in Oregon without an overweight permit?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"answer":1,"explanation":"Oregon limits a tandem axle (two axles) to 34,000 pounds, matching the federal standard. Source: ORS 818.010 (Maximum allowable weight).","handbook":"","hbref":""},{"q":"What is the maximum gross vehicle weight generally allowed on Oregon highways without an overweight or extended-weight permit?","options":["73,280 pounds","80,000 pounds","88,000 pounds","105,500 pounds"],"answer":1,"explanation":"The standard maximum gross combination weight in Oregon is 80,000 pounds; heavier divisible loads require an ODOT extended weight permit. Source: ORS 818.010 and Oregon DOT Commerce and Compliance Division.","handbook":"","hbref":""},{"q":"Under an ODOT extended (divisible load) weight permit, what is the maximum gross combination weight a qualifying vehicle may haul in Oregon?","options":["90,000 pounds","98,000 pounds","105,500 pounds","129,000 pounds"],"answer":2,"explanation":"Oregon's extended weight permit allows qualifying multi-axle combinations to operate up to 105,500 pounds gross weight when hauling divisible loads. Source: Oregon DOT Commerce and Compliance Division, Extended Weight (Divisible Load) Permit.","handbook":"","hbref":""},{"q":"Oregon law caps the load that may be carried on tires based on tire width. What is the maximum pounds per inch of tire width allowed?","options":["500 pounds per inch","550 pounds per inch","600 pounds per inch","650 pounds per inch"],"answer":2,"explanation":"Oregon uses the manufacturer's sidewall tire rating, but not to exceed 600 pounds per inch of tire width, multiplied by the sum of the tire widths. Source: ORS 818.010 (Maximum allowable weight).","handbook":"","hbref":""},{"q":"Which formula does Oregon apply to determine the maximum gross weight allowed on a group of consecutive axles based on their spacing?","options":["The Federal Bridge Formula (Bridge Gross Weight Formula)","The GAWR rating formula","The Oregon mileage-tax formula","The Cargo Securement Formula"],"answer":0,"explanation":"Oregon adopts the Federal Bridge Formula, W = 500[LN/(N-1) + 12N + 36], to limit the weight on any group of two or more consecutive axles based on axle spacing and number of axles. Source: ORS 818.010 and 23 CFR 658 as applied by Oregon DOT.","handbook":"","hbref":""},{"q":"In the Federal Bridge Formula used in Oregon, what does the variable 'L' represent?","options":["The legal load limit in tons","The distance in feet between the outer axles of the group","The length of the trailer in feet","The number of license plates required"],"answer":1,"explanation":"In the bridge formula W = 500[LN/(N-1) + 12N + 36], L is the distance in feet between the outermost axles of the group, N is the number of axles, and W is the allowable gross weight. Source: Federal Bridge Formula as applied by Oregon DOT; ORS 818.010.","handbook":"","hbref":""},{"q":"When is an Oregon DOT over-dimension or overweight permit required for a commercial vehicle?","options":["Only when crossing a state line","Whenever the vehicle or load exceeds the legal size or weight limits","Only on weekends and holidays","Only for vehicles registered out of state"],"answer":1,"explanation":"Any vehicle or load that exceeds Oregon's legal limits for width, height, length, or weight must obtain an over-dimension/overweight permit before operating. Source: ORS 818.200 and Oregon DOT Commerce and Compliance Division, Over-Dimension Operations.","handbook":"","hbref":""},{"q":"Which Oregon agency issues oversize and overweight (over-dimension) permits for commercial vehicles?","options":["The Oregon State Police","The Oregon DOT Commerce and Compliance Division","The county sheriff's office","The Federal Motor Carrier Safety Administration"],"answer":1,"explanation":"Over-dimension and overweight permits in Oregon are issued by the Oregon Department of Transportation's Commerce and Compliance Division (formerly Motor Carrier Transportation Division), available online or at ports of entry. Source: Oregon DOT Commerce and Compliance Division.","handbook":"","hbref":""},{"q":"What is the maximum weight Oregon allows on any individual wheel?","options":["8,000 pounds","10,000 pounds","12,000 pounds","17,000 pounds"],"answer":1,"explanation":"Oregon limits the weight on any individual wheel to 10,000 pounds. Source: ORS 818.010 (Maximum allowable weight).","handbook":"","hbref":""},{"q":"A 'divisible load' that exceeds Oregon's 80,000-pound limit is one that:","options":["Cannot be separated without excessive expense or risk of damage","Can reasonably be split into smaller, legal loads","Is always classified as hazardous material","Must be hauled only at night"],"answer":1,"explanation":"A divisible load can reasonably be broken into smaller legal loads; in Oregon such loads may exceed 80,000 pounds only under an ODOT extended (divisible load) weight permit, unlike non-divisible loads which use over-dimension variance permits. Source: Oregon DOT Commerce and Compliance Division.","handbook":"","hbref":""},{"q":"Without a permit, what is the maximum load overhang allowed off the FRONT of a vehicle in Oregon?","options":["3 feet","4 feet","5 feet","6 feet"],"answer":1,"explanation":"Oregon allows a maximum front load overhang of 4 feet without a permit; greater front overhang requires an over-dimension permit and flagging. Source: ORS 818.080 and Oregon DOT Legal Vehicle Dimensions.","handbook":"","hbref":""},{"q":"In the Federal Bridge Formula as applied in Oregon, increasing the spacing between the outer axles of a group, while keeping the number of axles the same, generally:","options":["Decreases the allowable gross weight","Has no effect on allowable weight","Increases the allowable gross weight","Voids the truck's registration"],"answer":2,"explanation":"Because L (axle spacing) is in the numerator, greater distance between outer axles increases the allowable gross weight for that axle group; closely spaced axles are limited to protect bridges. Source: Federal Bridge Formula as applied by Oregon DOT; ORS 818.010.","handbook":"","hbref":""},{"q":"Oregon grants certain weight tolerances and reduced-fee permits for which type of hauling that is important to the state's economy?","options":["Passenger charter buses","Agricultural and forest (log) products hauling","Interstate package delivery vans","Rental moving trucks"],"answer":1,"explanation":"Oregon provides specific permits and weight provisions for agricultural commodities and forest/log products (e.g., reduced or registration-weight tolerances and extended-weight log permits) reflecting the importance of farming and timber to the state. Source: Oregon DOT Commerce and Compliance Division and ORS Chapter 818 permit provisions.","handbook":"","hbref":""},{"q":"In Oregon, which class of CDL is required to drive any combination of vehicles with a Gross Combination Weight Rating (GCWR) of 26,001 pounds or more, provided the vehicle being towed is heavier than 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Oregon follows the standard CDL classes: a Class A CDL covers any combination of vehicles with a GCWR of 26,001 lbs or more where the towed unit exceeds 10,000 lbs. Source: Oregon Commercial Driver Manual / Oregon DMV Driver License Classes (mirrors 49 CFR 383.91; ORS 807.031).","handbook":"","hbref":""},{"q":"Under Oregon rules, which CDL class covers a single vehicle with a Gross Vehicle Weight Rating (GVWR) of 26,001 pounds or more, or such a vehicle towing a unit not over 10,000 pounds?","options":["Class A","Class B","Class C","Class M"],"answer":1,"explanation":"A Class B CDL in Oregon covers a single vehicle with a GVWR of 26,001 lbs or more, or such a vehicle towing a trailer not exceeding 10,000 lbs. Source: Oregon Commercial Driver Manual / Oregon DMV Driver License Classes (49 CFR 383.91).","handbook":"","hbref":""},{"q":"In Oregon, a smaller vehicle that does not meet the Class A or Class B weight thresholds still requires a Class C CDL if it is designed to transport at least how many people, including the driver?","options":["10","12","16","24"],"answer":2,"explanation":"A Class C CDL is required for a vehicle (not meeting Class A or B) designed to carry 16 or more persons including the driver, or used to transport placarded hazardous materials. Source: Oregon Commercial Driver Manual / Oregon DMV Driver License Classes (49 CFR 383.91).","handbook":"","hbref":""},{"q":"Besides carrying 16 or more passengers, what is the other condition that requires a Class C CDL in Oregon for a vehicle too small to be Class A or B?","options":["Towing any trailer over 5,000 pounds","Transporting hazardous materials in amounts requiring placards","Operating after dark on a state highway","Carrying any farm products for hire"],"answer":1,"explanation":"Oregon requires a Class C CDL for a smaller vehicle used to transport hazardous materials in quantities requiring placards (or to carry 16+ persons). Source: Oregon Commercial Driver Manual; Oregon DMV CDL Classes (49 CFR 383.91).","handbook":"","hbref":""},{"q":"Which endorsement code does Oregon use for the Hazardous Materials endorsement on a CDL?","options":["H","N","T","X"],"answer":0,"explanation":"The Hazardous Materials endorsement is coded 'H' in Oregon. (Code 'X' represents a combined Tank and HazMat endorsement.) Source: Oregon DMV CDL Endorsements & Restrictions; Oregon Commercial Driver Manual.","handbook":"","hbref":""},{"q":"An Oregon driver needs to operate a commercial vehicle pulling double or triple trailers. Which endorsement is required?","options":["P endorsement","N endorsement","T endorsement","S endorsement"],"answer":2,"explanation":"The 'T' (Doubles/Triples) endorsement is required in Oregon to drive any commercial motor vehicle pulling double or triple trailers, and is obtained by passing a knowledge test. Source: Oregon DMV CDL Endorsements; Oregon Commercial Driver Manual.","handbook":"","hbref":""},{"q":"In Oregon, the Tank Vehicle (N) endorsement is required when a CMV is designed to haul liquid or gas in a tank rated at more than 119 gallons individually AND with an aggregate rated capacity of at least how many gallons?","options":["500 gallons","750 gallons","1,000 gallons","1,500 gallons"],"answer":2,"explanation":"Oregon requires the N (Tank) endorsement for a vehicle transporting liquid or gas in a tank rated at more than 119 gallons individually with an aggregate rated capacity of 1,000 gallons or more. Source: Oregon Commercial Driver Manual; Oregon DMV CDL Endorsements (49 CFR 383.5).","handbook":"","hbref":""},{"q":"Which Oregon CDL endorsement is required to drive a vehicle designed to carry 16 or more people, including the driver?","options":["P (Passenger)","S (School Bus)","T (Doubles/Triples)","N (Tank)"],"answer":0,"explanation":"The 'P' (Passenger) endorsement is required in Oregon to operate a vehicle designed to transport 16 or more passengers including the driver; it requires a knowledge and a skills test. Source: Oregon DMV CDL Endorsements; Oregon Commercial Driver Manual.","handbook":"","hbref":""},{"q":"To drive a school bus in Oregon, which endorsement must a CDL holder add in addition to meeting the passenger-vehicle requirements?","options":["H endorsement","S endorsement","T endorsement","X endorsement"],"answer":1,"explanation":"The 'S' (School Bus) endorsement is required to drive a school bus in Oregon; an applicant must also hold the P endorsement and pass a school-bus knowledge and skills test. Source: Oregon DMV CDL Endorsements; Oregon Commercial Driver Manual.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain an Oregon CDL restricted to intrastate (in-Oregon-only) commercial driving?","options":["16 years old","18 years old","21 years old","25 years old"],"answer":1,"explanation":"Oregon requires an applicant to be at least 18 years old for an intrastate CDL; interstate driving requires age 21. Source: Oregon DMV 'Getting a CDL or CLP'; Oregon Commercial Driver Manual.","handbook":"","hbref":""},{"q":"Under Oregon rules, what is the minimum age to drive a commercial motor vehicle in interstate commerce?","options":["18 years old","19 years old","21 years old","23 years old"],"answer":2,"explanation":"Oregon requires a driver to be at least 21 years old to operate a CMV in interstate commerce; intrastate-only operation is allowed at 18. Source: Oregon DMV 'Getting a CDL or CLP'; Oregon Commercial Driver Manual.","handbook":"","hbref":""},{"q":"In Oregon, how long must a person hold a valid Commercial Learner Permit (CLP) before being allowed to take the CDL skills test?","options":["At least 7 days","At least 14 days","At least 30 days","At least 60 days"],"answer":1,"explanation":"Oregon requires an applicant to hold a valid CLP for at least 14 days before taking the CDL skills test, reflecting the federal mandatory hold period. Source: Oregon Commercial Driver Manual (Oregon Information); Oregon DMV (49 CFR 383.25).","handbook":"","hbref":""},{"q":"For how long are commercial knowledge test scores valid in Oregon when working toward a CDL?","options":["Three months","Six months","One year","Two years"],"answer":1,"explanation":"Oregon states that commercial knowledge test scores are valid for six months; the CDL application must be completed within that window. Source: Oregon Commercial Driver Manual (Oregon Information); Oregon DMV 'Getting a CDL or CLP.'","handbook":"","hbref":""},{"q":"Which of the following must an applicant present to the Oregon DMV when applying for a CDL or CLP?","options":["A notarized employer letter only","Proof of full legal name, identity, date of birth, lawful U.S. status, residence address, and a Social Security Number","A passport and nothing else","A high school diploma and two references"],"answer":1,"explanation":"Oregon DMV requires proof of full legal name, identity, date of birth, lawful status in the U.S., Oregon residence address, and the applicant's Social Security Number. Source: Oregon Commercial Driver Manual (Oregon Information); Oregon DMV 'Getting a CDL or CLP.'","handbook":"","hbref":""},{"q":"Before taking the CDL skills test for a first Class A or Class B license in Oregon, where must an applicant complete Entry-Level Driver Training (ELDT)?","options":["Any community college course","A provider listed on the FMCSA Training Provider Registry","An Oregon DMV field office","An employer's in-house program of any kind"],"answer":1,"explanation":"Oregon requires ELDT from a provider listed on FMCSA's Training Provider Registry (tpr.fmcsa.dot.gov) before scheduling the skills test for a first Class A/B CDL, a B-to-A upgrade, or a first P, S, or H endorsement. Source: Oregon Commercial Driver Manual; Oregon DMV (49 CFR Part 380).","handbook":"","hbref":""},{"q":"ELDT in Oregon is required before testing for which of these endorsements for the first time?","options":["Doubles/Triples (T)","Tank (N)","Hazardous Materials (H)","None of the endorsements require ELDT"],"answer":2,"explanation":"Oregon requires ELDT before taking the HazMat (H) knowledge test for the first time, as well as for first P or S endorsements and first Class A/B CDLs. The T and N endorsements are not on the ELDT list. Source: Oregon DMV; Oregon Commercial Driver Manual (49 CFR Part 380).","handbook":"","hbref":""},{"q":"An Oregon CDL applicant who will drive only within Oregon and is not subject to federal medical rules should self-certify under which category?","options":["Non-excepted Interstate (NI)","Excepted Interstate (EI)","Non-excepted Intrastate (NA)","Excepted Intrastate (EA)"],"answer":2,"explanation":"Oregon offers self-certification types; a driver operating a Class A, B, or C CMV only in intrastate commerce certifies Non-excepted Intrastate and must meet Oregon CDL medical standards rather than full federal standards. Source: Oregon DMV CDL Medical/Self-Certification; Oregon Commercial Driver Manual.","handbook":"","hbref":""},{"q":"Which self-certification category does the Oregon DMV recommend for most CDL drivers so their license is not needlessly restricted to Oregon-only use?","options":["Excepted Interstate","Non-excepted Interstate","Non-excepted Intrastate","Excepted Intrastate"],"answer":1,"explanation":"Oregon DMV recommends most drivers certify Non-excepted Interstate, which requires meeting all federal medical qualifications and also permits excepted-interstate and intrastate operation. Source: Oregon DMV CDL Self-Certification; Oregon Commercial Driver Manual.","handbook":"","hbref":""},{"q":"To obtain and keep an Oregon HazMat (H) endorsement, a driver must pass a Transportation Security Administration (TSA) security threat assessment, including fingerprinting, that must be renewed how often?","options":["Every 2 years","Every 3 years","Every 5 years","Every 8 years"],"answer":2,"explanation":"Oregon's HazMat endorsement requires a TSA security threat assessment with fingerprint-based background check that must be renewed every five years. Source: Oregon DMV CDL Endorsements & Restrictions (49 CFR 1572).","handbook":"","hbref":""},{"q":"A driver self-certifying as Excepted Interstate in Oregon must still meet which medical standard?","options":["No medical standard at all","Full federal interstate medical standards","Oregon CDL medical standards","Only a vision screening at renewal"],"answer":2,"explanation":"An Oregon driver who certifies Excepted Interstate engages only in operations excepted under federal rules (e.g., 49 CFR 390.3(f), 391.2) and is not held to full federal medical standards, but must still meet Oregon CDL medical standards. Source: Oregon DMV CDL Self-Certification; Oregon Commercial Driver Manual.","handbook":"","hbref":""},{"q":"In Oregon, what is the blood alcohol concentration (BAC) at or above which it is illegal to operate a commercial motor vehicle (CMV)?","options":["0.08%","0.04%","0.02%","0.10%"],"answer":1,"explanation":"Oregon adopts the federal CMV standard: it is illegal to operate a CMV with a BAC of 0.04% or more, half the 0.08% limit for non-commercial drivers. Source: Oregon Commercial Driver Manual, Section 1 (Disqualifications); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Oregon's implied-consent rule for commercial drivers, what is true when you operate a CMV?","options":["You may refuse all testing without penalty","You are deemed to have given consent to alcohol testing","Testing requires a separate signed waiver each trip","Consent applies only above 0.08% BAC"],"answer":1,"explanation":"The Oregon CDL Manual states that by operating a CMV you are deemed to have given consent to alcohol testing. Refusing the test carries the same disqualification as a major offense. Source: Oregon Commercial Driver Manual, Section 1; ORS 813.100.","handbook":"","hbref":""},{"q":"An Oregon CDL holder is convicted of driving a CMV with a BAC of 0.04% or higher for the FIRST time, not carrying hazardous materials. What is the minimum disqualification period?","options":["60 days","90 days","1 year","3 years"],"answer":2,"explanation":"A first major offense, including a CMV BAC of 0.04% or higher, disqualifies the driver for at least 1 year in Oregon. Source: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"If a first major offense (such as a 0.04% BAC) occurs while the driver is operating a CMV placarded for hazardous materials, what is the minimum Oregon disqualification?","options":["1 year","18 months","3 years","5 years"],"answer":2,"explanation":"When a first major offense occurs in a CMV placarded for hazardous materials, the disqualification increases to at least 3 years. Source: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the Oregon disqualification for a SECOND major offense committed by a CDL holder?","options":["3 years","5 years","10 years","Lifetime"],"answer":3,"explanation":"A second major offense (for example, a second DUI in a CMV, or a major offense after a prior one) results in a lifetime CDL disqualification in Oregon. Source: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"An Oregon CDL holder refuses to submit to alcohol testing while operating a CMV (first occurrence). How is this treated for disqualification purposes?","options":["No CDL penalty, only a fine","Treated as a major offense: at least 1-year disqualification","30-day disqualification","Treated as a serious violation: 60 days"],"answer":1,"explanation":"Refusing alcohol testing is listed among the major offenses and carries at least a 1-year disqualification (3 years if placarded for hazmat), the same as a BAC failure. Source: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51; ORS 813.100.","handbook":"","hbref":""},{"q":"An Oregon CDL holder uses a CMV to commit a felony involving a controlled substance (manufacturing, distributing, or dispensing). What is the disqualification?","options":["1 year","3 years","10 years","Lifetime, with no reinstatement"],"answer":3,"explanation":"Using a CMV to commit a felony involving controlled substances results in a lifetime disqualification with no possibility of reinstatement. Source: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A CDL driver in Oregon is found to have a detectable amount of alcohol BELOW 0.04% while on duty. What happens?","options":["Nothing, it is under the legal limit","Placed out-of-service for 24 hours","1-year disqualification","Placed out-of-service for 1 hour"],"answer":1,"explanation":"Any detectable alcohol under 0.04% does not trigger a major-offense disqualification but does place the driver out-of-service for 24 hours. Source: Oregon Commercial Driver Manual, Section 1; 49 CFR 392.5.","handbook":"","hbref":""},{"q":"Which of the following is classified as a 'serious traffic violation' for an Oregon CDL holder?","options":["Parking in a no-parking zone","Excessive speeding, 15 mph or more over the limit","A burned-out marker lamp","Driving 5 mph over the limit"],"answer":1,"explanation":"Serious traffic violations include excessive speeding defined as 15 mph or more above the posted limit, reckless driving, improper or erratic lane changes, and following too closely. Source: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How many serious traffic violations within a 3-year period trigger a disqualification in Oregon, and for how long is the FIRST such disqualification?","options":["1 violation; 30 days","2 violations; at least 60 days","2 violations; at least 30 days","3 violations; at least 60 days"],"answer":1,"explanation":"Two serious traffic violations within 3 years result in a disqualification of at least 60 days. Source: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"An Oregon CDL holder commits THREE serious traffic violations within a 3-year period. What is the minimum disqualification?","options":["60 days","90 days","120 days","1 year"],"answer":2,"explanation":"Three or more serious traffic violations within 3 years result in a disqualification of at least 120 days. Source: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Do serious traffic violations count toward CDL disqualification when committed in the driver's PERSONAL (non-commercial) vehicle?","options":["No, only violations in a CMV count","Yes, if they result in license suspension or revocation","Only if alcohol is involved","Only violations on interstate highways count"],"answer":1,"explanation":"Serious traffic violations committed in a non-CMV count against a CDL holder if the conviction results in the suspension or revocation of the driver's license. Source: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"For a SECOND railroad-highway grade crossing violation within 3 years, what is the minimum Oregon disqualification?","options":["60 days","120 days","180 days","1 year"],"answer":1,"explanation":"A second railroad-highway grade crossing violation within a 3-year period results in a disqualification of at least 120 days. Source: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the minimum Oregon disqualification for a THIRD railroad-highway grade crossing violation within a 3-year period?","options":["120 days","180 days","1 year","3 years"],"answer":2,"explanation":"A third or subsequent railroad-highway grade crossing violation within 3 years results in a disqualification of at least 1 year. Source: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"An Oregon CDL holder violates an out-of-service order for the FIRST time while NOT transporting hazardous materials or passengers. What is the minimum disqualification?","options":["60 days","90 days","180 days","1 year"],"answer":2,"explanation":"A first out-of-service order violation (non-hazmat, non-passenger) results in a disqualification of at least 180 days. Source: Oregon Commercial Driver Manual, Section 1 / ODOT Commercial Driver Convictions page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A driver violates an out-of-service order for the FIRST time while transporting hazardous materials (or driving a vehicle designed for 16+ passengers). What is the minimum Oregon disqualification?","options":["180 days","1 year","3 years","5 years"],"answer":1,"explanation":"A first out-of-service violation while hauling hazmat or operating a 16-or-more-passenger vehicle results in a disqualification of at least 1 year, longer than the 180-day baseline. Source: ODOT Commercial Driver Convictions page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the minimum disqualification for a SECOND out-of-service order violation within 10 years, not involving hazmat or passengers?","options":["1 year","2 years","3 years","5 years"],"answer":2,"explanation":"A second out-of-service violation within 10 years (non-hazmat, non-passenger) results in a disqualification of at least 3 years; if hazmat or passengers were involved it rises to at least 5 years. Source: ODOT Commercial Driver Convictions page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Besides license disqualification, what civil penalty does Oregon/ODOT impose on a driver for a FIRST violation of an out-of-service order?","options":["$650","$1,000","$3,861","$7,723"],"answer":2,"explanation":"ODOT imposes a civil penalty of $3,861 for a first out-of-service order violation and $7,723 for a second or subsequent violation, in addition to the disqualification. Source: ODOT Commercial Driver Convictions page; 49 CFR 383.53.","handbook":"","hbref":""},{"q":"Under the rules that apply to Oregon CDL drivers, what is prohibited regarding mobile phones while driving a CMV?","options":["All radio communication is banned","Holding a phone for a call, dialing more than one button, or texting","Hands-free calling is also banned","Phones must be powered off at all times"],"answer":1,"explanation":"CMV drivers may not hold a mobile phone to talk, dial by pressing more than a single button, or send/read text messages while driving; a texting/handheld violation is a serious traffic violation (max federal fine $2,750) that counts toward the 60/120-day disqualification. Source: Oregon Commercial Driver Manual, Section 1; 49 CFR 392.80-392.82, 383.51.","handbook":"","hbref":""},{"q":"Under Oregon's Move Over Law, when you approach a stopped emergency, tow, roadside-assistance, or hazard-light vehicle on a multi-lane road and you CANNOT safely change to a non-adjacent lane, what must you do?","options":["Slow to a speed at least 5 mph below the posted or designated speed limit","Come to a complete stop until the vehicle leaves","Slow to exactly 10 mph below the posted speed limit","Maintain the posted speed but sound your horn"],"answer":0,"explanation":"Oregon's Move Over Law (ORS 811.147) requires drivers to move to a non-adjacent lane if possible; if that is not possible, they must slow to at least 5 mph below the posted or designated speed limit and proceed with caution. Source: ORS 811.147; Oregon Driver Manual.","handbook":"","hbref":""},{"q":"A violation of Oregon's Move Over Law (failure to maintain a safe distance from a stopped emergency, roadside-assistance, tow vehicle, or ambulance) is classified as which type of offense?","options":["A Class B traffic violation","A Class A traffic violation","A Class C misdemeanor","A Class D traffic violation"],"answer":0,"explanation":"Failure to maintain a safe distance from an emergency, roadside-assistance, tow vehicle, or ambulance under Oregon's Move Over Law is a Class B traffic violation. Source: ORS 811.147.","handbook":"","hbref":""},{"q":"In Oregon, when a school bus is stopped on a two-way street with its red lights flashing, how far back must an approaching driver stop?","options":["20 feet or more from the bus","10 feet or more from the bus","30 feet or more from the bus","50 feet or more from the bus"],"answer":0,"explanation":"Oregon requires drivers to stop 20 feet or more from a school bus displaying flashing red warning lights and to remain stopped until the lights stop flashing. Source: ORS 811.155; Oregon Driver Manual.","handbook":"","hbref":""},{"q":"Under Oregon law, which is the ONLY situation in which an oncoming driver is NOT required to stop for a school bus showing flashing red lights?","options":["The bus is stopped on a different roadway, separated by a physical median or barrier","The bus is stopped in a 25 mph residential zone","There is a center two-way left-turn lane between the driver and the bus","The road is painted with a solid yellow centerline"],"answer":0,"explanation":"In Oregon a driver need not stop only if the bus showing red lights is on a different roadway, meaning the highway is divided by a physical median or barrier into separate roadways. A painted yellow line or a center turn lane does NOT create separate roadways, so all lanes must stop. Source: ORS 811.155; Oregon Driver Manual.","handbook":"","hbref":""},{"q":"Failing to stop for a school bus's flashing red safety lights in Oregon is what level of traffic offense?","options":["A Class A traffic violation","A Class B traffic violation","A Class C traffic violation","A Class A misdemeanor"],"answer":0,"explanation":"Failure to stop for bus safety lights under ORS 811.155 is a Class A traffic violation, Oregon's most serious traffic-violation class. Source: ORS 811.155.","handbook":"","hbref":""},{"q":"When an Oregon CDL driver must stop at a railroad crossing in a placarded hazmat vehicle (and there is no marked stop line), where must the vehicle stop?","options":["Not less than 15 feet nor more than 50 feet from the nearest rail","Not less than 10 feet nor more than 25 feet from the nearest rail","Not less than 5 feet nor more than 15 feet from the nearest rail","Not less than 50 feet nor more than 100 feet from the nearest rail"],"answer":0,"explanation":"A driver of a placarded hazmat vehicle, a chlorine load, or a hazmat cargo tank (loaded or empty) must stop not less than 15 feet nor more than 50 feet from the nearest rail when there is no stop line. Source: Oregon Commercial Driver Manual Section 9; ORS 811.460.","handbook":"","hbref":""},{"q":"While crossing railroad tracks in a placarded hazmat vehicle in Oregon, what does the rule specifically prohibit?","options":["Manually shifting gears while on the tracks","Using the engine brake while on the tracks","Turning on the four-way flashers while on the tracks","Sounding the horn while on the tracks"],"answer":0,"explanation":"Oregon's high-risk crossing rule requires the driver to cross in a gear that does not require manually changing gears, so you must not shift gears while on the tracks; proceed only when sure you can clear the tracks without stopping. Source: ORS 811.460; Oregon Commercial Driver Manual Section 9.","handbook":"","hbref":""},{"q":"Which of these vehicles is NOT among the 'high-risk' vehicles that Oregon law requires to stop at every railroad crossing?","options":["An empty flatbed truck carrying ordinary freight","A school bus","A loaded or empty cargo tank that hauls hazardous materials","A commercial bus carrying passengers"],"answer":0,"explanation":"ORS 811.460 lists high-risk vehicles that must stop at crossings: school buses, certain school activity and worker-transport buses, commercial buses, vehicles carrying explosives/flammables/corrosives, and hazmat tank vehicles (loaded or empty). An ordinary freight truck with non-hazardous cargo is not required to stop unless signals require it. Source: ORS 811.460.","handbook":"","hbref":""},{"q":"In Oregon, what is the standard maximum speed limit for a commercial vehicle over 10,000 pounds GVWR unless a different speed is posted?","options":["55 mph","60 mph","65 mph","70 mph"],"answer":0,"explanation":"Unless a different speed is posted, the default maximum for commercial vehicles over 10,000 lbs GVWR (or truck tractors over 8,000 lbs GVWR) is 55 mph. Source: ORS 811.111; ORS 810.180.","handbook":"","hbref":""},{"q":"By Oregon rule, the highest speed the Department of Transportation may designate for commercial vehicles on an interstate highway is:","options":["65 mph","70 mph","60 mph","75 mph"],"answer":0,"explanation":"ODOT may set designated interstate speeds but cannot exceed 65 mph for commercial vehicles (the cap for other vehicles is 70 mph). Some Oregon interstate segments have been raised to 60 mph for trucks where cars run 65. Source: ORS 810.180; OAR 734-020-0010.","handbook":"","hbref":""},{"q":"On an Oregon roadway with two or more lanes going the same direction, which vehicles are required to drive in the right lane except when passing or turning?","options":["Campers, vehicles towing a trailer, and vehicles with a registration weight of 10,000 pounds or more","Only vehicles with three or more axles","Only vehicles displaying hazmat placards","All vehicles traveling below 45 mph"],"answer":0,"explanation":"ORS 811.325 requires any camper, any vehicle with a trailer, and any vehicle with a registration weight of 10,000 lbs or more to use the right lane on multi-lane one-direction roadways, except when passing, turning left, responding to an emergency, avoiding merging traffic, or as directed by traffic control devices. Source: ORS 811.325.","handbook":"","hbref":""},{"q":"Failure to keep a camper, trailer, or truck (10,000 lbs+) in the right lane on an Oregon multi-lane highway is what kind of offense?","options":["A Class B traffic violation","A Class A traffic violation","A Class C traffic violation","A Class D traffic violation"],"answer":0,"explanation":"Violating the right-lane requirement of ORS 811.325 is a Class B traffic violation. Source: ORS 811.325.","handbook":"","hbref":""},{"q":"Which is a recognized lawful exception that lets an Oregon truck (10,000 lbs+) leave the right lane on a multi-lane highway?","options":["Overtaking and passing another vehicle going the same direction","Wanting to maintain a faster cruising speed","Keeping a longer following distance from the vehicle ahead","Avoiding wear on the right-lane pavement"],"answer":0,"explanation":"ORS 811.325 permits leaving the right lane to lawfully overtake and pass, to prepare for a left turn, to respond to emergency conditions, to avoid traffic entering from merge/acceleration lanes, or as directed by traffic control devices. Source: ORS 811.325.","handbook":"","hbref":""},{"q":"On a divided or one-way highway in Oregon, where must a CDL driver place the three emergency warning triangles when stopped on the road?","options":["Within 10 feet of the rear, and at 100 feet and 200 feet toward approaching traffic","Within 25 feet of the rear, and at 50 feet and 150 feet toward approaching traffic","Within 10 feet of the front, and at 100 feet and 300 feet toward approaching traffic","Within 50 feet of the rear, and at 100 feet and 250 feet toward approaching traffic"],"answer":0,"explanation":"On a one-way or divided highway, place one warning device within 10 feet of the rear toward approaching traffic, one about 100 feet back, and one about 200 feet back. This federal standard (49 CFR 392.22) is taught in the Oregon Commercial Driver Manual. Source: Oregon Commercial Driver Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"On a two-lane, two-way Oregon road, after a CDL vehicle stops on the traveled portion, within how many minutes must the driver have the emergency warning devices placed?","options":["Within 10 minutes","Within 5 minutes","Within 15 minutes","Within 30 minutes"],"answer":0,"explanation":"A CDL driver must place the warning devices (three triangles or equivalent) within 10 minutes of stopping on the traveled portion or shoulder of a road. Source: Oregon Commercial Driver Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"In Oregon, what is the maximum legal vehicle/load WIDTH before an over-dimension permit is required?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"answer":0,"explanation":"Oregon's legal maximum width is 8 feet 6 inches; loads exceeding this require an over-dimension permit from ODOT's Commerce and Compliance Division. Source: ORS 818.080; ODOT Legal Vehicle Dimensions.","handbook":"","hbref":""},{"q":"What is Oregon's legal maximum vehicle HEIGHT before an over-dimension permit is required?","options":["14 feet 0 inches","13 feet 6 inches","13 feet 0 inches","15 feet 0 inches"],"answer":0,"explanation":"Oregon's legal maximum height is 14 feet 0 inches; loads exceeding this require an over-dimension permit. (Note many other states use 13'6\".) Source: ORS 818.080; ODOT Legal Vehicle Dimensions.","handbook":"","hbref":""},{"q":"Oregon requires all vehicles over 10,000 lbs GVW to carry tire chains during the snow season:","options":["Whenever conditions exist where their use may be needed or required","Only when traveling east of the Cascades","Only on weekends from December through February","Only if the vehicle lacks studded tires"],"answer":0,"explanation":"Oregon law requires vehicles over 10,000 lbs GVW to carry chains whenever conditions exist where chains may be needed or required, and to install them when the chain law is in effect (typically October through March on mountain passes). Source: ODOT Commerce and Compliance Division, Chains and Traction Tires.","handbook":"","hbref":""},{"q":"During which period are studded tires legal to use on Oregon roads?","options":["November 1 through March 31","October 1 through April 30","November 15 through April 15","December 1 through March 1"],"answer":0,"explanation":"Studded tires are legal in Oregon only from November 1 through March 31; using them outside this window can bring a fine. Source: ODOT / Oregon TripCheck; ORS studded-tire provisions.","handbook":"","hbref":""},{"q":"Oregon is notable for an early runaway-truck escape feature on a steep Interstate 5 grade. Where was the nation's first negative-grade (downhill) truck arrester bed built and tested?","options":["Near Siskiyou Summit on I-5 in southern Oregon","On the Cabbage Hill grade of I-84","At Government Camp on US 26 over Mount Hood","On the Santiam Pass of US 20"],"answer":0,"explanation":"The first negative-grade (downhill) truck arrester bed in the United States was built and tested in 1977 along I-5 near Siskiyou Summit in southern Oregon, a notably steep mountain grade where runaway-ramp use is emphasized. Source: ODOT; Oregon Commercial Driver Manual mountain-driving guidance.","handbook":"","hbref":""},{"q":"In Oregon, which state agency issues Commercial Driver Licenses (CDLs) and administers the testing process?","options":["The Oregon DMV, part of the Oregon Department of Transportation (ODOT) Driver & Motor Vehicle Services","The Oregon State Police Commercial Vehicle Division","The federal Motor Carrier Safety Administration (FMCSA) regional office","The Oregon Secretary of State, Corporations and Licensing Division"],"answer":0,"explanation":"Oregon CDLs are issued by the Oregon DMV, which is part of the Oregon Department of Transportation (ODOT) Driver & Motor Vehicle Services. Source: Oregon DMV 'Getting a CDL or CLP' page; Oregon Commercial Driver Manual.","handbook":"","hbref":""},{"q":"A vehicle requires an Oregon CDL based on weight when its gross vehicle weight rating (GVWR) is at least how many pounds?","options":["26,001 pounds","10,001 pounds","18,000 pounds","33,000 pounds"],"answer":0,"explanation":"Oregon requires a CDL to operate a vehicle with a GVWR of 26,001 pounds or more (and for combinations where the towed unit is over 10,000 lbs). Source: Oregon Commercial Driver Manual, Section 1.","handbook":"","hbref":""},{"q":"Apart from weight, which passenger threshold makes a vehicle require an Oregon CDL?","options":["Designed to carry 16 or more people, including the driver","Designed to carry 9 or more people, including the driver","Designed to carry 24 or more people, not counting the driver","Designed to carry 12 or more people, including the driver"],"answer":0,"explanation":"A CDL is required for a vehicle designed to transport 16 or more people, including the driver. The third trigger is transporting hazardous materials requiring placards. Source: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.5 as applied in Oregon.","handbook":"","hbref":""},{"q":"When applying for an Oregon CDL or commercial learner permit, an applicant must 'self-certify' which type of commerce they will operate in. Which set of categories does Oregon offer?","options":["Non-excepted Interstate, Excepted Interstate, and Non-excepted Intrastate","Interstate Hazmat, Intrastate Hazmat, and Non-Hazmat only","Federal Carrier, State Carrier, and Private Carrier","Class A, Class B, and Class C operation"],"answer":0,"explanation":"Oregon DMV offers three self-certification categories: Non-excepted Interstate, Excepted Interstate, and Non-excepted Intrastate. (Excepted Intrastate is the fourth FMCSA category; Oregon does not separately list it.) Source: Oregon DMV CDL application/self-certification; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"An Oregon CDL applicant who self-certifies as 'Non-excepted Interstate' is required to do what regarding medical qualification?","options":["Provide DMV a copy of a valid DOT medical examiner's certificate and keep a current one on file","Carry the paper medical card in the truck but never give it to DMV","Submit a notarized statement that no medical exam is needed","Pass an additional DMV-administered physical fitness road test"],"answer":0,"explanation":"A non-excepted interstate driver must provide Oregon DMV a copy of a valid medical examiner's certificate (DOT medical card) and is responsible for keeping a current one on file, or the CDL is downgraded. Source: Oregon DMV CDL medical certification; 49 CFR 383.71/391.45.","handbook":"","hbref":""},{"q":"Who is qualified to perform the DOT physical exam that produces the medical examiner's certificate used for an Oregon CDL?","options":["A medical examiner listed on the FMCSA National Registry of Certified Medical Examiners","Any licensed pharmacist in Oregon","An Oregon DMV field office examiner","Any physician, as long as they are licensed in any U.S. state"],"answer":0,"explanation":"The DOT medical exam must be performed by a medical examiner listed on the FMCSA National Registry of Certified Medical Examiners. Source: Oregon DMV 'Getting a CDL or CLP'; 49 CFR 390.103.","handbook":"","hbref":""},{"q":"Before an applicant can take the CDL skills test in Oregon, they must first obtain which credential?","options":["A Commercial Learner Permit (CLP)","A Class C provisional CDL","A federal interstate operating authority (MC number)","A temporary out-of-service waiver"],"answer":0,"explanation":"Applicants who require skills testing must first obtain a Commercial Learner Permit (CLP) by passing the required knowledge test(s). Source: Oregon DMV CDL process; OAR 735-063-0250 / 735-063-0260.","handbook":"","hbref":""},{"q":"To obtain an Oregon Class A Commercial Learner Permit, which knowledge tests must the applicant pass?","options":["The General Knowledge test and the Combination Vehicles test (plus Air Brakes if applicable)","Only the General Knowledge test","The General Knowledge test and the Hazardous Materials test","Only the Combination Vehicles test"],"answer":0,"explanation":"A Class A CLP requires passing the General Knowledge test and the Combination Vehicles test, plus the Air Brakes test if the vehicle has air brakes. Source: OAR 735-063-0250; Oregon Commercial Driver Manual.","handbook":"","hbref":""},{"q":"What is the minimum passing score on the Oregon CDL knowledge tests?","options":["80 percent correct","70 percent correct","90 percent correct","75 percent correct"],"answer":0,"explanation":"A score of at least 80 percent correct is required to pass each Oregon CDL knowledge test (e.g., 40 of 50 questions on the General Knowledge test). Source: Oregon Commercial Driver Manual / Oregon DMV; 49 CFR 383.135.","handbook":"","hbref":""},{"q":"The Oregon CDL skills test is made up of three parts that must be taken in a set order. What is that order?","options":["Pre-trip vehicle inspection, then basic control skills, then on-road driving","On-road driving, then pre-trip inspection, then basic control skills","Basic control skills, then on-road driving, then pre-trip inspection","Pre-trip inspection, then on-road driving, then basic control skills"],"answer":0,"explanation":"The skills test is administered in order: pre-trip vehicle inspection first, then basic control skills, then the on-road drive; each part must be passed before moving on. Source: OAR 735-063-0260 / OAR 735-060-0120.","handbook":"","hbref":""},{"q":"Federal Entry-Level Driver Training (ELDT) must be completed before testing in Oregon for which of the following?","options":["Obtaining a Class A or B CDL for the first time, upgrading Class B to A, or first-time passenger/school bus/hazmat endorsements","Every CDL renewal, regardless of class","Only for drivers under the age of 21","Only when adding a doubles/triples endorsement"],"answer":0,"explanation":"ELDT is required before testing for a first-time Class A or B CDL, upgrading a Class B to Class A, or obtaining a passenger, school bus, or hazardous materials endorsement for the first time. Source: Oregon DMV; 49 CFR Part 380 Subpart F.","handbook":"","hbref":""},{"q":"Entry-Level Driver Training (ELDT) for an Oregon CDL must be provided by an entity that is listed where?","options":["On the FMCSA Training Provider Registry (TPR)","In the Oregon DMV's list of approved high schools","On the Oregon Trucking Associations member roster","With the U.S. Department of Labor apprenticeship office"],"answer":0,"explanation":"ELDT instruction must be completed through a school or entity on the FMCSA Training Provider Registry (TPR) before scheduling a skills test or taking the hazmat knowledge test. Source: Oregon DMV; FMCSA Training Provider Registry.","handbook":"","hbref":""},{"q":"How long must an Oregon Commercial Learner Permit be held before the holder may take the CDL skills test?","options":["At least 14 days","At least 30 days","At least 7 days","At least 60 days"],"answer":0,"explanation":"Oregon DMV must have issued the unexpired CLP not less than 14 days prior to the skills test. Source: OAR 735-063-0260.","handbook":"","hbref":""},{"q":"How long is an Oregon Commercial Learner Permit (CLP) valid, and can it be renewed?","options":["Valid for one year and is not renewable","Valid for 180 days and may be renewed once","Valid for two years and is renewable yearly","Valid for 90 days and is not renewable"],"answer":0,"explanation":"An Oregon CLP is valid for one year from issuance and is not renewable. Source: ORS 807.285.","handbook":"","hbref":""},{"q":"A passing score on the Oregon CDL knowledge tests (and on a completed skills test) remains valid for how long before the CDL must be issued?","options":["Six months","Three months","One year","Thirty days"],"answer":0,"explanation":"A passing knowledge-test score is valid for six months, and a passing score for a completed CDL skills test is valid for six months. Source: OAR 735-063-0250 and OAR 735-063-0260.","handbook":"","hbref":""},{"q":"Once issued, how long is an Oregon CDL valid before it must be renewed?","options":["8 years","4 years","5 years","10 years"],"answer":0,"explanation":"An Oregon CDL issued to a U.S. citizen or permanent resident is valid for 8 years, the same standard cycle as a regular Oregon driver license. Source: Oregon DMV; ORS Chapter 807.","handbook":"","hbref":""},{"q":"What is the Oregon CDL renewal window relative to the expiration date?","options":["Up to 12 months before expiration and up to 2 years after expiration","Only on or after the expiration date, with no early renewal","Up to 30 days before and up to 30 days after expiration","Up to 6 months before expiration only"],"answer":0,"explanation":"An Oregon CDL may be renewed up to 12 months before it expires and up to 2 years after it expires; beyond that, the driver must apply for a new license. Source: Oregon DMV 'Renewing a Commercial Driver License'.","handbook":"","hbref":""},{"q":"Which documents must an Oregon CDL/CLP applicant provide to establish eligibility at application?","options":["Proof of full legal name, U.S. citizenship or lawful permanent residence, identity, date of birth, residence address, and Social Security Number","Only a current passport photo and a credit card","A notarized employer letter and a vehicle title","Proof of three years of commercial driving experience"],"answer":0,"explanation":"Applicants must provide proof of full legal name, U.S. citizenship or lawful permanent residence, identity, date of birth, and residence address, plus their Social Security Number. Source: Oregon DMV 'Getting a CDL or CLP'; OAR 735-063-0250.","handbook":"","hbref":""},{"q":"When renewing an Oregon CDL that carries a Hazardous Materials endorsement, what additional requirement applies?","options":["Pass the HazMat knowledge test and have a current TSA security background check (threat assessment)","Provide a notarized letter from the shipper of last record","Surrender the CDL for 30 days during the background review","Pass a second on-road skills test in a placarded vehicle"],"answer":0,"explanation":"Renewing a CDL with a HazMat endorsement requires passing the HazMat knowledge test and holding a current TSA security threat assessment (background check). Source: Oregon DMV 'Renewing a CDL'; 49 CFR Part 1572.","handbook":"","hbref":""},{"q":"If an Oregon CDL holder lets a required medical examiner's certificate expire (for a non-excepted self-certification), what does Oregon DMV do?","options":["Downgrades the CDL, removing commercial driving privileges until a valid medical certificate is on file","Suspends the regular (Class C) driving privileges as well","Issues an automatic 90-day medical waiver with no action needed","Refers the driver to the Oregon State Police for citation"],"answer":0,"explanation":"If a non-excepted driver's medical certificate expires and no current one is on file, Oregon DMV downgrades the CDL, removing commercial privileges until a valid certificate is submitted; the regular license remains. Source: Oregon DMV CDL medical certification; 49 CFR 383.73.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная допустимая ширина для большинства коммерческих транспортных средств на автомагистралях штата Орегон без разрешения на превышение габаритов?","options":["8 футов (96 inches)","8 футов 6 inches (102 inches)","9 футов (108 inches)","10 футов (120 inches)"],"explanation":"Орегон ограничивает общую внешнюю ширину транспортного средства до 8 футов 6 inches (102 inches) на дорогах общего пользования; всё, что шире, требует разрешения на превышение габаритов. Источник: ORS 818.080 (Maximum size limits) и Oregon DOT Commerce and Compliance Division, Legal Vehicle Dimensions."},"1":{"q":"Какова максимальная допустимая высота, включая груз, для транспортного средства, движущегося по автомагистралям штата Орегон без разрешения?","options":["13 футов 6 inches","14 футов","14 футов 6 inches","15 футов"],"explanation":"Орегон устанавливает максимальную высоту, включая любой груз, в 14 футов; превышение этого значения требует разрешения на превышение габаритов и проверки маршрута. Источник: ORS 818.080 и Oregon DOT Legal Vehicle Dimensions."},"2":{"q":"Без специального разрешения на длину, какова максимальная общая длина большинства сцепок тягача с полуприцепом на автомагистралях общего пользования штата Орегон?","options":["50 футов","55 футов","60 футов","75 футов"],"explanation":"На автомагистралях общего пользования штата Орегон максимальная общая длина для сцепки транспортных средств составляет 60 футов; более длинные сцепки разрешены только на специально определённых маршрутах или по разрешению. Источник: ORS 818.080 и Oregon DOT Legal Vehicle Dimensions."},"3":{"q":"На специально определённых маршрутах штата Орегон, где допускается неограниченная общая длина, какова максимальная длина одиночного полуприцепа в сцепке тягач-полуприцеп?","options":["48 футов","53 футов","57 футов","60 футов"],"explanation":"Орегон допускает максимальную длину полуприцепа в 53 фута; на специально определённых маршрутах общая длина сцепки может быть неограниченной, но сам полуприцеп не может превышать 53 фута. Источник: ORS 818.080 и Oregon DOT Legal Vehicle Dimensions."},"4":{"q":"Какова максимальная длина одиночного (соло) транспортного средства на автомагистралях штата Орегон без разрешения?","options":["35 футов","40 футов","45 футов","53 футов"],"explanation":"Одиночное транспортное средство, движущееся самостоятельно в штате Орегон, не может превышать 40 футов в длину без разрешения. Источник: ORS 818.080 (Maximum size limits)."},"5":{"q":"В штате Орегон, какова максимальная допустимая нагрузка на любую одиночную ось без разрешения на превышение веса?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"Орегон ограничивает нагрузку на любую одиночную ось до 20,000 pounds. Источник: ORS 818.010 (Maximum allowable weight)."},"6":{"q":"Какова максимальная допустимая нагрузка на группу спаренных осей в штате Орегон без разрешения на превышение веса?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Орегон ограничивает нагрузку на спаренную ось (две оси) до 34,000 pounds, что соответствует федеральному стандарту. Источник: ORS 818.010 (Maximum allowable weight)."},"7":{"q":"Какова максимальная полная масса транспортного средства, как правило допускаемая на автомагистралях штата Орегон без разрешения на превышение веса или на увеличенный вес?","options":["73,280 pounds","80,000 pounds","88,000 pounds","105,500 pounds"],"explanation":"Стандартная максимальная полная масса сцепки в штате Орегон составляет 80,000 pounds; более тяжёлые делимые грузы требуют разрешения на увеличенный вес от ODOT. Источник: ORS 818.010 и Oregon DOT Commerce and Compliance Division."},"8":{"q":"По разрешению ODOT на увеличенный вес (делимый груз), какова максимальная полная масса сцепки, которую может перевозить соответствующее требованиям транспортное средство в штате Орегон?","options":["90,000 pounds","98,000 pounds","105,500 pounds","129,000 pounds"],"explanation":"Разрешение штата Орегон на увеличенный вес позволяет соответствующим требованиям многоосным сцепкам работать с полной массой до 105,500 pounds при перевозке делимых грузов. Источник: Oregon DOT Commerce and Compliance Division, Extended Weight (Divisible Load) Permit."},"9":{"q":"Закон штата Орегон ограничивает нагрузку, которая может приходиться на шины, исходя из ширины шины. Какова максимальная допустимая нагрузка в фунтах на дюйм ширины шины?","options":["500 pounds per inch","550 pounds per inch","600 pounds per inch","650 pounds per inch"],"explanation":"Орегон использует рейтинг шины, указанный производителем на боковине, но не более 600 pounds per inch ширины шины, умноженной на сумму ширин шин. Источник: ORS 818.010 (Maximum allowable weight)."},"10":{"q":"Какую формулу применяет штат Орегон для определения максимальной полной массы, допустимой для группы последовательных осей, исходя из расстояния между ними?","options":["Федеральная мостовая формула (Bridge Gross Weight Formula)","Формула рейтинга GAWR","Формула налога на пробег штата Орегон","Формула крепления груза"],"explanation":"Орегон применяет Федеральную мостовую формулу, W = 500[LN/(N-1) + 12N + 36], чтобы ограничить нагрузку на любую группу из двух или более последовательных осей, исходя из расстояния между осями и их количества. Источник: ORS 818.010 и 23 CFR 658, применяемые Oregon DOT."},"11":{"q":"В Федеральной мостовой формуле, применяемой в штате Орегон, что обозначает переменная 'L'?","options":["Допустимый предел нагрузки в тоннах","Расстояние в футах между крайними осями группы","Длину прицепа в футах","Количество требуемых номерных знаков"],"explanation":"В мостовой формуле W = 500[LN/(N-1) + 12N + 36], L — это расстояние в футах между крайними осями группы, N — количество осей, а W — допустимая полная масса. Источник: Федеральная мостовая формула, применяемая Oregon DOT; ORS 818.010."},"12":{"q":"Когда требуется разрешение Oregon DOT на превышение габаритов или веса для коммерческого транспортного средства?","options":["Только при пересечении границы штата","Всякий раз, когда транспортное средство или груз превышает допустимые пределы по размеру или весу","Только в выходные и праздничные дни","Только для транспортных средств, зарегистрированных за пределами штата"],"explanation":"Любое транспортное средство или груз, превышающие допустимые в штате Орегон пределы по ширине, высоте, длине или весу, должны получить разрешение на превышение габаритов/веса перед началом движения. Источник: ORS 818.200 и Oregon DOT Commerce and Compliance Division, Over-Dimension Operations."},"13":{"q":"Какое агентство штата Орегон выдаёт разрешения на превышение габаритов и веса (over-dimension) для коммерческих транспортных средств?","options":["Полиция штата Орегон","Oregon DOT Commerce and Compliance Division","Офис шерифа округа","Federal Motor Carrier Safety Administration"],"explanation":"Разрешения на превышение габаритов и веса в штате Орегон выдаются подразделением Commerce and Compliance Division Департамента транспорта штата Орегон (Oregon Department of Transportation) (ранее Motor Carrier Transportation Division), доступны онлайн или на пунктах въезда. Источник: Oregon DOT Commerce and Compliance Division."},"14":{"q":"Какова максимальная нагрузка, допускаемая в штате Орегон на любое отдельное колесо?","options":["8,000 pounds","10,000 pounds","12,000 pounds","17,000 pounds"],"explanation":"Орегон ограничивает нагрузку на любое отдельное колесо до 10,000 pounds. Источник: ORS 818.010 (Maximum allowable weight)."},"15":{"q":"«Делимый груз» (divisible load), который превышает предел штата Орегон в 80,000-pound, — это груз, который:","options":["Не может быть разделён без чрезмерных затрат или риска повреждения","Может быть обоснованно разделён на меньшие, законные грузы","Всегда классифицируется как опасный материал","Должен перевозиться только ночью"],"explanation":"Делимый груз может быть обоснованно разделён на меньшие законные грузы; в штате Орегон такие грузы могут превышать 80,000 pounds только по разрешению ODOT на увеличенный вес (делимый груз), в отличие от неделимых грузов, для которых используются разрешения на отклонение по габаритам. Источник: Oregon DOT Commerce and Compliance Division."},"16":{"q":"Без разрешения, каков максимальный свес груза, допускаемый ВПЕРЕДИ транспортного средства в штате Орегон?","options":["3 фута","4 фута","5 футов","6 футов"],"explanation":"Орегон допускает максимальный передний свес груза в 4 фута без разрешения; больший передний свес требует разрешения на превышение габаритов и флажковой разметки. Источник: ORS 818.080 и Oregon DOT Legal Vehicle Dimensions."},"17":{"q":"В Федеральной мостовой формуле, применяемой в штате Орегон, увеличение расстояния между крайними осями группы при сохранении того же количества осей, как правило:","options":["Уменьшает допустимую полную массу","Не влияет на допустимый вес","Увеличивает допустимую полную массу","Аннулирует регистрацию грузовика"],"explanation":"Поскольку L (расстояние между осями) находится в числителе, большее расстояние между крайними осями увеличивает допустимую полную массу для этой группы осей; близко расположенные оси ограничены для защиты мостов. Источник: Федеральная мостовая формула, применяемая Oregon DOT; ORS 818.010."},"18":{"q":"Орегон предоставляет определённые послабления по весу и разрешения с пониженной платой для какого типа перевозок, важных для экономики штата?","options":["Пассажирские чартерные автобусы","Перевозка сельскохозяйственной и лесной (брёвна) продукции","Межштатные фургоны доставки посылок","Арендованные грузовики для переездов"],"explanation":"Орегон предусматривает специальные разрешения и весовые положения для сельскохозяйственных товаров и лесной продукции/брёвен (например, пониженные послабления или послабления по регистрационному весу и разрешения на увеличенный вес для брёвен), что отражает важность сельского хозяйства и лесозаготовки для штата. Источник: Oregon DOT Commerce and Compliance Division и положения о разрешениях ORS Chapter 818."},"19":{"q":"В штате Орегон, какой класс CDL требуется для управления любой сцепкой транспортных средств с полной массой сцепки (Gross Combination Weight Rating, GCWR) 26,001 pounds или более, при условии, что буксируемое транспортное средство тяжелее 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"explanation":"Орегон следует стандартным классам CDL: Class A CDL охватывает любую сцепку транспортных средств с GCWR 26,001 lbs или более, где буксируемая единица превышает 10,000 lbs. Источник: Oregon Commercial Driver Manual / Oregon DMV Driver License Classes (соответствует 49 CFR 383.91; ORS 807.031)."},"20":{"q":"По правилам штата Орегон, какой класс CDL охватывает одиночное транспортное средство с полной массой (Gross Vehicle Weight Rating, GVWR) 26,001 pounds или более, либо такое транспортное средство, буксирующее единицу массой не более 10,000 pounds?","options":["Class A","Class B","Class C","Class M"],"explanation":"Class B CDL в штате Орегон охватывает одиночное транспортное средство с GVWR 26,001 lbs или более, либо такое транспортное средство, буксирующее прицеп массой не более 10,000 lbs. Источник: Oregon Commercial Driver Manual / Oregon DMV Driver License Classes (49 CFR 383.91)."},"21":{"q":"В штате Орегон меньшее транспортное средство, которое не соответствует весовым порогам Class A или Class B, всё равно требует Class C CDL, если оно предназначено для перевозки как минимум скольких человек, включая водителя?","options":["10","12","16","24"],"explanation":"Class C CDL требуется для транспортного средства (не соответствующего Class A или B), предназначенного для перевозки 16 или более человек, включая водителя, либо используемого для перевозки опасных материалов, требующих размещения табличек (placards). Источник: Oregon Commercial Driver Manual / Oregon DMV Driver License Classes (49 CFR 383.91)."},"22":{"q":"Помимо перевозки 16 или более пассажиров, какое ещё условие требует Class C CDL в штате Орегон для транспортного средства, слишком малого для Class A или B?","options":["Буксировка любого прицепа массой более 5,000 pounds","Перевозка опасных материалов в количествах, требующих размещения табличек (placards)","Движение после наступления темноты по автомагистрали штата","Перевозка любой сельскохозяйственной продукции за плату"],"explanation":"Орегон требует Class C CDL для меньшего транспортного средства, используемого для перевозки опасных материалов в количествах, требующих размещения табличек (placards) (либо для перевозки 16+ человек). Источник: Oregon Commercial Driver Manual; Oregon DMV CDL Classes (49 CFR 383.91)."},"23":{"q":"Какой код подтверждения (endorsement) использует Орегон для подтверждения на перевозку опасных материалов (Hazardous Materials) в CDL?","options":["H","N","T","X"],"explanation":"Подтверждение на перевозку опасных материалов (Hazardous Materials) кодируется как 'H' в штате Орегон. (Код 'X' обозначает комбинированное подтверждение Tank и HazMat.) Источник: Oregon DMV CDL Endorsements & Restrictions; Oregon Commercial Driver Manual."},"24":{"q":"Водителю из штата Орегон необходимо управлять коммерческим транспортным средством, буксирующим двойные или тройные прицепы. Какое подтверждение (endorsement) требуется?","options":["Подтверждение P","Подтверждение N","Подтверждение T","Подтверждение S"],"explanation":"Подтверждение 'T' (Doubles/Triples) требуется в штате Орегон для управления любым коммерческим механическим транспортным средством, буксирующим двойные или тройные прицепы, и получается путём сдачи теста на знания. Источник: Oregon DMV CDL Endorsements; Oregon Commercial Driver Manual."},"25":{"q":"В штате Орегон подтверждение на цистерну (Tank Vehicle, N) требуется, когда CMV предназначено для перевозки жидкости или газа в цистерне с индивидуальным рейтингом более 119 gallons И с совокупной номинальной вместимостью не менее скольких галлонов?","options":["500 gallons","750 gallons","1,000 gallons","1,500 gallons"],"explanation":"Орегон требует подтверждение N (Tank) для транспортного средства, перевозящего жидкость или газ в цистерне с индивидуальным рейтингом более 119 gallons и совокупной номинальной вместимостью 1,000 gallons или более. Источник: Oregon Commercial Driver Manual; Oregon DMV CDL Endorsements (49 CFR 383.5)."},"26":{"q":"Какое подтверждение (endorsement) CDL штата Орегон требуется для управления транспортным средством, предназначенным для перевозки 16 или более человек, включая водителя?","options":["P (Passenger)","S (School Bus)","T (Doubles/Triples)","N (Tank)"],"explanation":"Подтверждение 'P' (Passenger) требуется в штате Орегон для управления транспортным средством, предназначенным для перевозки 16 или более пассажиров, включая водителя; оно требует сдачи теста на знания и теста навыков. Источник: Oregon DMV CDL Endorsements; Oregon Commercial Driver Manual."},"27":{"q":"Чтобы водить школьный автобус в штате Орегон, какое подтверждение (endorsement) должен добавить владелец CDL в дополнение к выполнению требований для пассажирских транспортных средств?","options":["Подтверждение H","Подтверждение S","Подтверждение T","Подтверждение X"],"explanation":"Подтверждение 'S' (School Bus) требуется для управления школьным автобусом в штате Орегон; заявитель также должен иметь подтверждение P и сдать тест на знания и навыки управления школьным автобусом. Источник: Oregon DMV CDL Endorsements; Oregon Commercial Driver Manual."},"28":{"q":"Каков минимальный возраст для получения CDL штата Орегон с ограничением только внутриштатными (только в пределах Орегона) коммерческими перевозками?","options":["16 лет","18 лет","21 год","25 лет"],"explanation":"Орегон требует, чтобы заявитель был не моложе 18 лет для внутриштатного CDL; межштатные перевозки требуют возраста 21 год. Источник: Oregon DMV 'Getting a CDL or CLP'; Oregon Commercial Driver Manual."},"29":{"q":"По правилам штата Орегон, каков минимальный возраст для управления коммерческим механическим транспортным средством в межштатных перевозках?","options":["18 лет","19 лет","21 год","23 года"],"explanation":"Орегон требует, чтобы водителю было не менее 21 года для управления CMV в межштатных перевозках; работа только в пределах штата разрешена с 18 лет. Источник: Oregon DMV 'Getting a CDL or CLP'; Oregon Commercial Driver Manual."},"30":{"q":"В штате Орегон, как долго человек должен иметь действующее коммерческое ученическое разрешение (Commercial Learner Permit, CLP), прежде чем ему будет разрешено сдавать тест навыков CDL?","options":["Не менее 7 days","Не менее 14 days","Не менее 30 days","Не менее 60 days"],"explanation":"Орегон требует, чтобы заявитель имел действующее CLP не менее 14 days перед сдачей теста навыков CDL, что отражает федеральный обязательный период ожидания. Источник: Oregon Commercial Driver Manual (Oregon Information); Oregon DMV (49 CFR 383.25)."},"31":{"q":"Как долго действительны результаты теста на коммерческие знания в штате Орегон при работе над получением CDL?","options":["Три месяца","Шесть месяцев","Один год","Два года"],"explanation":"Орегон указывает, что результаты теста на коммерческие знания действительны в течение шести месяцев; заявление на CDL должно быть завершено в течение этого периода. Источник: Oregon Commercial Driver Manual (Oregon Information); Oregon DMV 'Getting a CDL or CLP.'"},"32":{"q":"Что из перечисленного заявитель должен предъявить в Oregon DMV при подаче заявления на CDL или CLP?","options":["Только нотариально заверенное письмо работодателя","Подтверждение полного юридического имени, личности, даты рождения, законного статуса в США, адреса проживания и номера социального страхования (Social Security Number)","Только паспорт и ничего больше","Аттестат об окончании школы и две рекомендации"],"explanation":"Oregon DMV требует подтверждение полного юридического имени, личности, даты рождения, законного статуса в США, адреса проживания в Орегоне и номера социального страхования (Social Security Number) заявителя. Источник: Oregon Commercial Driver Manual (Oregon Information); Oregon DMV 'Getting a CDL or CLP.'"},"33":{"q":"Перед сдачей теста навыков CDL для получения первой лицензии Class A или Class B в штате Орегон, где заявитель должен пройти обучение водителей начального уровня (Entry-Level Driver Training, ELDT)?","options":["Любой курс в общественном колледже","У провайдера, указанного в реестре провайдеров обучения FMCSA (FMCSA Training Provider Registry)","В отделении Oregon DMV","В любой внутренней программе работодателя"],"explanation":"Орегон требует прохождения ELDT у провайдера, указанного в реестре провайдеров обучения FMCSA (tpr.fmcsa.dot.gov), перед записью на тест навыков для первого CDL Class A/B, повышения с B до A, либо первого подтверждения P, S или H. Источник: Oregon Commercial Driver Manual; Oregon DMV (49 CFR Part 380)."},"34":{"q":"ELDT в штате Орегон требуется перед тестированием на какое из этих подтверждений (endorsements) в первый раз?","options":["Doubles/Triples (T)","Tank (N)","Hazardous Materials (H)","Ни одно из подтверждений не требует ELDT"],"explanation":"Орегон требует ELDT перед сдачей теста на знания HazMat (H) в первый раз, а также для первых подтверждений P или S и первых CDL Class A/B. Подтверждения T и N не входят в список ELDT. Источник: Oregon DMV; Oregon Commercial Driver Manual (49 CFR Part 380)."},"35":{"q":"Заявитель на CDL в штате Орегон, который будет водить только в пределах Орегона и не подпадает под федеральные медицинские правила, должен самостоятельно сертифицироваться по какой категории?","options":["Non-excepted Interstate (NI)","Excepted Interstate (EI)","Non-excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Орегон предлагает типы самосертификации; водитель, управляющий CMV класса A, B или C только во внутриштатных перевозках, сертифицируется как Non-excepted Intrastate и должен соответствовать медицинским стандартам CDL штата Орегон, а не полным федеральным стандартам. Источник: Oregon DMV CDL Medical/Self-Certification; Oregon Commercial Driver Manual."},"36":{"q":"Какую категорию самосертификации рекомендует Oregon DMV большинству водителей CDL, чтобы их лицензия не была без необходимости ограничена использованием только в пределах Орегона?","options":["Excepted Interstate","Non-excepted Interstate","Non-excepted Intrastate","Excepted Intrastate"],"explanation":"Oregon DMV рекомендует большинству водителей сертифицироваться как Non-excepted Interstate, что требует соответствия всем федеральным медицинским требованиям и также позволяет работу в режиме excepted-interstate и внутриштатных перевозках. Источник: Oregon DMV CDL Self-Certification; Oregon Commercial Driver Manual."},"37":{"q":"Чтобы получить и сохранить подтверждение HazMat (H) в штате Орегон, водитель должен пройти оценку угрозы безопасности Управления транспортной безопасности (Transportation Security Administration, TSA), включая снятие отпечатков пальцев, которую необходимо обновлять как часто?","options":["Каждые 2 года","Каждые 3 года","Каждые 5 лет","Каждые 8 лет"],"explanation":"Подтверждение HazMat в штате Орегон требует оценки угрозы безопасности TSA с проверкой биографии на основе отпечатков пальцев, которую необходимо обновлять каждые пять лет. Источник: Oregon DMV CDL Endorsements & Restrictions (49 CFR 1572)."},"38":{"q":"Водитель, самостоятельно сертифицирующийся как Excepted Interstate в штате Орегон, всё равно должен соответствовать какому медицинскому стандарту?","options":["Никакому медицинскому стандарту вообще","Полным федеральным медицинским стандартам для межштатных перевозок","Медицинским стандартам CDL штата Орегон","Только проверке зрения при продлении"],"explanation":"Водитель из штата Орегон, который сертифицируется как Excepted Interstate, занимается только операциями, исключёнными по федеральным правилам (например, 49 CFR 390.3(f), 391.2), и не обязан соответствовать полным федеральным медицинским стандартам, но всё равно должен соответствовать медицинским стандартам CDL штата Орегон. Источник: Oregon DMV CDL Self-Certification; Oregon Commercial Driver Manual."},"39":{"q":"В штате Орегон, при какой концентрации алкоголя в крови (BAC) на этом уровне или выше управление коммерческим механическим транспортным средством (CMV) является незаконным?","options":["0.08%","0.04%","0.02%","0.10%"],"explanation":"Орегон принимает федеральный стандарт для CMV: управлять CMV с BAC 0.04% или более незаконно, что составляет половину предела 0.08% для некоммерческих водителей. Источник: Oregon Commercial Driver Manual, Section 1 (Disqualifications); 49 CFR 383.51."},"40":{"q":"По правилу подразумеваемого согласия (implied-consent) штата Орегон для коммерческих водителей, что является верным, когда вы управляете CMV?","options":["Вы можете отказаться от любого тестирования без штрафа","Считается, что вы дали согласие на тестирование на алкоголь","Тестирование требует отдельного подписанного отказа от прав на каждую поездку","Согласие применяется только при BAC выше 0.08%"],"explanation":"Oregon CDL Manual гласит, что, управляя CMV, вы считаетесь давшим согласие на тестирование на алкоголь. Отказ от теста влечёт ту же дисквалификацию, что и серьёзное правонарушение. Источник: Oregon Commercial Driver Manual, Section 1; ORS 813.100."},"41":{"q":"Владелец CDL штата Орегон осуждён за управление CMV с BAC 0.04% или выше в ПЕРВЫЙ раз, без перевозки опасных материалов. Каков минимальный срок дисквалификации?","options":["60 days","90 days","1 year","3 years"],"explanation":"Первое серьёзное правонарушение, включая BAC в CMV 0.04% или выше, дисквалифицирует водителя как минимум на 1 year в штате Орегон. Источник: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"42":{"q":"Если первое серьёзное правонарушение (такое как BAC 0.04%) происходит, когда водитель управляет CMV с табличками (placarded) для опасных материалов, какова минимальная дисквалификация в штате Орегон?","options":["1 year","18 months","3 years","5 years"],"explanation":"Когда первое серьёзное правонарушение происходит в CMV с табличками (placarded) для опасных материалов, дисквалификация увеличивается как минимум до 3 years. Источник: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"43":{"q":"Какова дисквалификация в штате Орегон за ВТОРОЕ серьёзное правонарушение, совершённое владельцем CDL?","options":["3 years","5 years","10 years","Пожизненно"],"explanation":"Второе серьёзное правонарушение (например, второй DUI в CMV или серьёзное правонарушение после предыдущего) приводит к пожизненной дисквалификации CDL в штате Орегон. Источник: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"44":{"q":"Владелец CDL штата Орегон отказывается пройти тестирование на алкоголь во время управления CMV (первый случай). Как это рассматривается для целей дисквалификации?","options":["Без штрафа CDL, только денежный штраф","Рассматривается как серьёзное правонарушение: дисквалификация не менее 1 year","Дисквалификация на 30 days","Рассматривается как серьёзное нарушение: 60 days"],"explanation":"Отказ от тестирования на алкоголь входит в число серьёзных правонарушений и влечёт дисквалификацию не менее чем на 1 year (3 years, если есть таблички для опасных материалов), так же как и превышение BAC. Источник: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51; ORS 813.100."},"45":{"q":"Владелец CDL штата Орегон использует CMV для совершения тяжкого преступления (felony), связанного с контролируемым веществом (изготовление, распространение или сбыт). Какова дисквалификация?","options":["1 year","3 years","10 years","Пожизненно, без восстановления"],"explanation":"Использование CMV для совершения тяжкого преступления, связанного с контролируемыми веществами, приводит к пожизненной дисквалификации без возможности восстановления. Источник: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"46":{"q":"У водителя CDL в штате Орегон обнаружено заметное количество алкоголя НИЖЕ 0.04% во время несения службы. Что происходит?","options":["Ничего, это ниже допустимого предела","Отстранение от работы (out-of-service) на 24 hours","Дисквалификация на 1 year","Отстранение от работы (out-of-service) на 1 hour"],"explanation":"Любое заметное количество алкоголя ниже 0.04% не влечёт дисквалификацию за серьёзное правонарушение, но приводит к отстранению водителя от работы (out-of-service) на 24 hours. Источник: Oregon Commercial Driver Manual, Section 1; 49 CFR 392.5."},"47":{"q":"Что из перечисленного классифицируется как «серьёзное нарушение правил дорожного движения» (serious traffic violation) для владельца CDL штата Орегон?","options":["Парковка в зоне, где парковка запрещена","Превышение скорости на 15 mph или более сверх предела","Перегоревший габаритный фонарь","Движение на 5 mph выше предела"],"explanation":"Серьёзные нарушения правил дорожного движения включают превышение скорости, определяемое как 15 mph или более выше установленного предела, безрассудное вождение, неправильную или беспорядочную смену полос и слишком близкое следование. Источник: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"48":{"q":"Сколько серьёзных нарушений правил дорожного движения в течение 3-летнего периода влечёт дисквалификацию в штате Орегон, и какова продолжительность ПЕРВОЙ такой дисквалификации?","options":["1 нарушение; 30 days","2 нарушения; не менее 60 days","2 нарушения; не менее 30 days","3 нарушения; не менее 60 days"],"explanation":"Два серьёзных нарушения правил дорожного движения в течение 3 years приводят к дисквалификации не менее чем на 60 days. Источник: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"49":{"q":"Владелец CDL штата Орегон совершает ТРИ серьёзных нарушения правил дорожного движения в течение 3-летнего периода. Какова минимальная дисквалификация?","options":["60 days","90 days","120 days","1 year"],"explanation":"Три или более серьёзных нарушения правил дорожного движения в течение 3 years приводят к дисквалификации не менее чем на 120 days. Источник: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"50":{"q":"Засчитываются ли серьёзные нарушения правил дорожного движения в счёт дисквалификации CDL, если они совершены на ЛИЧНОМ (некоммерческом) транспортном средстве водителя?","options":["Нет, засчитываются только нарушения на CMV","Да, если они приводят к приостановлению или аннулированию лицензии","Только если замешан алкоголь","Засчитываются только нарушения на межштатных автомагистралях"],"explanation":"Серьёзные нарушения правил дорожного движения, совершённые не на CMV, засчитываются владельцу CDL, если осуждение приводит к приостановлению или аннулированию водительской лицензии. Источник: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"51":{"q":"За ВТОРОЕ нарушение на железнодорожном переезде (railroad-highway grade crossing) в течение 3 лет, какова минимальная дисквалификация в штате Орегон?","options":["60 days","120 days","180 days","1 year"],"explanation":"Второе нарушение на железнодорожном переезде в течение 3-летнего периода приводит к дисквалификации не менее чем на 120 days. Источник: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"52":{"q":"Какова минимальная дисквалификация в штате Орегон за ТРЕТЬЕ нарушение на железнодорожном переезде (railroad-highway grade crossing) в течение 3-летнего периода?","options":["120 days","180 days","1 year","3 years"],"explanation":"Третье или последующее нарушение на железнодорожном переезде в течение 3 years приводит к дисквалификации не менее чем на 1 year. Источник: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"53":{"q":"Владелец CDL штата Орегон нарушает предписание об отстранении от работы (out-of-service order) в ПЕРВЫЙ раз, НЕ перевозя опасные материалы или пассажиров. Какова минимальная дисквалификация?","options":["60 days","90 days","180 days","1 year"],"explanation":"Первое нарушение предписания об отстранении от работы (без опасных материалов, без пассажиров) приводит к дисквалификации не менее чем на 180 days. Источник: Oregon Commercial Driver Manual, Section 1 / ODOT Commercial Driver Convictions page; 49 CFR 383.51."},"54":{"q":"Водитель нарушает предписание об отстранении от работы (out-of-service order) в ПЕРВЫЙ раз, перевозя опасные материалы (или управляя транспортным средством, предназначенным для 16+ пассажиров). Какова минимальная дисквалификация в штате Орегон?","options":["180 days","1 year","3 years","5 years"],"explanation":"Первое нарушение предписания об отстранении от работы при перевозке опасных материалов или управлении транспортным средством на 16 или более пассажиров приводит к дисквалификации не менее чем на 1 year, что дольше базового срока в 180 days. Источник: ODOT Commercial Driver Convictions page; 49 CFR 383.51."},"55":{"q":"Какова минимальная дисквалификация за ВТОРОЕ нарушение предписания об отстранении от работы (out-of-service order) в течение 10 лет, не связанное с опасными материалами или пассажирами?","options":["1 year","2 years","3 years","5 years"],"explanation":"Второе нарушение предписания об отстранении от работы в течение 10 years (без опасных материалов, без пассажиров) приводит к дисквалификации не менее чем на 3 years; если были задействованы опасные материалы или пассажиры, срок возрастает не менее чем до 5 years. Источник: ODOT Commercial Driver Convictions page; 49 CFR 383.51."},"56":{"q":"Помимо дисквалификации лицензии, какой гражданский штраф (civil penalty) налагает Oregon/ODOT на водителя за ПЕРВОЕ нарушение предписания об отстранении от работы (out-of-service order)?","options":["$650","$1,000","$3,861","$7,723"],"explanation":"ODOT налагает гражданский штраф в размере $3,861 за первое нарушение предписания об отстранении от работы и $7,723 за второе или последующее нарушение, в дополнение к дисквалификации. Источник: ODOT Commercial Driver Convictions page; 49 CFR 383.53."},"57":{"q":"По правилам, применяемым к водителям CDL штата Орегон, что запрещено в отношении мобильных телефонов во время управления CMV?","options":["Любая радиосвязь запрещена","Держать телефон во время разговора, набирать более одной кнопки или отправлять текстовые сообщения","Звонки в режиме hands-free также запрещены","Телефоны должны быть всегда выключены"],"explanation":"Водители CMV не могут держать мобильный телефон во время разговора, набирать номер, нажимая более одной кнопки, или отправлять/читать текстовые сообщения во время движения; нарушение, связанное с набором текста/держанием телефона в руке, является серьёзным нарушением правил дорожного движения (максимальный федеральный штраф $2,750), которое засчитывается в счёт дисквалификации на 60/120-day. Источник: Oregon Commercial Driver Manual, Section 1; 49 CFR 392.80-392.82, 383.51."},"58":{"q":"Согласно закону штата Орегон «Move Over Law» («Уступи дорогу»), когда вы приближаетесь к стоящему аварийному автомобилю, эвакуатору, машине дорожной помощи или транспортному средству с включённой аварийной сигнализацией на многополосной дороге и НЕ можете безопасно перестроиться в несоседнюю полосу, что вы обязаны сделать?","options":["Снизить скорость как минимум на 5 mph ниже установленного или обозначенного ограничения скорости","Полностью остановиться, пока автомобиль не уедет","Снизить скорость ровно на 10 mph ниже установленного ограничения скорости","Сохранять установленную скорость, но подавать звуковой сигнал"],"explanation":"Закон штата Орегон «Move Over Law» (ORS 811.147) требует, чтобы водители перестраивались в несоседнюю полосу, если это возможно; если это невозможно, они должны снизить скорость как минимум на 5 mph ниже установленного или обозначенного ограничения скорости и двигаться с осторожностью. Источник: ORS 811.147; Oregon Driver Manual."},"59":{"q":"Нарушение закона штата Орегон «Move Over Law» (несоблюдение безопасной дистанции от стоящего аварийного автомобиля, машины дорожной помощи, эвакуатора или машины скорой помощи) классифицируется как какой тип правонарушения?","options":["Дорожное нарушение класса B (Class B traffic violation)","Дорожное нарушение класса A (Class A traffic violation)","Мисдиминор класса C (Class C misdemeanor)","Дорожное нарушение класса D (Class D traffic violation)"],"explanation":"Несоблюдение безопасной дистанции от аварийного автомобиля, машины дорожной помощи, эвакуатора или машины скорой помощи согласно закону штата Орегон «Move Over Law» является дорожным нарушением класса B. Источник: ORS 811.147."},"60":{"q":"В штате Орегон, когда школьный автобус остановился на двусторонней улице с включёнными мигающими красными огнями, на каком расстоянии должен остановиться приближающийся водитель?","options":["20 feet или более от автобуса","10 feet или более от автобуса","30 feet или более от автобуса","50 feet или более от автобуса"],"explanation":"Орегон требует, чтобы водители останавливались на расстоянии 20 feet или более от школьного автобуса с включёнными мигающими красными предупреждающими огнями и оставались на месте, пока огни не перестанут мигать. Источник: ORS 811.155; Oregon Driver Manual."},"61":{"q":"Согласно закону штата Орегон, какая ЕДИНСТВЕННАЯ ситуация, в которой встречный водитель НЕ обязан останавливаться перед школьным автобусом с включёнными мигающими красными огнями?","options":["Автобус остановился на другой проезжей части, отделённой физическим разделителем или барьером","Автобус остановился в жилой зоне с ограничением 25 mph","Между водителем и автобусом есть центральная полоса для левого поворота в обоих направлениях","Дорога размечена сплошной жёлтой осевой линией"],"explanation":"В штате Орегон водитель не обязан останавливаться только в том случае, если автобус с включёнными красными огнями находится на другой проезжей части, то есть шоссе разделено физическим разделителем или барьером на отдельные проезжие части. Нанесённая жёлтая линия или центральная полоса для поворота НЕ создают отдельных проезжих частей, поэтому останавливаться должны все полосы. Источник: ORS 811.155; Oregon Driver Manual."},"62":{"q":"Несоблюдение остановки перед мигающими красными сигнальными огнями школьного автобуса в штате Орегон является каким уровнем дорожного правонарушения?","options":["Дорожное нарушение класса A (Class A traffic violation)","Дорожное нарушение класса B (Class B traffic violation)","Дорожное нарушение класса C (Class C traffic violation)","Мисдиминор класса A (Class A misdemeanor)"],"explanation":"Несоблюдение остановки перед сигнальными огнями автобуса согласно ORS 811.155 является дорожным нарушением класса A — наиболее серьёзным классом дорожных нарушений в штате Орегон. Источник: ORS 811.155."},"63":{"q":"Когда водитель CDL в штате Орегон должен остановиться на железнодорожном переезде в транспортном средстве с табличками HazMat (и нет размеченной стоп-линии), где должно остановиться транспортное средство?","options":["Не ближе 15 feet и не дальше 50 feet от ближайшего рельса","Не ближе 10 feet и не дальше 25 feet от ближайшего рельса","Не ближе 5 feet и не дальше 15 feet от ближайшего рельса","Не ближе 50 feet и не дальше 100 feet от ближайшего рельса"],"explanation":"Водитель транспортного средства с табличками HazMat, груза хлора или цистерны с опасными материалами (загруженной или пустой) должен остановиться не ближе 15 feet и не дальше 50 feet от ближайшего рельса при отсутствии стоп-линии. Источник: Oregon Commercial Driver Manual Section 9; ORS 811.460."},"64":{"q":"При пересечении железнодорожных путей в транспортном средстве с табличками HazMat в штате Орегон что конкретно запрещает правило?","options":["Ручное переключение передач во время нахождения на путях","Использование моторного тормоза во время нахождения на путях","Включение аварийной сигнализации во время нахождения на путях","Подачу звукового сигнала во время нахождения на путях"],"explanation":"Правило штата Орегон о переездах повышенного риска требует, чтобы водитель пересекал пути на передаче, не требующей ручного переключения передач, поэтому нельзя переключать передачи во время нахождения на путях; продолжайте движение только тогда, когда уверены, что сможете освободить пути без остановки. Источник: ORS 811.460; Oregon Commercial Driver Manual Section 9."},"65":{"q":"Какое из этих транспортных средств НЕ относится к транспортным средствам «повышенного риска», которым по закону штата Орегон необходимо останавливаться на каждом железнодорожном переезде?","options":["Пустой бортовой грузовик, перевозящий обычный груз","Школьный автобус","Загруженная или пустая цистерна, перевозящая опасные материалы","Коммерческий автобус, перевозящий пассажиров"],"explanation":"ORS 811.460 перечисляет транспортные средства повышенного риска, которые должны останавливаться на переездах: школьные автобусы, определённые автобусы для школьных мероприятий и перевозки рабочих, коммерческие автобусы, транспортные средства, перевозящие взрывчатые/легковоспламеняющиеся/едкие вещества, а также цистерны с опасными материалами (загруженные или пустые). Обычный грузовик с неопасным грузом не обязан останавливаться, если только этого не требуют сигналы. Источник: ORS 811.460."},"66":{"q":"В штате Орегон каково стандартное максимальное ограничение скорости для коммерческого транспортного средства массой более 10,000 pounds GVWR, если не установлена другая скорость?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"Если не установлена другая скорость, максимальное значение по умолчанию для коммерческих транспортных средств массой более 10,000 lbs GVWR (или седельных тягачей массой более 8,000 lbs GVWR) составляет 55 mph. Источник: ORS 811.111; ORS 810.180."},"67":{"q":"Согласно правилу штата Орегон, наивысшая скорость, которую Департамент транспорта может назначить для коммерческих транспортных средств на межштатном шоссе, составляет:","options":["65 mph","70 mph","60 mph","75 mph"],"explanation":"ODOT может устанавливать назначенные скорости на межштатных трассах, но не может превышать 65 mph для коммерческих транспортных средств (предел для остальных транспортных средств составляет 70 mph). На некоторых участках межштатных трасс Орегона скорость для грузовиков была повышена до 60 mph там, где легковые автомобили едут со скоростью 65. Источник: ORS 810.180; OAR 734-020-0010."},"68":{"q":"На дороге штата Орегон с двумя или более полосами движения в одном направлении какие транспортные средства обязаны двигаться по правой полосе, кроме случаев обгона или поворота?","options":["Кемперы, транспортные средства с прицепом и транспортные средства с регистрационной массой 10,000 pounds или более","Только транспортные средства с тремя или более осями","Только транспортные средства с табличками HazMat","Все транспортные средства, движущиеся со скоростью ниже 45 mph"],"explanation":"ORS 811.325 требует, чтобы любой кемпер, любое транспортное средство с прицепом и любое транспортное средство с регистрационной массой 10,000 lbs или более использовали правую полосу на многополосных дорогах с односторонним направлением, за исключением случаев обгона, поворота налево, реагирования на чрезвычайную ситуацию, избегания вливающегося потока или согласно указаниям устройств управления движением. Источник: ORS 811.325."},"69":{"q":"Несоблюдение движения кемпера, прицепа или грузовика (10,000 lbs и более) по правой полосе на многополосном шоссе штата Орегон является каким видом правонарушения?","options":["Дорожное нарушение класса B (Class B traffic violation)","Дорожное нарушение класса A (Class A traffic violation)","Дорожное нарушение класса C (Class C traffic violation)","Дорожное нарушение класса D (Class D traffic violation)"],"explanation":"Нарушение требования о движении по правой полосе согласно ORS 811.325 является дорожным нарушением класса B. Источник: ORS 811.325."},"70":{"q":"Что является признанным законным исключением, позволяющим грузовику в штате Орегон (10,000 lbs и более) покинуть правую полосу на многополосном шоссе?","options":["Обгон и опережение другого транспортного средства, движущегося в том же направлении","Желание поддерживать более высокую крейсерскую скорость","Сохранение большей дистанции до впереди идущего транспортного средства","Избегание износа покрытия правой полосы"],"explanation":"ORS 811.325 разрешает покидать правую полосу для законного обгона и опережения, для подготовки к повороту налево, для реагирования на чрезвычайные условия, для избегания транспорта, въезжающего с полос разгона/слияния, или согласно указаниям устройств управления движением. Источник: ORS 811.325."},"71":{"q":"На разделённом шоссе или шоссе с односторонним движением в штате Орегон, где водитель CDL должен разместить три аварийных предупреждающих треугольника при остановке на дороге?","options":["В пределах 10 feet от задней части, а также на расстоянии 100 feet и 200 feet в сторону приближающегося транспорта","В пределах 25 feet от задней части, а также на расстоянии 50 feet и 150 feet в сторону приближающегося транспорта","В пределах 10 feet от передней части, а также на расстоянии 100 feet и 300 feet в сторону приближающегося транспорта","В пределах 50 feet от задней части, а также на расстоянии 100 feet и 250 feet в сторону приближающегося транспорта"],"explanation":"На шоссе с односторонним движением или разделённом шоссе разместите одно предупреждающее устройство в пределах 10 feet от задней части в сторону приближающегося транспорта, одно примерно в 100 feet позади и одно примерно в 200 feet позади. Этот федеральный стандарт (49 CFR 392.22) изучается в Oregon Commercial Driver Manual. Источник: Oregon Commercial Driver Manual; 49 CFR 392.22."},"72":{"q":"На двухполосной двусторонней дороге штата Орегон, после того как транспортное средство CDL остановилось на проезжей части, в течение скольких минут водитель должен разместить аварийные предупреждающие устройства?","options":["В течение 10 минут","В течение 5 минут","В течение 15 минут","В течение 30 минут"],"explanation":"Водитель CDL должен разместить предупреждающие устройства (три треугольника или эквивалент) в течение 10 минут после остановки на проезжей части или обочине дороги. Источник: Oregon Commercial Driver Manual; 49 CFR 392.22."},"73":{"q":"В штате Орегон какова максимальная разрешённая законом ШИРИНА транспортного средства/груза, до того как потребуется разрешение на негабаритный груз?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"Максимальная разрешённая законом ширина в штате Орегон составляет 8 feet 6 inches; грузы, превышающие это значение, требуют разрешения на негабаритный груз от Commerce and Compliance Division при ODOT. Источник: ORS 818.080; ODOT Legal Vehicle Dimensions."},"74":{"q":"Какова максимальная разрешённая законом ВЫСОТА транспортного средства в штате Орегон, до того как потребуется разрешение на негабаритный груз?","options":["14 feet 0 inches","13 feet 6 inches","13 feet 0 inches","15 feet 0 inches"],"explanation":"Максимальная разрешённая законом высота в штате Орегон составляет 14 feet 0 inches; грузы, превышающие это значение, требуют разрешения на негабаритный груз. (Обратите внимание, что во многих других штатах используется 13'6\".) Источник: ORS 818.080; ODOT Legal Vehicle Dimensions."},"75":{"q":"Орегон требует, чтобы все транспортные средства массой более 10,000 lbs GVW возили цепи противоскольжения в снежный сезон:","options":["Всякий раз, когда существуют условия, при которых их использование может потребоваться или быть необходимым","Только при движении к востоку от Каскадных гор","Только по выходным с декабря по февраль","Только если на транспортном средстве нет шипованных шин"],"explanation":"Закон штата Орегон требует, чтобы транспортные средства массой более 10,000 lbs GVW возили цепи всякий раз, когда существуют условия, при которых цепи могут потребоваться или быть необходимыми, и устанавливали их, когда действует закон о цепях (обычно с октября по март на горных перевалах). Источник: ODOT Commerce and Compliance Division, Chains and Traction Tires."},"76":{"q":"В какой период разрешено использование шипованных шин на дорогах штата Орегон?","options":["С 1 ноября по 31 марта","С 1 октября по 30 апреля","С 15 ноября по 15 апреля","С 1 декабря по 1 марта"],"explanation":"Шипованные шины разрешены в штате Орегон только с 1 ноября по 31 марта; использование их вне этого периода может повлечь штраф. Источник: ODOT / Oregon TripCheck; положения ORS о шипованных шинах."},"77":{"q":"Орегон известен ранним устройством аварийного съезда для грузовиков на крутом спуске Interstate 5. Где была построена и испытана первая в стране аварийная улавливающая полоса для грузовиков на спуске (отрицательный уклон)?","options":["Вблизи Siskiyou Summit на I-5 на юге штата Орегон","На спуске Cabbage Hill на I-84","В Government Camp на US 26 через гору Mount Hood","На перевале Santiam Pass на US 20"],"explanation":"Первая в Соединённых Штатах аварийная улавливающая полоса для грузовиков на спуске (отрицательный уклон) была построена и испытана в 1977 году вдоль I-5 вблизи Siskiyou Summit на юге штата Орегон — заметно крутого горного спуска, где особое внимание уделяется использованию аварийных съездов. Источник: ODOT; рекомендации Oregon Commercial Driver Manual по вождению в горах."},"78":{"q":"В штате Орегон какое государственное ведомство выдаёт коммерческие водительские права (CDL) и управляет процессом тестирования?","options":["Oregon DMV, часть Driver & Motor Vehicle Services при Oregon Department of Transportation (ODOT)","Commercial Vehicle Division полиции штата Орегон","Региональное отделение федерального Motor Carrier Safety Administration (FMCSA)","Corporations and Licensing Division при Секретаре штата Орегон"],"explanation":"Орегонские CDL выдаются Oregon DMV, который является частью Driver & Motor Vehicle Services при Oregon Department of Transportation (ODOT). Источник: страница Oregon DMV «Getting a CDL or CLP»; Oregon Commercial Driver Manual."},"79":{"q":"Транспортному средству требуется орегонский CDL по массе, когда его полная разрешённая масса (GVWR) составляет не менее скольких pounds?","options":["26,001 pounds","10,001 pounds","18,000 pounds","33,000 pounds"],"explanation":"Орегон требует CDL для управления транспортным средством с GVWR 26,001 pounds или более (а также для составов, где буксируемая единица превышает 10,000 lbs). Источник: Oregon Commercial Driver Manual, Section 1."},"80":{"q":"Помимо массы, какой порог по числу пассажиров делает транспортное средство требующим орегонского CDL?","options":["Рассчитано на перевозку 16 или более человек, включая водителя","Рассчитано на перевозку 9 или более человек, включая водителя","Рассчитано на перевозку 24 или более человек, не считая водителя","Рассчитано на перевозку 12 или более человек, включая водителя"],"explanation":"CDL требуется для транспортного средства, рассчитанного на перевозку 16 или более человек, включая водителя. Третьим основанием является перевозка опасных материалов, требующих табличек. Источник: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.5 в применении в штате Орегон."},"81":{"q":"При подаче заявления на орегонский CDL или коммерческое ученическое разрешение заявитель должен «самостоятельно удостоверить» (self-certify), в каком виде коммерческой деятельности он будет работать. Какой набор категорий предлагает Орегон?","options":["Non-excepted Interstate, Excepted Interstate и Non-excepted Intrastate","Interstate Hazmat, Intrastate Hazmat и только Non-Hazmat","Federal Carrier, State Carrier и Private Carrier","Эксплуатация класса A, класса B и класса C"],"explanation":"Oregon DMV предлагает три категории самостоятельного удостоверения: Non-excepted Interstate, Excepted Interstate и Non-excepted Intrastate. (Excepted Intrastate является четвёртой категорией FMCSA; Орегон не выделяет её отдельно.) Источник: Oregon DMV CDL application/self-certification; 49 CFR 383.71."},"82":{"q":"Заявитель на орегонский CDL, который самостоятельно удостоверяет себя как «Non-excepted Interstate», обязан сделать что в отношении медицинской квалификации?","options":["Предоставить DMV копию действующего сертификата медицинского эксперта DOT и хранить актуальный сертификат в деле","Возить бумажную медицинскую карту в грузовике, но никогда не передавать её в DMV","Подать нотариально заверенное заявление о том, что медосмотр не требуется","Пройти дополнительный дорожный тест физической пригодности, проводимый DMV"],"explanation":"Водитель non-excepted interstate должен предоставить в Oregon DMV копию действующего сертификата медицинского эксперта (медицинской карты DOT) и несёт ответственность за хранение актуального сертификата в деле, иначе CDL понижается в категории. Источник: Oregon DMV CDL medical certification; 49 CFR 383.71/391.45."},"83":{"q":"Кто имеет право проводить медицинский осмотр DOT, по результатам которого выдаётся сертификат медицинского эксперта, используемый для орегонского CDL?","options":["Медицинский эксперт, внесённый в FMCSA National Registry of Certified Medical Examiners","Любой лицензированный фармацевт в штате Орегон","Экзаменатор в полевом офисе Oregon DMV","Любой врач, если он лицензирован в любом штате США"],"explanation":"Медицинский осмотр DOT должен проводиться медицинским экспертом, внесённым в FMCSA National Registry of Certified Medical Examiners. Источник: Oregon DMV «Getting a CDL or CLP»; 49 CFR 390.103."},"84":{"q":"Прежде чем заявитель сможет сдать тест навыков CDL в штате Орегон, он должен сначала получить какой документ?","options":["Коммерческое ученическое разрешение (CLP)","Временный CDL класса C","Федеральное разрешение на межштатную деятельность (номер MC)","Временное освобождение из статуса out-of-service"],"explanation":"Заявители, которым требуется тестирование навыков, должны сначала получить коммерческое ученическое разрешение (CLP), сдав необходимый тест(ы) на знания. Источник: Oregon DMV CDL process; OAR 735-063-0250 / 735-063-0260."},"85":{"q":"Чтобы получить орегонское коммерческое ученическое разрешение класса A, какие тесты на знания должен сдать заявитель?","options":["Тест General Knowledge и тест Combination Vehicles (плюс Air Brakes при необходимости)","Только тест General Knowledge","Тест General Knowledge и тест Hazardous Materials","Только тест Combination Vehicles"],"explanation":"CLP класса A требует сдачи теста General Knowledge и теста Combination Vehicles, плюс теста Air Brakes, если транспортное средство оснащено пневматическими тормозами. Источник: OAR 735-063-0250; Oregon Commercial Driver Manual."},"86":{"q":"Каков минимальный проходной балл на тестах на знания орегонского CDL?","options":["80 процентов правильных ответов","70 процентов правильных ответов","90 процентов правильных ответов","75 процентов правильных ответов"],"explanation":"Для прохождения каждого теста на знания орегонского CDL требуется не менее 80 процентов правильных ответов (например, 40 из 50 вопросов в тесте General Knowledge). Источник: Oregon Commercial Driver Manual / Oregon DMV; 49 CFR 383.135."},"87":{"q":"Тест навыков орегонского CDL состоит из трёх частей, которые необходимо сдавать в установленном порядке. Каков этот порядок?","options":["Предрейсовый осмотр транспортного средства, затем базовые навыки управления, затем вождение по дороге","Вождение по дороге, затем предрейсовый осмотр, затем базовые навыки управления","Базовые навыки управления, затем вождение по дороге, затем предрейсовый осмотр","Предрейсовый осмотр, затем вождение по дороге, затем базовые навыки управления"],"explanation":"Тест навыков проводится в следующем порядке: сначала предрейсовый осмотр транспортного средства, затем базовые навыки управления, затем вождение по дороге; каждая часть должна быть сдана перед переходом к следующей. Источник: OAR 735-063-0260 / OAR 735-060-0120."},"88":{"q":"Федеральное обучение водителей начального уровня (ELDT) должно быть завершено до тестирования в штате Орегон для какого из следующих случаев?","options":["Получение CDL класса A или B впервые, повышение с класса B до A или получение впервые отметок passenger/school bus/hazmat","Каждое продление CDL, независимо от класса","Только для водителей младше 21 года","Только при добавлении отметки doubles/triples"],"explanation":"ELDT требуется до тестирования при получении впервые CDL класса A или B, при повышении с класса B до класса A или при получении впервые отметки passenger, school bus или hazardous materials. Источник: Oregon DMV; 49 CFR Part 380 Subpart F."},"89":{"q":"Обучение водителей начального уровня (ELDT) для орегонского CDL должно проводиться организацией, которая внесена куда?","options":["В FMCSA Training Provider Registry (TPR)","В список одобренных средних школ Oregon DMV","В реестр членов Oregon Trucking Associations","В офис ученичества U.S. Department of Labor"],"explanation":"Обучение ELDT должно быть завершено через школу или организацию, внесённую в FMCSA Training Provider Registry (TPR), прежде чем записываться на тест навыков или сдавать тест на знания hazmat. Источник: Oregon DMV; FMCSA Training Provider Registry."},"90":{"q":"Как долго орегонское коммерческое ученическое разрешение должно находиться на руках, прежде чем его обладатель сможет сдать тест навыков CDL?","options":["Не менее 14 days","Не менее 30 days","Не менее 7 days","Не менее 60 days"],"explanation":"Oregon DMV должен был выдать непросроченное CLP не менее чем за 14 days до теста навыков. Источник: OAR 735-063-0260."},"91":{"q":"Как долго действует орегонское коммерческое ученическое разрешение (CLP) и можно ли его продлить?","options":["Действует один год и не подлежит продлению","Действует 180 days и может быть продлено один раз","Действует два года и продлевается ежегодно","Действует 90 days и не подлежит продлению"],"explanation":"Орегонское CLP действует один год с момента выдачи и не подлежит продлению. Источник: ORS 807.285."},"92":{"q":"Проходной балл на тестах на знания орегонского CDL (и на завершённом тесте навыков) остаётся действительным в течение какого срока, прежде чем должен быть выдан CDL?","options":["Шесть месяцев","Три месяца","Один год","Тридцать дней"],"explanation":"Проходной балл теста на знания действителен в течение шести месяцев, и проходной балл за завершённый тест навыков CDL действителен в течение шести месяцев. Источник: OAR 735-063-0250 и OAR 735-063-0260."},"93":{"q":"После выдачи как долго действует орегонский CDL, прежде чем его необходимо продлить?","options":["8 years","4 years","5 years","10 years"],"explanation":"Орегонский CDL, выданный гражданину США или постоянному резиденту, действителен в течение 8 years — тот же стандартный цикл, что и для обычных орегонских водительских прав. Источник: Oregon DMV; ORS Chapter 807."},"94":{"q":"Каково окно продления орегонского CDL относительно даты истечения срока?","options":["До 12 months до истечения срока и до 2 years после истечения срока","Только в день истечения срока или после него, без досрочного продления","До 30 days до и до 30 days после истечения срока","Только до 6 months до истечения срока"],"explanation":"Орегонский CDL может быть продлён до 12 months до истечения срока и до 2 years после истечения срока; по прошествии этого времени водитель должен подать заявление на новые права. Источник: Oregon DMV «Renewing a Commercial Driver License»."},"95":{"q":"Какие документы должен предоставить заявитель на орегонский CDL/CLP для подтверждения права на получение при подаче заявления?","options":["Подтверждение полного юридического имени, гражданства США или законного постоянного резидентства, личности, даты рождения, адреса проживания и номера социального страхования","Только актуальную фотографию из паспорта и кредитную карту","Нотариально заверенное письмо работодателя и документ о праве собственности на транспортное средство","Подтверждение трёх лет опыта коммерческого вождения"],"explanation":"Заявители должны предоставить подтверждение полного юридического имени, гражданства США или законного постоянного резидентства, личности, даты рождения и адреса проживания, а также свой номер социального страхования. Источник: Oregon DMV «Getting a CDL or CLP»; OAR 735-063-0250."},"96":{"q":"При продлении орегонского CDL с отметкой Hazardous Materials какое дополнительное требование применяется?","options":["Сдать тест на знания HazMat и иметь действующую проверку безопасности TSA (оценку угрозы)","Предоставить нотариально заверенное письмо от последнего грузоотправителя по записи","Сдать CDL на 30 days на время проверки данных","Сдать повторный дорожный тест навыков на транспортном средстве с табличками"],"explanation":"Продление CDL с отметкой HazMat требует сдачи теста на знания HazMat и наличия действующей оценки угрозы безопасности TSA (проверки данных). Источник: Oregon DMV «Renewing a CDL»; 49 CFR Part 1572."},"97":{"q":"Если обладатель орегонского CDL допускает истечение срока требуемого сертификата медицинского эксперта (при non-excepted самостоятельном удостоверении), что делает Oregon DMV?","options":["Понижает CDL в категории, отзывая права на коммерческое вождение до тех пор, пока действующий медицинский сертификат не будет в деле","Приостанавливает также обычные права на вождение (класс C)","Выдаёт автоматическое медицинское освобождение на 90 days без необходимости каких-либо действий","Направляет водителя в полицию штата Орегон для выписки штрафа"],"explanation":"Если медицинский сертификат водителя non-excepted истекает и действующего сертификата нет в деле, Oregon DMV понижает CDL в категории, отзывая коммерческие права до тех пор, пока не будет подан действующий сертификат; обычные права сохраняются. Источник: Oregon DMV CDL medical certification; 49 CFR 383.73."}},"tr":{"0":{"q":"Oregon karayollarında çoğu ticari araç için aşırı boyut izni olmaksızın izin verilen yasal maksimum genişlik nedir?","options":["8 feet (96 inches)","8 feet 6 inches (102 inches)","9 feet (108 inches)","10 feet (120 inches)"],"explanation":"Oregon, kamu karayollarında toplam dış araç genişliğini 8 feet 6 inches (102 inches) ile sınırlar; bundan daha geniş herhangi bir şey için aşırı boyut izni gereklidir. Kaynak: ORS 818.080 (Maksimum boyut sınırları) ve Oregon DOT Commerce and Compliance Division, Yasal Araç Boyutları."},"1":{"q":"Oregon karayollarında izin olmaksızın çalışan bir araç için yük dahil yasal maksimum yükseklik nedir?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"Oregon, yük dahil maksimum yüksekliği 14 feet olarak belirler; bunu aşmak için aşırı boyut izni ve güzergah onayı gereklidir. Kaynak: ORS 818.080 ve Oregon DOT Yasal Araç Boyutları."},"2":{"q":"Özel bir uzunluk izni olmadan, Oregon'un genel karayollarında çoğu çekici-traktör ve yarı römork kombinasyonu için maksimum toplam uzunluk nedir?","options":["50 feet","55 feet","60 feet","75 feet"],"explanation":"Oregon'un genel karayollarında bir araç kombinasyonu için maksimum toplam uzunluk 60 feet'tir; daha uzun kombinasyonlara yalnızca belirlenmiş güzergahlarda veya izinle izin verilir. Kaynak: ORS 818.080 ve Oregon DOT Yasal Araç Boyutları."},"3":{"q":"Sınırsız toplam uzunluğa izin veren belirlenmiş Oregon güzergahlarında, bir traktör-yarı römork kombinasyonundaki tek bir yarı römorkun maksimum uzunluğu nedir?","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"Oregon, maksimum 53 feet yarı römork uzunluğuna izin verir; belirlenmiş güzergahlarda toplam kombinasyon uzunluğu sınırsız olabilir, ancak yarı römorkun kendisi 53 feet'i aşamaz. Kaynak: ORS 818.080 ve Oregon DOT Yasal Araç Boyutları."},"4":{"q":"Oregon karayollarında izin olmaksızın tek (solo) bir aracın maksimum uzunluğu nedir?","options":["35 feet","40 feet","45 feet","53 feet"],"explanation":"Oregon'da tek başına çalışan bir araç, izin olmaksızın 40 feet uzunluğu aşamaz. Kaynak: ORS 818.080 (Maksimum boyut sınırları)."},"5":{"q":"Oregon'da, fazla ağırlık izni olmaksızın herhangi bir tek dingile izin verilen maksimum ağırlık nedir?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"Oregon, herhangi bir tek dingili 20,000 pounds ile sınırlar. Kaynak: ORS 818.010 (Maksimum izin verilen ağırlık)."},"6":{"q":"Oregon'da fazla ağırlık izni olmaksızın bir tandem dingil grubuna izin verilen maksimum ağırlık nedir?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Oregon, bir tandem dingili (iki dingil) federal standartla uyumlu olarak 34,000 pounds ile sınırlar. Kaynak: ORS 818.010 (Maksimum izin verilen ağırlık)."},"7":{"q":"Oregon karayollarında fazla ağırlık veya uzatılmış ağırlık izni olmaksızın genellikle izin verilen maksimum brüt araç ağırlığı nedir?","options":["73,280 pounds","80,000 pounds","88,000 pounds","105,500 pounds"],"explanation":"Oregon'da standart maksimum brüt kombinasyon ağırlığı 80,000 pounds'tur; daha ağır bölünebilir yükler için bir ODOT uzatılmış ağırlık izni gereklidir. Kaynak: ORS 818.010 ve Oregon DOT Commerce and Compliance Division."},"8":{"q":"Bir ODOT uzatılmış (bölünebilir yük) ağırlık izni kapsamında, uygun bir araç Oregon'da maksimum ne kadar brüt kombinasyon ağırlığı taşıyabilir?","options":["90,000 pounds","98,000 pounds","105,500 pounds","129,000 pounds"],"explanation":"Oregon'un uzatılmış ağırlık izni, bölünebilir yükler taşırken uygun çok dingilli kombinasyonların 105,500 pounds brüt ağırlığa kadar çalışmasına izin verir. Kaynak: Oregon DOT Commerce and Compliance Division, Uzatılmış Ağırlık (Bölünebilir Yük) İzni."},"9":{"q":"Oregon yasası, lastik genişliğine göre lastiklerde taşınabilecek yükü sınırlar. İzin verilen lastik genişliği başına maksimum pound nedir?","options":["500 pounds per inch","550 pounds per inch","600 pounds per inch","650 pounds per inch"],"explanation":"Oregon, üreticinin yan duvar lastik derecelendirmesini kullanır, ancak lastik genişliği başına 600 pounds'u aşmamak kaydıyla, lastik genişliklerinin toplamı ile çarpılır. Kaynak: ORS 818.010 (Maksimum izin verilen ağırlık)."},"10":{"q":"Oregon, ardışık dingil grubuna aralarındaki mesafeye göre izin verilen maksimum brüt ağırlığı belirlemek için hangi formülü uygular?","options":["Federal Köprü Formülü (Köprü Brüt Ağırlık Formülü)","GAWR derecelendirme formülü","Oregon kilometre vergisi formülü","Yük Bağlama Formülü"],"explanation":"Oregon, dingil aralığına ve dingil sayısına göre iki veya daha fazla ardışık dingil grubundaki ağırlığı sınırlamak için Federal Köprü Formülü'nü, W = 500[LN/(N-1) + 12N + 36], benimser. Kaynak: ORS 818.010 ve Oregon DOT tarafından uygulanan 23 CFR 658."},"11":{"q":"Oregon'da kullanılan Federal Köprü Formülünde 'L' değişkeni neyi temsil eder?","options":["Ton cinsinden yasal yük sınırını","Grubun dış dingilleri arasındaki feet cinsinden mesafeyi","Römorkun feet cinsinden uzunluğunu","Gerekli plaka sayısını"],"explanation":"Köprü formülünde W = 500[LN/(N-1) + 12N + 36], L grubun en dıştaki dingilleri arasındaki feet cinsinden mesafedir, N dingil sayısıdır ve W izin verilen brüt ağırlıktır. Kaynak: Oregon DOT tarafından uygulanan Federal Köprü Formülü; ORS 818.010."},"12":{"q":"Bir ticari araç için ne zaman Oregon DOT aşırı boyut veya fazla ağırlık izni gereklidir?","options":["Yalnızca bir eyalet sınırını geçerken","Araç veya yük yasal boyut veya ağırlık sınırlarını aştığında her zaman","Yalnızca hafta sonları ve tatillerde","Yalnızca eyalet dışında kayıtlı araçlar için"],"explanation":"Genişlik, yükseklik, uzunluk veya ağırlık için Oregon'un yasal sınırlarını aşan herhangi bir araç veya yük, çalışmadan önce bir aşırı boyut/fazla ağırlık izni almalıdır. Kaynak: ORS 818.200 ve Oregon DOT Commerce and Compliance Division, Aşırı Boyut Operasyonları."},"13":{"q":"Hangi Oregon kurumu ticari araçlar için fazla boyut ve fazla ağırlık (aşırı boyut) izinlerini verir?","options":["Oregon Eyalet Polisi","Oregon DOT Commerce and Compliance Division","İlçe şerif ofisi","Federal Motor Carrier Safety Administration"],"explanation":"Oregon'da aşırı boyut ve fazla ağırlık izinleri, çevrimiçi olarak veya giriş noktalarında temin edilebilen Oregon Department of Transportation'ın Commerce and Compliance Division'ı (eski adıyla Motor Carrier Transportation Division) tarafından verilir. Kaynak: Oregon DOT Commerce and Compliance Division."},"14":{"q":"Oregon'un herhangi bir tek tekerleğe izin verdiği maksimum ağırlık nedir?","options":["8,000 pounds","10,000 pounds","12,000 pounds","17,000 pounds"],"explanation":"Oregon, herhangi bir tek tekerlekteki ağırlığı 10,000 pounds ile sınırlar. Kaynak: ORS 818.010 (Maksimum izin verilen ağırlık)."},"15":{"q":"Oregon'un 80,000 pound sınırını aşan bir 'bölünebilir yük' şu özelliğe sahiptir:","options":["Aşırı masraf veya hasar riski olmadan ayrılamaz","Makul olarak daha küçük, yasal yüklere bölünebilir","Her zaman tehlikeli madde olarak sınıflandırılır","Yalnızca gece taşınmalıdır"],"explanation":"Bölünebilir bir yük makul olarak daha küçük yasal yüklere ayrılabilir; Oregon'da bu tür yükler 80,000 pounds'u yalnızca bir ODOT uzatılmış (bölünebilir yük) ağırlık izni kapsamında aşabilir; aşırı boyut sapma izinleri kullanan bölünemez yüklerin aksine. Kaynak: Oregon DOT Commerce and Compliance Division."},"16":{"q":"İzin olmaksızın, Oregon'da bir aracın ÖN tarafından izin verilen maksimum yük çıkıntısı nedir?","options":["3 feet","4 feet","5 feet","6 feet"],"explanation":"Oregon, izin olmaksızın maksimum 4 feet ön yük çıkıntısına izin verir; daha fazla ön çıkıntı için aşırı boyut izni ve bayraklama gereklidir. Kaynak: ORS 818.080 ve Oregon DOT Yasal Araç Boyutları."},"17":{"q":"Oregon'da uygulanan Federal Köprü Formülünde, dingil sayısını aynı tutarken bir grubun dış dingilleri arasındaki aralığı artırmak genellikle:","options":["İzin verilen brüt ağırlığı azaltır","İzin verilen ağırlık üzerinde hiçbir etkisi yoktur","İzin verilen brüt ağırlığı artırır","Kamyonun kaydını geçersiz kılar"],"explanation":"L (dingil aralığı) pay kısmında olduğu için, dış dingiller arasındaki daha büyük mesafe o dingil grubu için izin verilen brüt ağırlığı artırır; yakın aralıklı dingiller köprüleri korumak için sınırlandırılır. Kaynak: Oregon DOT tarafından uygulanan Federal Köprü Formülü; ORS 818.010."},"18":{"q":"Oregon, eyaletin ekonomisi için önemli olan hangi taşımacılık türü için belirli ağırlık toleransları ve indirimli ücretli izinler sağlar?","options":["Yolcu kiralık otobüsleri","Tarım ve orman (tomruk) ürünleri taşımacılığı","Eyaletler arası paket teslimat minibüsleri","Kiralık taşıma kamyonları"],"explanation":"Oregon, çiftçilik ve keresteciliğin eyalet için önemini yansıtarak tarım ürünleri ve orman/tomruk ürünleri için belirli izinler ve ağırlık hükümleri sağlar (örneğin indirimli veya kayıt-ağırlığı toleransları ve uzatılmış ağırlık tomruk izinleri). Kaynak: Oregon DOT Commerce and Compliance Division ve ORS Bölüm 818 izin hükümleri."},"19":{"q":"Oregon'da, çekilen aracın 10,000 pound'dan ağır olması koşuluyla, 26,001 pound veya daha fazla Brüt Kombinasyon Ağırlık Derecelendirmesine (GCWR) sahip herhangi bir araç kombinasyonunu sürmek için hangi sınıf CDL gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Oregon standart CDL sınıflarını takip eder: bir Class A CDL, çekilen ünitenin 10,000 lbs'yi aştığı ve GCWR'si 26,001 lbs veya daha fazla olan herhangi bir araç kombinasyonunu kapsar. Kaynak: Oregon Commercial Driver Manual / Oregon DMV Sürücü Belgesi Sınıfları (49 CFR 383.91 ile aynıdır; ORS 807.031)."},"20":{"q":"Oregon kurallarına göre, hangi CDL sınıfı 26,001 pound veya daha fazla Brüt Araç Ağırlık Derecelendirmesine (GVWR) sahip tek bir aracı ya da 10,000 pound'u geçmeyen bir üniteyi çeken böyle bir aracı kapsar?","options":["Class A","Class B","Class C","Class M"],"explanation":"Oregon'da bir Class B CDL, GVWR'si 26,001 lbs veya daha fazla olan tek bir aracı ya da 10,000 lbs'yi aşmayan bir römork çeken böyle bir aracı kapsar. Kaynak: Oregon Commercial Driver Manual / Oregon DMV Sürücü Belgesi Sınıfları (49 CFR 383.91)."},"21":{"q":"Oregon'da, Class A veya Class B ağırlık eşiklerini karşılamayan daha küçük bir araç, sürücü dahil en az kaç kişiyi taşımak üzere tasarlandıysa yine de bir Class C CDL gerektirir?","options":["10","12","16","24"],"explanation":"Sürücü dahil 16 veya daha fazla kişiyi taşımak üzere tasarlanmış (Class A veya B karşılamayan) bir araç ya da plakartlı tehlikeli maddeleri taşımak için kullanılan bir araç için bir Class C CDL gereklidir. Kaynak: Oregon Commercial Driver Manual / Oregon DMV Sürücü Belgesi Sınıfları (49 CFR 383.91)."},"22":{"q":"16 veya daha fazla yolcu taşımanın yanı sıra, Oregon'da Class A veya B olamayacak kadar küçük bir araç için Class C CDL gerektiren diğer koşul nedir?","options":["5,000 pound'dan ağır herhangi bir römork çekmek","Plakart gerektiren miktarlarda tehlikeli madde taşımak","Bir eyalet karayolunda hava karardıktan sonra çalışmak","Ücret karşılığı herhangi bir çiftlik ürünü taşımak"],"explanation":"Oregon, plakart gerektiren miktarlarda tehlikeli madde taşımak için kullanılan daha küçük bir araç için bir Class C CDL gerektirir (ya da 16+ kişi taşımak için). Kaynak: Oregon Commercial Driver Manual; Oregon DMV CDL Sınıfları (49 CFR 383.91)."},"23":{"q":"Oregon, bir CDL üzerindeki Tehlikeli Maddeler onayı için hangi onay kodunu kullanır?","options":["H","N","T","X"],"explanation":"Tehlikeli Maddeler onayı Oregon'da 'H' olarak kodlanır. ('X' kodu birleşik Tank ve HazMat onayını temsil eder.) Kaynak: Oregon DMV CDL Onayları ve Kısıtlamaları; Oregon Commercial Driver Manual."},"24":{"q":"Bir Oregon sürücüsünün çift veya üçlü römork çeken bir ticari araç kullanması gerekiyor. Hangi onay gereklidir?","options":["P onayı","N onayı","T onayı","S onayı"],"explanation":"Oregon'da çift veya üçlü römork çeken herhangi bir ticari motorlu aracı sürmek için 'T' (Çiftli/Üçlü) onayı gereklidir ve bir bilgi testini geçerek elde edilir. Kaynak: Oregon DMV CDL Onayları; Oregon Commercial Driver Manual."},"25":{"q":"Oregon'da, Tank Aracı (N) onayı, bir CMV bireysel olarak 119 galondan fazla dereceli bir tankta sıvı veya gaz taşımak için tasarlandığında VE en az kaç galon toplam dereceli kapasiteye sahip olduğunda gereklidir?","options":["500 gallons","750 gallons","1,000 gallons","1,500 gallons"],"explanation":"Oregon, bireysel olarak 119 galondan fazla dereceli bir tankta ve 1,000 galon veya daha fazla toplam dereceli kapasiteyle sıvı veya gaz taşıyan bir araç için N (Tank) onayını gerektirir. Kaynak: Oregon Commercial Driver Manual; Oregon DMV CDL Onayları (49 CFR 383.5)."},"26":{"q":"Sürücü dahil 16 veya daha fazla kişi taşımak için tasarlanmış bir aracı sürmek için hangi Oregon CDL onayı gereklidir?","options":["P (Yolcu)","S (Okul Otobüsü)","T (Çiftli/Üçlü)","N (Tank)"],"explanation":"Oregon'da sürücü dahil 16 veya daha fazla yolcu taşımak için tasarlanmış bir aracı kullanmak için 'P' (Yolcu) onayı gereklidir; bir bilgi ve bir beceri testi gerektirir. Kaynak: Oregon DMV CDL Onayları; Oregon Commercial Driver Manual."},"27":{"q":"Oregon'da bir okul otobüsü sürmek için, bir CDL sahibinin yolcu aracı gereksinimlerini karşılamanın yanı sıra hangi onayı eklemesi gerekir?","options":["H onayı","S onayı","T onayı","X onayı"],"explanation":"Oregon'da bir okul otobüsü sürmek için 'S' (Okul Otobüsü) onayı gereklidir; bir başvuru sahibinin ayrıca P onayına sahip olması ve bir okul otobüsü bilgi ve beceri testini geçmesi gerekir. Kaynak: Oregon DMV CDL Onayları; Oregon Commercial Driver Manual."},"28":{"q":"Eyalet içi (yalnızca Oregon içinde) ticari sürücülükle sınırlı bir Oregon CDL'si almak için minimum yaş nedir?","options":["16 years old","18 years old","21 years old","25 years old"],"explanation":"Oregon, eyalet içi bir CDL için bir başvuru sahibinin en az 18 yaşında olmasını gerektirir; eyaletler arası sürücülük 21 yaş gerektirir. Kaynak: Oregon DMV 'CDL veya CLP Almak'; Oregon Commercial Driver Manual."},"29":{"q":"Oregon kurallarına göre, eyaletler arası ticarette bir ticari motorlu aracı sürmek için minimum yaş nedir?","options":["18 years old","19 years old","21 years old","23 years old"],"explanation":"Oregon, eyaletler arası ticarette bir CMV kullanmak için bir sürücünün en az 21 yaşında olmasını gerektirir; yalnızca eyalet içi operasyona 18 yaşında izin verilir. Kaynak: Oregon DMV 'CDL veya CLP Almak'; Oregon Commercial Driver Manual."},"30":{"q":"Oregon'da, bir kişinin CDL beceri testine girmesine izin verilmeden önce ne kadar süre geçerli bir Ticari Öğrenci İzni (CLP) tutması gerekir?","options":["En az 7 gün","En az 14 gün","En az 30 gün","En az 60 gün"],"explanation":"Oregon, federal zorunlu bekleme süresini yansıtarak, bir başvuru sahibinin CDL beceri testine girmeden önce en az 14 gün geçerli bir CLP tutmasını gerektirir. Kaynak: Oregon Commercial Driver Manual (Oregon Bilgileri); Oregon DMV (49 CFR 383.25)."},"31":{"q":"Bir CDL için çalışırken, ticari bilgi testi puanları Oregon'da ne kadar süre geçerlidir?","options":["Üç ay","Altı ay","Bir yıl","İki yıl"],"explanation":"Oregon, ticari bilgi testi puanlarının altı ay boyunca geçerli olduğunu belirtir; CDL başvurusu bu süre içinde tamamlanmalıdır. Kaynak: Oregon Commercial Driver Manual (Oregon Bilgileri); Oregon DMV 'CDL veya CLP Almak'."},"32":{"q":"Bir CDL veya CLP için başvururken aşağıdakilerden hangisini bir başvuru sahibinin Oregon DMV'ye sunması gerekir?","options":["Yalnızca noter onaylı bir işveren mektubu","Tam yasal ad, kimlik, doğum tarihi, yasal ABD statüsü, ikamet adresi ve bir Sosyal Güvenlik Numarası kanıtı","Yalnızca bir pasaport ve başka hiçbir şey","Bir lise diploması ve iki referans"],"explanation":"Oregon DMV, tam yasal ad, kimlik, doğum tarihi, ABD'de yasal statü, Oregon ikamet adresi ve başvuru sahibinin Sosyal Güvenlik Numarası kanıtını gerektirir. Kaynak: Oregon Commercial Driver Manual (Oregon Bilgileri); Oregon DMV 'CDL veya CLP Almak'."},"33":{"q":"Oregon'da ilk bir Class A veya Class B belgesi için CDL beceri testine girmeden önce, bir başvuru sahibinin Giriş Düzeyi Sürücü Eğitimini (ELDT) nerede tamamlaması gerekir?","options":["Herhangi bir topluluk koleji kursu","FMCSA Eğitim Sağlayıcı Kaydı'nda (Training Provider Registry) listelenen bir sağlayıcı","Bir Oregon DMV saha ofisi","Her türden bir işverenin kurum içi programı"],"explanation":"Oregon, ilk bir Class A/B CDL, bir B'den A'ya yükseltme veya ilk bir P, S veya H onayı için beceri testini planlamadan önce FMCSA'nın Eğitim Sağlayıcı Kaydı'nda (tpr.fmcsa.dot.gov) listelenen bir sağlayıcıdan ELDT alınmasını gerektirir. Kaynak: Oregon Commercial Driver Manual; Oregon DMV (49 CFR Part 380)."},"34":{"q":"Oregon'da ELDT, bunlardan hangi onay için ilk kez teste girmeden önce gereklidir?","options":["Çiftli/Üçlü (T)","Tank (N)","Tehlikeli Maddeler (H)","Onayların hiçbiri ELDT gerektirmez"],"explanation":"Oregon, ilk P veya S onayları ve ilk Class A/B CDL'leri için olduğu gibi, ilk kez HazMat (H) bilgi testine girmeden önce ELDT gerektirir. T ve N onayları ELDT listesinde değildir. Kaynak: Oregon DMV; Oregon Commercial Driver Manual (49 CFR Part 380)."},"35":{"q":"Yalnızca Oregon içinde sürüş yapacak ve federal tıbbi kurallara tabi olmayan bir Oregon CDL başvuru sahibi hangi kategori altında kendini sertifikalandırmalıdır?","options":["İstisnasız Eyaletler Arası (NI)","İstisnalı Eyaletler Arası (EI)","İstisnasız Eyalet İçi (NA)","İstisnalı Eyalet İçi (EA)"],"explanation":"Oregon kendi kendine sertifikalandırma türleri sunar; yalnızca eyalet içi ticarette bir Class A, B veya C CMV kullanan bir sürücü İstisnasız Eyalet İçi olarak sertifikalandırır ve tam federal standartlar yerine Oregon CDL tıbbi standartlarını karşılamalıdır. Kaynak: Oregon DMV CDL Tıbbi/Kendi Kendine Sertifikalandırma; Oregon Commercial Driver Manual."},"36":{"q":"Oregon DMV, çoğu CDL sürücüsü için belgelerinin gereksiz yere yalnızca Oregon kullanımıyla sınırlanmaması için hangi kendi kendine sertifikalandırma kategorisini önerir?","options":["İstisnalı Eyaletler Arası","İstisnasız Eyaletler Arası","İstisnasız Eyalet İçi","İstisnalı Eyalet İçi"],"explanation":"Oregon DMV, çoğu sürücünün, tüm federal tıbbi yeterlilikleri karşılamayı gerektiren ve ayrıca istisnalı eyaletler arası ve eyalet içi operasyona izin veren İstisnasız Eyaletler Arası olarak sertifikalandırmasını önerir. Kaynak: Oregon DMV CDL Kendi Kendine Sertifikalandırma; Oregon Commercial Driver Manual."},"37":{"q":"Bir Oregon HazMat (H) onayı almak ve sürdürmek için, bir sürücü parmak izi alımı dahil olmak üzere bir Transportation Security Administration (TSA) güvenlik tehdit değerlendirmesini geçmelidir; bu ne sıklıkla yenilenmelidir?","options":["Her 2 yılda bir","Her 3 yılda bir","Her 5 yılda bir","Her 8 yılda bir"],"explanation":"Oregon'un HazMat onayı, her beş yılda bir yenilenmesi gereken parmak izi tabanlı bir geçmiş kontrolü içeren bir TSA güvenlik tehdit değerlendirmesi gerektirir. Kaynak: Oregon DMV CDL Onayları ve Kısıtlamaları (49 CFR 1572)."},"38":{"q":"Oregon'da İstisnalı Eyaletler Arası olarak kendi kendine sertifikalandıran bir sürücünün yine de hangi tıbbi standardı karşılaması gerekir?","options":["Hiçbir tıbbi standart yok","Tam federal eyaletler arası tıbbi standartlar","Oregon CDL tıbbi standartları","Yalnızca yenilemede bir görme taraması"],"explanation":"İstisnalı Eyaletler Arası olarak sertifikalandıran bir Oregon sürücüsü yalnızca federal kurallar kapsamında istisna tanınan operasyonlarda (örneğin 49 CFR 390.3(f), 391.2) yer alır ve tam federal tıbbi standartlara tabi tutulmaz, ancak yine de Oregon CDL tıbbi standartlarını karşılamalıdır. Kaynak: Oregon DMV CDL Kendi Kendine Sertifikalandırma; Oregon Commercial Driver Manual."},"39":{"q":"Oregon'da, bir ticari motorlu aracı (CMV) kullanmanın yasadışı olduğu kan alkol konsantrasyonu (BAC) hangi değerde veya üzerindedir?","options":["0.08%","0.04%","0.02%","0.10%"],"explanation":"Oregon federal CMV standardını benimser: bir CMV'yi 0.04% veya daha fazla BAC ile kullanmak yasadışıdır; bu, ticari olmayan sürücüler için olan 0.08% sınırının yarısıdır. Kaynak: Oregon Commercial Driver Manual, Bölüm 1 (Diskalifikasyonlar); 49 CFR 383.51."},"40":{"q":"Oregon'un ticari sürücüler için zımni rıza kuralı kapsamında, bir CMV kullandığınızda ne doğrudur?","options":["Tüm testleri cezasız reddedebilirsiniz","Alkol testine rıza göstermiş sayılırsınız","Test her seferinde ayrı imzalı bir feragatname gerektirir","Rıza yalnızca 0.08% BAC üzerinde geçerlidir"],"explanation":"Oregon CDL Manual, bir CMV kullanarak alkol testine rıza göstermiş sayıldığınızı belirtir. Testi reddetmek, büyük bir suçla aynı diskalifikasyonu taşır. Kaynak: Oregon Commercial Driver Manual, Bölüm 1; ORS 813.100."},"41":{"q":"Bir Oregon CDL sahibi, tehlikeli madde taşımadan, İLK kez 0.04% veya daha yüksek BAC ile bir CMV kullanmaktan mahkum oluyor. Minimum diskalifikasyon süresi nedir?","options":["60 gün","90 gün","1 yıl","3 yıl"],"explanation":"0.04% veya daha yüksek bir CMV BAC dahil ilk büyük suç, Oregon'da sürücüyü en az 1 yıl diskalifiye eder. Kaynak: Oregon Commercial Driver Manual, Bölüm 1; 49 CFR 383.51."},"42":{"q":"İlk bir büyük suç (örneğin 0.04% BAC), sürücü tehlikeli maddeler için plakartlı bir CMV kullanırken meydana gelirse, minimum Oregon diskalifikasyonu nedir?","options":["1 yıl","18 ay","3 yıl","5 yıl"],"explanation":"İlk bir büyük suç, tehlikeli maddeler için plakartlı bir CMV'de meydana geldiğinde, diskalifikasyon en az 3 yıla çıkar. Kaynak: Oregon Commercial Driver Manual, Bölüm 1; 49 CFR 383.51."},"43":{"q":"Bir CDL sahibi tarafından işlenen İKİNCİ bir büyük suç için Oregon diskalifikasyonu nedir?","options":["3 yıl","5 yıl","10 yıl","Ömür boyu"],"explanation":"İkinci bir büyük suç (örneğin bir CMV'de ikinci bir DUI veya önceki bir suçtan sonraki bir büyük suç), Oregon'da ömür boyu CDL diskalifikasyonuyla sonuçlanır. Kaynak: Oregon Commercial Driver Manual, Bölüm 1; 49 CFR 383.51."},"44":{"q":"Bir Oregon CDL sahibi, bir CMV kullanırken alkol testine girmeyi reddediyor (ilk olay). Bu, diskalifikasyon açısından nasıl ele alınır?","options":["CDL cezası yok, yalnızca bir para cezası","Büyük bir suç olarak ele alınır: en az 1 yıl diskalifikasyon","30 gün diskalifikasyon","Ciddi bir ihlal olarak ele alınır: 60 gün"],"explanation":"Alkol testini reddetmek büyük suçlar arasında listelenir ve BAC başarısızlığıyla aynı şekilde en az 1 yıl diskalifikasyon (hazmat için plakartlıysa 3 yıl) taşır. Kaynak: Oregon Commercial Driver Manual, Bölüm 1; 49 CFR 383.51; ORS 813.100."},"45":{"q":"Bir Oregon CDL sahibi, kontrollü bir madde içeren bir suç işlemek için (üretim, dağıtım veya temin) bir CMV kullanıyor. Diskalifikasyon nedir?","options":["1 yıl","3 yıl","10 yıl","Ömür boyu, yeniden verilme olmaksızın"],"explanation":"Kontrollü maddeler içeren bir suç işlemek için bir CMV kullanmak, yeniden verilme imkanı olmaksızın ömür boyu diskalifikasyonla sonuçlanır. Kaynak: Oregon Commercial Driver Manual, Bölüm 1; 49 CFR 383.51."},"46":{"q":"Oregon'da bir CDL sürücüsünün görev başındayken 0.04%'nin ALTINDA tespit edilebilir miktarda alkole sahip olduğu bulunuyor. Ne olur?","options":["Hiçbir şey, yasal sınırın altında","24 saat hizmet dışı bırakılır","1 yıl diskalifikasyon","1 saat hizmet dışı bırakılır"],"explanation":"0.04%'nin altındaki herhangi bir tespit edilebilir alkol, büyük bir suç diskalifikasyonunu tetiklemez ancak sürücüyü 24 saat hizmet dışı bırakır. Kaynak: Oregon Commercial Driver Manual, Bölüm 1; 49 CFR 392.5."},"47":{"q":"Bir Oregon CDL sahibi için aşağıdakilerden hangisi 'ciddi trafik ihlali' olarak sınıflandırılır?","options":["Park yasağı bölgesinde park etmek","Aşırı hız, sınırın 15 mph veya daha fazla üzerinde","Yanmış bir işaret lambası","Sınırın 5 mph üzerinde sürmek"],"explanation":"Ciddi trafik ihlalleri, belirtilen sınırın 15 mph veya daha fazla üzerinde tanımlanan aşırı hız, dikkatsiz sürüş, uygunsuz veya düzensiz şerit değişiklikleri ve çok yakından takip etmeyi içerir. Kaynak: Oregon Commercial Driver Manual, Bölüm 1; 49 CFR 383.51."},"48":{"q":"Oregon'da 3 yıllık bir süre içinde kaç ciddi trafik ihlali bir diskalifikasyonu tetikler ve İLK böyle diskalifikasyon ne kadar sürer?","options":["1 ihlal; 30 gün","2 ihlal; en az 60 gün","2 ihlal; en az 30 gün","3 ihlal; en az 60 gün"],"explanation":"3 yıl içinde iki ciddi trafik ihlali, en az 60 günlük bir diskalifikasyonla sonuçlanır. Kaynak: Oregon Commercial Driver Manual, Bölüm 1; 49 CFR 383.51."},"49":{"q":"Bir Oregon CDL sahibi, 3 yıllık bir süre içinde ÜÇ ciddi trafik ihlali işliyor. Minimum diskalifikasyon nedir?","options":["60 gün","90 gün","120 gün","1 yıl"],"explanation":"3 yıl içinde üç veya daha fazla ciddi trafik ihlali, en az 120 günlük bir diskalifikasyonla sonuçlanır. Kaynak: Oregon Commercial Driver Manual, Bölüm 1; 49 CFR 383.51."},"50":{"q":"Ciddi trafik ihlalleri, sürücünün KİŞİSEL (ticari olmayan) aracında işlendiğinde CDL diskalifikasyonuna sayılır mı?","options":["Hayır, yalnızca bir CMV'deki ihlaller sayılır","Evet, eğer belge askıya alınması veya iptaliyle sonuçlanırsa","Yalnızca alkol söz konusuysa","Yalnızca eyaletler arası karayollarındaki ihlaller sayılır"],"explanation":"Bir CMV olmayan araçta işlenen ciddi trafik ihlalleri, mahkumiyet sürücünün belgesinin askıya alınması veya iptaliyle sonuçlanırsa bir CDL sahibinin aleyhine sayılır. Kaynak: Oregon Commercial Driver Manual, Bölüm 1; 49 CFR 383.51."},"51":{"q":"3 yıl içinde İKİNCİ bir demiryolu-karayolu hemzemin geçiş ihlali için minimum Oregon diskalifikasyonu nedir?","options":["60 gün","120 gün","180 gün","1 yıl"],"explanation":"3 yıllık bir süre içinde ikinci bir demiryolu-karayolu hemzemin geçiş ihlali, en az 120 günlük bir diskalifikasyonla sonuçlanır. Kaynak: Oregon Commercial Driver Manual, Bölüm 1; 49 CFR 383.51."},"52":{"q":"3 yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçiş ihlali için minimum Oregon diskalifikasyonu nedir?","options":["120 gün","180 gün","1 yıl","3 yıl"],"explanation":"3 yıl içinde üçüncü veya sonraki bir demiryolu-karayolu hemzemin geçiş ihlali, en az 1 yıllık bir diskalifikasyonla sonuçlanır. Kaynak: Oregon Commercial Driver Manual, Bölüm 1; 49 CFR 383.51."},"53":{"q":"Bir Oregon CDL sahibi, tehlikeli madde veya yolcu taşımazken İLK kez bir hizmet dışı emrini ihlal ediyor. Minimum diskalifikasyon nedir?","options":["60 gün","90 gün","180 gün","1 yıl"],"explanation":"İlk bir hizmet dışı emri ihlali (hazmat olmayan, yolcu olmayan), en az 180 günlük bir diskalifikasyonla sonuçlanır. Kaynak: Oregon Commercial Driver Manual, Bölüm 1 / ODOT Ticari Sürücü Mahkumiyetleri sayfası; 49 CFR 383.51."},"54":{"q":"Bir sürücü, tehlikeli madde taşırken (veya 16+ yolcu için tasarlanmış bir araç sürerken) İLK kez bir hizmet dışı emrini ihlal ediyor. Minimum Oregon diskalifikasyonu nedir?","options":["180 gün","1 yıl","3 yıl","5 yıl"],"explanation":"Hazmat taşırken veya 16 ya da daha fazla yolculu bir araç kullanırken ilk bir hizmet dışı ihlali, 180 günlük temel süreden daha uzun olarak en az 1 yıllık bir diskalifikasyonla sonuçlanır. Kaynak: ODOT Ticari Sürücü Mahkumiyetleri sayfası; 49 CFR 383.51."},"55":{"q":"Hazmat veya yolcu içermeyen, 10 yıl içinde İKİNCİ bir hizmet dışı emri ihlali için minimum diskalifikasyon nedir?","options":["1 yıl","2 yıl","3 yıl","5 yıl"],"explanation":"10 yıl içinde ikinci bir hizmet dışı ihlali (hazmat olmayan, yolcu olmayan), en az 3 yıllık bir diskalifikasyonla sonuçlanır; hazmat veya yolcu söz konusuysa en az 5 yıla yükselir. Kaynak: ODOT Ticari Sürücü Mahkumiyetleri sayfası; 49 CFR 383.51."},"56":{"q":"Belge diskalifikasyonunun yanı sıra, Oregon/ODOT bir hizmet dışı emrinin İLK ihlali için bir sürücüye hangi hukuki para cezasını uygular?","options":["$650","$1,000","$3,861","$7,723"],"explanation":"ODOT, diskalifikasyona ek olarak, ilk bir hizmet dışı emri ihlali için $3,861 ve ikinci veya sonraki bir ihlal için $7,723 hukuki para cezası uygular. Kaynak: ODOT Ticari Sürücü Mahkumiyetleri sayfası; 49 CFR 383.53."},"57":{"q":"Oregon CDL sürücüleri için geçerli kurallar kapsamında, bir CMV kullanırken cep telefonlarıyla ilgili ne yasaktır?","options":["Tüm telsiz iletişimi yasaktır","Bir çağrı için telefonu elde tutmak, birden fazla düğmeye basarak çevirmek veya mesajlaşmak","Eller serbest arama da yasaktır","Telefonlar her zaman kapalı olmalıdır"],"explanation":"CMV sürücüleri, sürüş sırasında konuşmak için bir cep telefonunu elde tutamaz, tek bir düğmeden fazlasına basarak çeviremez ya da mesaj gönderemez/okuyamaz; bir mesajlaşma/elde tutma ihlali, 60/120 günlük diskalifikasyona sayılan ciddi bir trafik ihlalidir (maksimum federal para cezası $2,750). Kaynak: Oregon Commercial Driver Manual, Bölüm 1; 49 CFR 392.80-392.82, 383.51."},"58":{"q":"Oregon'un Şerit Değiştirme (Move Over) Yasası kapsamında, çok şeritli bir yolda durmuş bir acil durum, çekici, yol kenarı yardım veya uyarı ışıkları yanan tehlike aracına yaklaştığınızda ve güvenli bir şekilde bitişik olmayan bir şeride geçemiyorsanız ne yapmalısınız?","options":["Belirlenen veya işaretli hız sınırının en az 5 mph altına yavaşlayın","Araç gidene kadar tamamen durun","Tam olarak işaretli hız sınırının 10 mph altına yavaşlayın","İşaretli hızı koruyun ama kornanızı çalın"],"explanation":"Oregon'un Şerit Değiştirme (Move Over) Yasası (ORS 811.147), sürücülerin mümkünse bitişik olmayan bir şeride geçmesini gerektirir; bu mümkün değilse, işaretli veya belirlenen hız sınırının en az 5 mph altına yavaşlamaları ve dikkatli bir şekilde ilerlemeleri gerekir. Kaynak: ORS 811.147; Oregon Sürücü El Kitabı."},"59":{"q":"Oregon'un Şerit Değiştirme (Move Over) Yasasının ihlali (durmuş bir acil durum, yol kenarı yardım, çekici aracı veya ambulanstan güvenli mesafeyi koruyamama) hangi tür suç olarak sınıflandırılır?","options":["B Sınıfı bir trafik ihlali","A Sınıfı bir trafik ihlali","C Sınıfı bir hafif suç (misdemeanor)","D Sınıfı bir trafik ihlali"],"explanation":"Oregon'un Şerit Değiştirme (Move Over) Yasası kapsamında bir acil durum, yol kenarı yardım, çekici aracı veya ambulanstan güvenli mesafeyi koruyamamak B Sınıfı bir trafik ihlalidir. Kaynak: ORS 811.147."},"60":{"q":"Oregon'da, çift yönlü bir caddede bir okul otobüsü kırmızı ışıkları yanıp sönerek durduğunda, yaklaşan bir sürücü ne kadar geriden durmalıdır?","options":["Otobüsten 20 fit veya daha fazla geriden","Otobüsten 10 fit veya daha fazla geriden","Otobüsten 30 fit veya daha fazla geriden","Otobüsten 50 fit veya daha fazla geriden"],"explanation":"Oregon, sürücülerin yanıp sönen kırmızı uyarı ışıkları gösteren bir okul otobüsünden 20 fit veya daha fazla geriden durmasını ve ışıklar sönene kadar durmuş halde kalmasını gerektirir. Kaynak: ORS 811.155; Oregon Sürücü El Kitabı."},"61":{"q":"Oregon yasalarına göre, karşıdan gelen bir sürücünün yanıp sönen kırmızı ışıklar gösteren bir okul otobüsü için durmasının gerekMEDİĞİ TEK durum hangisidir?","options":["Otobüs, fiziksel bir orta refüj veya bariyerle ayrılmış farklı bir yolda durmuştur","Otobüs 25 mph hızlı bir yerleşim bölgesinde durmuştur","Sürücü ile otobüs arasında çift yönlü bir orta sola dönüş şeridi bulunmaktadır","Yol, kesintisiz sarı bir orta çizgi ile boyanmıştır"],"explanation":"Oregon'da bir sürücünün durmasına gerek olmayan tek durum, kırmızı ışıklar gösteren otobüsün farklı bir yolda olması, yani karayolunun fiziksel bir orta refüj veya bariyerle ayrı yollara bölünmüş olmasıdır. Boyalı bir sarı çizgi veya orta dönüş şeridi ayrı yollar oluşturmaz, bu nedenle tüm şeritler durmalıdır. Kaynak: ORS 811.155; Oregon Sürücü El Kitabı."},"62":{"q":"Oregon'da bir okul otobüsünün yanıp sönen kırmızı güvenlik ışıkları için durmamak hangi düzeyde bir trafik suçudur?","options":["A Sınıfı bir trafik ihlali","B Sınıfı bir trafik ihlali","C Sınıfı bir trafik ihlali","A Sınıfı bir hafif suç (misdemeanor)"],"explanation":"ORS 811.155 kapsamında otobüs güvenlik ışıkları için durmamak, Oregon'un en ciddi trafik ihlali sınıfı olan A Sınıfı bir trafik ihlalidir. Kaynak: ORS 811.155."},"63":{"q":"Bir Oregon CDL sürücüsü, plakart taşıyan bir tehlikeli madde (hazmat) aracında bir demiryolu geçidinde durması gerektiğinde (ve işaretli bir durma çizgisi yoksa), araç nerede durmalıdır?","options":["En yakın raydan 15 fitten az ve 50 fitten fazla olmamak üzere","En yakın raydan 10 fitten az ve 25 fitten fazla olmamak üzere","En yakın raydan 5 fitten az ve 15 fitten fazla olmamak üzere","En yakın raydan 50 fitten az ve 100 fitten fazla olmamak üzere"],"explanation":"Plakart taşıyan bir hazmat aracının, klor yükünün veya bir hazmat kargo tankının (dolu veya boş) sürücüsü, durma çizgisi olmadığında en yakın raydan 15 fitten az ve 50 fitten fazla olmamak üzere durmalıdır. Kaynak: Oregon Ticari Sürücü El Kitabı Bölüm 9; ORS 811.460."},"64":{"q":"Oregon'da plakart taşıyan bir hazmat aracında demiryolu raylarını geçerken, kural özellikle neyi yasaklar?","options":["Raylar üzerindeyken manuel olarak vites değiştirmeyi","Raylar üzerindeyken motor frenini kullanmayı","Raylar üzerindeyken dörtlü flaşörleri açmayı","Raylar üzerindeyken korna çalmayı"],"explanation":"Oregon'un yüksek riskli geçit kuralı, sürücünün manuel olarak vites değiştirmeyi gerektirmeyen bir viteste geçmesini gerektirir, bu nedenle raylar üzerindeyken vites değiştirmemelisiniz; yalnızca durmadan rayları geçebileceğinizden emin olduğunuzda ilerleyin. Kaynak: ORS 811.460; Oregon Ticari Sürücü El Kitabı Bölüm 9."},"65":{"q":"Aşağıdaki araçlardan hangisi, Oregon yasalarının her demiryolu geçidinde durmasını gerektirdiği 'yüksek riskli' araçlar arasında DEĞİLDİR?","options":["Sıradan yük taşıyan boş bir açık platform (flatbed) kamyon","Bir okul otobüsü","Tehlikeli madde taşıyan dolu veya boş bir kargo tankı","Yolcu taşıyan ticari bir otobüs"],"explanation":"ORS 811.460, geçitlerde durması gereken yüksek riskli araçları listeler: okul otobüsleri, belirli okul etkinliği ve işçi taşıma otobüsleri, ticari otobüsler, patlayıcı/yanıcı/aşındırıcı madde taşıyan araçlar ve hazmat tank araçları (dolu veya boş). Tehlikesiz kargo taşıyan sıradan bir yük kamyonu, sinyaller gerektirmedikçe durmak zorunda değildir. Kaynak: ORS 811.460."},"66":{"q":"Oregon'da, farklı bir hız belirtilmedikçe 10,000 pound GVWR üzeri ticari bir araç için standart maksimum hız sınırı nedir?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"Farklı bir hız belirtilmedikçe, 10,000 lbs GVWR üzeri ticari araçlar (veya 8,000 lbs GVWR üzeri çekici kamyonlar) için varsayılan maksimum hız 55 mph'dir. Kaynak: ORS 811.111; ORS 810.180."},"67":{"q":"Oregon kuralına göre, Ulaştırma Departmanının bir eyaletler arası karayolunda ticari araçlar için belirleyebileceği en yüksek hız nedir:","options":["65 mph","70 mph","60 mph","75 mph"],"explanation":"ODOT, belirlenen eyaletler arası karayolu hızlarını ayarlayabilir ancak ticari araçlar için 65 mph'yi aşamaz (diğer araçlar için üst sınır 70 mph'dir). Bazı Oregon eyaletler arası karayolu bölümlerinde kamyonlar için hız, otomobillerin 65 ile gittiği yerlerde 60 mph'ye yükseltilmiştir. Kaynak: ORS 810.180; OAR 734-020-0010."},"68":{"q":"Aynı yönde iki veya daha fazla şeridi olan bir Oregon yolunda, geçiş veya dönüş dışında sağ şeritte sürmesi gereken araçlar hangileridir?","options":["Karavanlar, römork çeken araçlar ve 10,000 pound veya daha fazla tescil ağırlığı olan araçlar","Yalnızca üç veya daha fazla aksı olan araçlar","Yalnızca hazmat plakartı gösteren araçlar","45 mph'nin altında seyreden tüm araçlar"],"explanation":"ORS 811.325, herhangi bir karavanın, römorklu herhangi bir aracın ve 10,000 lbs veya daha fazla tescil ağırlığı olan herhangi bir aracın çok şeritli tek yönlü yollarda sağ şeridi kullanmasını gerektirir; geçiş yapma, sola dönme, acil duruma müdahale etme, katılan trafikten kaçınma veya trafik kontrol cihazlarının yönlendirmesi durumları hariç. Kaynak: ORS 811.325."},"69":{"q":"Bir Oregon çok şeritli karayolunda bir karavanı, römorku veya kamyonu (10,000 lbs ve üzeri) sağ şeritte tutmamak ne tür bir suçtur?","options":["B Sınıfı bir trafik ihlali","A Sınıfı bir trafik ihlali","C Sınıfı bir trafik ihlali","D Sınıfı bir trafik ihlali"],"explanation":"ORS 811.325'in sağ şerit gerekliliğini ihlal etmek B Sınıfı bir trafik ihlalidir. Kaynak: ORS 811.325."},"70":{"q":"Bir Oregon kamyonunun (10,000 lbs ve üzeri) çok şeritli bir karayolunda sağ şeritten ayrılmasına izin veren, kabul edilmiş yasal bir istisna hangisidir?","options":["Aynı yönde giden başka bir aracı geçmek ve sollamak","Daha hızlı bir seyir hızını korumak istemek","Önündeki araçtan daha uzun bir takip mesafesi tutmak","Sağ şerit kaplamasındaki aşınmayı önlemek"],"explanation":"ORS 811.325, sağ şeritten ayrılmaya yasal olarak sollama ve geçiş yapmak için, sola dönüşe hazırlanmak için, acil durumlara müdahale etmek için, katılma/hızlanma şeritlerinden giren trafikten kaçınmak için veya trafik kontrol cihazlarının yönlendirmesiyle izin verir. Kaynak: ORS 811.325."},"71":{"q":"Oregon'da bölünmüş veya tek yönlü bir karayolunda, bir CDL sürücüsü yolda durduğunda üç acil durum uyarı üçgenini nereye yerleştirmelidir?","options":["Arkaya 10 fit içinde ve yaklaşan trafiğe doğru 100 fit ve 200 fitte","Arkaya 25 fit içinde ve yaklaşan trafiğe doğru 50 fit ve 150 fitte","Öne 10 fit içinde ve yaklaşan trafiğe doğru 100 fit ve 300 fitte","Arkaya 50 fit içinde ve yaklaşan trafiğe doğru 100 fit ve 250 fitte"],"explanation":"Tek yönlü veya bölünmüş bir karayolunda, bir uyarı cihazını arkaya 10 fit içinde yaklaşan trafiğe doğru, birini yaklaşık 100 fit geride ve birini yaklaşık 200 fit geride yerleştirin. Bu federal standart (49 CFR 392.22) Oregon Ticari Sürücü El Kitabı'nda öğretilir. Kaynak: Oregon Ticari Sürücü El Kitabı; 49 CFR 392.22."},"72":{"q":"İki şeritli, çift yönlü bir Oregon yolunda, bir CDL aracı seyir bölümünde durduktan sonra, sürücünün acil durum uyarı cihazlarını kaç dakika içinde yerleştirmiş olması gerekir?","options":["10 dakika içinde","5 dakika içinde","15 dakika içinde","30 dakika içinde"],"explanation":"Bir CDL sürücüsü, bir yolun seyir bölümünde veya banketinde durduktan sonra uyarı cihazlarını (üç üçgen veya eşdeğeri) 10 dakika içinde yerleştirmelidir. Kaynak: Oregon Ticari Sürücü El Kitabı; 49 CFR 392.22."},"73":{"q":"Oregon'da, bir boyut aşımı izni gerekmeden önce yasal maksimum araç/yük GENİŞLİĞİ nedir?","options":["8 fit 6 inç","8 fit 0 inç","9 fit 0 inç","10 fit 0 inç"],"explanation":"Oregon'un yasal maksimum genişliği 8 fit 6 inçtir; bunu aşan yükler ODOT'un Ticaret ve Uyum Bölümünden (Commerce and Compliance Division) bir boyut aşımı izni gerektirir. Kaynak: ORS 818.080; ODOT Yasal Araç Boyutları."},"74":{"q":"Bir boyut aşımı izni gerekmeden önce Oregon'un yasal maksimum araç YÜKSEKLİĞİ nedir?","options":["14 fit 0 inç","13 fit 6 inç","13 fit 0 inç","15 fit 0 inç"],"explanation":"Oregon'un yasal maksimum yüksekliği 14 fit 0 inçtir; bunu aşan yükler bir boyut aşımı izni gerektirir. (Diğer birçok eyaletin 13'6\" kullandığını unutmayın.) Kaynak: ORS 818.080; ODOT Yasal Araç Boyutları."},"75":{"q":"Oregon, kar mevsiminde 10,000 lbs GVW üzeri tüm araçların lastik zinciri taşımasını gerektirir:","options":["Kullanımlarının gerekebileceği veya zorunlu olabileceği koşulların var olduğu her zaman","Yalnızca Cascades'in doğusunda seyahat ederken","Yalnızca Aralık'tan Şubat'a kadar hafta sonları","Yalnızca araçta saplamalı lastik yoksa"],"explanation":"Oregon yasası, 10,000 lbs GVW üzeri araçların zincirlerin gerekebileceği veya zorunlu olabileceği koşulların var olduğu her zaman zincir taşımasını ve zincir yasası yürürlükteyken (genellikle dağ geçitlerinde Ekim'den Mart'a kadar) takmasını gerektirir. Kaynak: ODOT Ticaret ve Uyum Bölümü, Zincirler ve Çekiş Lastikleri."},"76":{"q":"Saplamalı lastiklerin Oregon yollarında kullanımı hangi dönemde yasaldır?","options":["1 Kasım'dan 31 Mart'a kadar","1 Ekim'den 30 Nisan'a kadar","15 Kasım'dan 15 Nisan'a kadar","1 Aralık'tan 1 Mart'a kadar"],"explanation":"Saplamalı lastikler Oregon'da yalnızca 1 Kasım'dan 31 Mart'a kadar yasaldır; bu pencerenin dışında kullanmak para cezasına yol açabilir. Kaynak: ODOT / Oregon TripCheck; ORS saplamalı lastik hükümleri."},"77":{"q":"Oregon, dik bir Interstate 5 yokuşunda erken bir kontrolden çıkan kamyon kaçış özelliği ile dikkat çeker. Ülkenin ilk negatif eğimli (yokuş aşağı) kamyon durdurma yatağı nerede inşa edildi ve test edildi?","options":["Güney Oregon'da I-5 üzerindeki Siskiyou Summit yakınında","I-84'ün Cabbage Hill yokuşunda","Mount Hood üzerinden US 26'da Government Camp'te","US 20'nin Santiam Pass'inde"],"explanation":"Amerika Birleşik Devletleri'ndeki ilk negatif eğimli (yokuş aşağı) kamyon durdurma yatağı, 1977 yılında güney Oregon'da Siskiyou Summit yakınında I-5 boyunca, kaçış rampası kullanımının vurgulandığı belirgin şekilde dik bir dağ yokuşunda inşa edildi ve test edildi. Kaynak: ODOT; Oregon Ticari Sürücü El Kitabı dağ sürüşü rehberi."},"78":{"q":"Oregon'da hangi eyalet kurumu Ticari Sürücü Belgesi (CDL) verir ve test sürecini yönetir?","options":["Oregon Ulaştırma Departmanının (ODOT) Sürücü ve Motorlu Araç Hizmetleri'nin bir parçası olan Oregon DMV","Oregon Eyalet Polisi Ticari Araç Bölümü","Federal Motorlu Taşıyıcı Güvenlik İdaresi'nin (FMCSA) bölge ofisi","Oregon Eyalet Sekreteri, Şirketler ve Lisanslama Bölümü"],"explanation":"Oregon CDL'leri, Oregon Ulaştırma Departmanının (ODOT) Sürücü ve Motorlu Araç Hizmetleri'nin bir parçası olan Oregon DMV tarafından verilir. Kaynak: Oregon DMV 'CDL veya CLP Edinme' sayfası; Oregon Ticari Sürücü El Kitabı."},"79":{"q":"Bir araç, brüt araç ağırlık derecesi (GVWR) en az kaç pound olduğunda ağırlığa dayalı olarak bir Oregon CDL gerektirir?","options":["26,001 pound","10,001 pound","18,000 pound","33,000 pound"],"explanation":"Oregon, 26,001 pound veya daha fazla GVWR'ye sahip bir aracı kullanmak için bir CDL gerektirir (ve çekilen ünitenin 10,000 lbs üzerinde olduğu kombinasyonlar için). Kaynak: Oregon Ticari Sürücü El Kitabı, Bölüm 1."},"80":{"q":"Ağırlık dışında, hangi yolcu eşiği bir aracın Oregon CDL gerektirmesine neden olur?","options":["Sürücü dahil 16 veya daha fazla kişi taşımak için tasarlanmış","Sürücü dahil 9 veya daha fazla kişi taşımak için tasarlanmış","Sürücü hariç 24 veya daha fazla kişi taşımak için tasarlanmış","Sürücü dahil 12 veya daha fazla kişi taşımak için tasarlanmış"],"explanation":"Sürücü dahil 16 veya daha fazla kişi taşımak için tasarlanmış bir araç için bir CDL gereklidir. Üçüncü tetikleyici, plakart gerektiren tehlikeli madde taşımaktır. Kaynak: Oregon Ticari Sürücü El Kitabı, Bölüm 1; Oregon'da uygulandığı şekliyle 49 CFR 383.5."},"81":{"q":"Bir Oregon CDL veya ticari öğrenci iznine başvururken, başvuru sahibi hangi tür ticarette faaliyet göstereceğini 'öz beyan' (self-certify) etmelidir. Oregon hangi kategori setini sunar?","options":["İstisnasız Eyaletlerarası, İstisnalı Eyaletlerarası ve İstisnasız Eyaletiçi (Non-excepted Interstate, Excepted Interstate ve Non-excepted Intrastate)","Eyaletlerarası Hazmat, Eyaletiçi Hazmat ve Yalnızca Hazmat Olmayan","Federal Taşıyıcı, Eyalet Taşıyıcısı ve Özel Taşıyıcı","A Sınıfı, B Sınıfı ve C Sınıfı operasyon"],"explanation":"Oregon DMV üç öz beyan kategorisi sunar: İstisnasız Eyaletlerarası (Non-excepted Interstate), İstisnalı Eyaletlerarası (Excepted Interstate) ve İstisnasız Eyaletiçi (Non-excepted Intrastate). (İstisnalı Eyaletiçi, dördüncü FMCSA kategorisidir; Oregon bunu ayrıca listelemez.) Kaynak: Oregon DMV CDL başvurusu/öz beyanı; 49 CFR 383.71."},"82":{"q":"'İstisnasız Eyaletlerarası' (Non-excepted Interstate) olarak öz beyanda bulunan bir Oregon CDL başvuru sahibinin tıbbi yeterlilik konusunda ne yapması gerekir?","options":["DMV'ye geçerli bir DOT tıbbi muayene sertifikasının bir kopyasını sunmak ve dosyada güncel bir tane bulundurmak","Kağıt tıbbi kartı kamyonda taşımak ama asla DMV'ye vermemek","Tıbbi muayene gerekmediğine dair noter onaylı bir beyan sunmak","DMV tarafından uygulanan ek bir fiziksel uygunluk yol testini geçmek"],"explanation":"İstisnasız bir eyaletlerarası sürücü, Oregon DMV'ye geçerli bir tıbbi muayene sertifikasının (DOT tıbbi kartı) bir kopyasını sunmalı ve dosyada güncel bir tane bulundurmaktan sorumludur, aksi takdirde CDL düşürülür. Kaynak: Oregon DMV CDL tıbbi belgelendirmesi; 49 CFR 383.71/391.45."},"83":{"q":"Bir Oregon CDL için kullanılan tıbbi muayene sertifikasını üreten DOT fiziksel muayenesini yapmaya kim yetkilidir?","options":["FMCSA Ulusal Sertifikalı Tıbbi Muayene Uzmanları Kayıt Defterinde (National Registry of Certified Medical Examiners) listelenen bir tıbbi muayene uzmanı","Oregon'da ruhsatlı herhangi bir eczacı","Bir Oregon DMV saha ofisi muayene görevlisi","Herhangi bir ABD eyaletinde ruhsatlı olduğu sürece herhangi bir hekim"],"explanation":"DOT tıbbi muayenesi, FMCSA Ulusal Sertifikalı Tıbbi Muayene Uzmanları Kayıt Defterinde listelenen bir tıbbi muayene uzmanı tarafından yapılmalıdır. Kaynak: Oregon DMV 'CDL veya CLP Edinme'; 49 CFR 390.103."},"84":{"q":"Bir başvuru sahibi Oregon'da CDL beceri testine girmeden önce, ilk olarak hangi belgeyi edinmelidir?","options":["Bir Ticari Öğrenci İzni (CLP)","C Sınıfı geçici bir CDL","Federal bir eyaletlerarası işletme yetkisi (MC numarası)","Geçici bir hizmet dışı muafiyeti"],"explanation":"Beceri testi gerektiren başvuru sahipleri, önce gerekli bilgi test(ler)ini geçerek bir Ticari Öğrenci İzni (CLP) edinmelidir. Kaynak: Oregon DMV CDL süreci; OAR 735-063-0250 / 735-063-0260."},"85":{"q":"Bir Oregon A Sınıfı Ticari Öğrenci İzni edinmek için, başvuru sahibi hangi bilgi testlerini geçmelidir?","options":["Genel Bilgi testi ve Kombinasyon Araçları testi (ayrıca uygulanabilirse Hava Frenleri)","Yalnızca Genel Bilgi testi","Genel Bilgi testi ve Tehlikeli Maddeler testi","Yalnızca Kombinasyon Araçları testi"],"explanation":"Bir A Sınıfı CLP, Genel Bilgi testi ve Kombinasyon Araçları testinin geçilmesini gerektirir, ayrıca araçta hava freni varsa Hava Frenleri testini de gerektirir. Kaynak: OAR 735-063-0250; Oregon Ticari Sürücü El Kitabı."},"86":{"q":"Oregon CDL bilgi testlerinde geçer minimum puan nedir?","options":["Yüzde 80 doğru","Yüzde 70 doğru","Yüzde 90 doğru","Yüzde 75 doğru"],"explanation":"Her Oregon CDL bilgi testini geçmek için en az yüzde 80 doğru bir puan gereklidir (örneğin, Genel Bilgi testinde 50 sorudan 40'ı). Kaynak: Oregon Ticari Sürücü El Kitabı / Oregon DMV; 49 CFR 383.135."},"87":{"q":"Oregon CDL beceri testi, belirli bir sırayla yapılması gereken üç bölümden oluşur. Bu sıra nedir?","options":["Yolculuk öncesi araç muayenesi, ardından temel kontrol becerileri, ardından yolda sürüş","Yolda sürüş, ardından yolculuk öncesi muayene, ardından temel kontrol becerileri","Temel kontrol becerileri, ardından yolda sürüş, ardından yolculuk öncesi muayene","Yolculuk öncesi muayene, ardından yolda sürüş, ardından temel kontrol becerileri"],"explanation":"Beceri testi şu sırayla uygulanır: önce yolculuk öncesi araç muayenesi, ardından temel kontrol becerileri, ardından yolda sürüş; bir sonrakine geçmeden önce her bölüm geçilmelidir. Kaynak: OAR 735-063-0260 / OAR 735-060-0120."},"88":{"q":"Federal Giriş Düzeyi Sürücü Eğitimi (ELDT), Oregon'da aşağıdakilerden hangisi için test öncesinde tamamlanmalıdır?","options":["İlk kez A veya B Sınıfı CDL edinme, B Sınıfını A'ya yükseltme veya ilk kez yolcu/okul otobüsü/hazmat onayları (endorsement)","Sınıfa bakılmaksızın her CDL yenilemesi","Yalnızca 21 yaşın altındaki sürücüler için","Yalnızca bir double/triple onayı eklerken"],"explanation":"ELDT, ilk kez A veya B Sınıfı CDL, bir B Sınıfını A Sınıfına yükseltmek veya ilk kez bir yolcu, okul otobüsü ya da tehlikeli madde onayı (endorsement) almak için test öncesinde gereklidir. Kaynak: Oregon DMV; 49 CFR Bölüm 380 Alt Bölüm F."},"89":{"q":"Bir Oregon CDL için Giriş Düzeyi Sürücü Eğitimi (ELDT), nerede listelenen bir kuruluş tarafından sağlanmalıdır?","options":["FMCSA Eğitim Sağlayıcı Kayıt Defterinde (Training Provider Registry - TPR)","Oregon DMV'nin onaylı liseler listesinde","Oregon Kamyonculuk Dernekleri üye listesinde","ABD Çalışma Bakanlığı çıraklık ofisinde"],"explanation":"ELDT eğitimi, bir beceri testi planlamadan veya hazmat bilgi testine girmeden önce FMCSA Eğitim Sağlayıcı Kayıt Defterinde (TPR) bulunan bir okul veya kuruluş aracılığıyla tamamlanmalıdır. Kaynak: Oregon DMV; FMCSA Eğitim Sağlayıcı Kayıt Defteri."},"90":{"q":"Bir Oregon Ticari Öğrenci İzni, sahibinin CDL beceri testine girebilmesi için ne kadar süre tutulmalıdır?","options":["En az 14 gün","En az 30 gün","En az 7 gün","En az 60 gün"],"explanation":"Oregon DMV, süresi dolmamış CLP'yi beceri testinden en az 14 gün önce vermiş olmalıdır. Kaynak: OAR 735-063-0260."},"91":{"q":"Bir Oregon Ticari Öğrenci İzni (CLP) ne kadar süre geçerlidir ve yenilenebilir mi?","options":["Bir yıl geçerlidir ve yenilenemez","180 gün geçerlidir ve bir kez yenilenebilir","İki yıl geçerlidir ve yıllık olarak yenilenebilir","90 gün geçerlidir ve yenilenemez"],"explanation":"Bir Oregon CLP, verildiği tarihten itibaren bir yıl geçerlidir ve yenilenemez. Kaynak: ORS 807.285."},"92":{"q":"Oregon CDL bilgi testlerindeki (ve tamamlanmış bir beceri testindeki) geçer puan, CDL verilmeden önce ne kadar süre geçerli kalır?","options":["Altı ay","Üç ay","Bir yıl","Otuz gün"],"explanation":"Geçer bir bilgi testi puanı altı ay geçerlidir ve tamamlanmış bir CDL beceri testi için geçer bir puan altı ay geçerlidir. Kaynak: OAR 735-063-0250 ve OAR 735-063-0260."},"93":{"q":"Verildikten sonra, bir Oregon CDL yenilenmesi gerekmeden önce ne kadar süre geçerlidir?","options":["8 yıl","4 yıl","5 yıl","10 yıl"],"explanation":"Bir ABD vatandaşına veya daimi ikamet eden kişiye verilen bir Oregon CDL, normal bir Oregon sürücü belgesi ile aynı standart döngü olan 8 yıl geçerlidir. Kaynak: Oregon DMV; ORS Bölüm 807."},"94":{"q":"Son kullanma tarihine göre Oregon CDL yenileme penceresi nedir?","options":["Son kullanma tarihinden 12 ay öncesine kadar ve son kullanma tarihinden 2 yıl sonrasına kadar","Yalnızca son kullanma tarihinde veya sonrasında, erken yenileme olmaksızın","Son kullanma tarihinden 30 gün öncesine ve 30 gün sonrasına kadar","Yalnızca son kullanma tarihinden 6 ay öncesine kadar"],"explanation":"Bir Oregon CDL, süresi dolmadan 12 aya kadar ve süresi dolduktan sonra 2 yıla kadar yenilenebilir; bunun ötesinde, sürücü yeni bir lisans için başvurmalıdır. Kaynak: Oregon DMV 'Ticari Sürücü Belgesi Yenileme'."},"95":{"q":"Bir Oregon CDL/CLP başvuru sahibi, başvuruda uygunluğu kanıtlamak için hangi belgeleri sunmalıdır?","options":["Tam yasal isim, ABD vatandaşlığı veya yasal daimi ikamet, kimlik, doğum tarihi, ikamet adresi ve Sosyal Güvenlik Numarası kanıtı","Yalnızca güncel bir pasaport fotoğrafı ve bir kredi kartı","Noter onaylı bir işveren mektubu ve bir araç tapusu","Üç yıllık ticari sürüş deneyimi kanıtı"],"explanation":"Başvuru sahipleri, tam yasal isim, ABD vatandaşlığı veya yasal daimi ikamet, kimlik, doğum tarihi ve ikamet adresi kanıtının yanı sıra Sosyal Güvenlik Numaralarını sunmalıdır. Kaynak: Oregon DMV 'CDL veya CLP Edinme'; OAR 735-063-0250."},"96":{"q":"Tehlikeli Maddeler onayı (endorsement) taşıyan bir Oregon CDL'sini yenilerken, hangi ek gereklilik geçerlidir?","options":["HazMat bilgi testini geçmek ve güncel bir TSA güvenlik geçmiş kontrolüne (tehdit değerlendirmesi) sahip olmak","Son kayıtlı göndericiden noter onaylı bir mektup sunmak","Geçmiş incelemesi sırasında CDL'yi 30 gün boyunca teslim etmek","Plakart taşıyan bir araçta ikinci bir yolda beceri testini geçmek"],"explanation":"HazMat onayı (endorsement) olan bir CDL'yi yenilemek, HazMat bilgi testini geçmeyi ve güncel bir TSA güvenlik tehdit değerlendirmesine (geçmiş kontrolü) sahip olmayı gerektirir. Kaynak: Oregon DMV 'CDL Yenileme'; 49 CFR Bölüm 1572."},"97":{"q":"Bir Oregon CDL sahibi, gerekli bir tıbbi muayene sertifikasının (istisnasız bir öz beyan için) süresinin dolmasına izin verirse, Oregon DMV ne yapar?","options":["CDL'yi düşürür, geçerli bir tıbbi sertifika dosyada olana kadar ticari sürüş ayrıcalıklarını kaldırır","Normal (C Sınıfı) sürüş ayrıcalıklarını da askıya alır","Hiçbir işlem gerekmeden otomatik bir 90 günlük tıbbi muafiyet verir","Sürücüyü ceza için Oregon Eyalet Polisine sevk eder"],"explanation":"İstisnasız bir sürücünün tıbbi sertifikasının süresi dolar ve dosyada güncel bir tane yoksa, Oregon DMV CDL'yi düşürür, geçerli bir sertifika sunulana kadar ticari ayrıcalıkları kaldırır; normal lisans kalır. Kaynak: Oregon DMV CDL tıbbi belgelendirmesi; 49 CFR 383.73."}},"es":{"0":{"q":"¿Cuál es el ancho máximo legal para la mayoría de los vehículos comerciales en las carreteras de Oregón sin un permiso de sobredimensión?","options":["8 pies (96 pulgadas)","8 pies 6 pulgadas (102 pulgadas)","9 pies (108 pulgadas)","10 pies (120 pulgadas)"],"explanation":"Oregón limita el ancho exterior total del vehículo a 8 pies 6 pulgadas (102 pulgadas) en las carreteras públicas; cualquier cosa más ancha requiere un permiso de sobredimensión. Fuente: ORS 818.080 (Límites máximos de tamaño) y Oregon DOT Commerce and Compliance Division, Legal Vehicle Dimensions."},"1":{"q":"¿Cuál es la altura máxima legal, incluyendo la carga, para un vehículo que circula por las carreteras de Oregón sin un permiso?","options":["13 pies 6 pulgadas","14 pies","14 pies 6 pulgadas","15 pies"],"explanation":"Oregón fija la altura máxima, incluyendo cualquier carga, en 14 pies; superar esto requiere un permiso de sobredimensión y la autorización de la ruta. Fuente: ORS 818.080 y Oregon DOT Legal Vehicle Dimensions."},"2":{"q":"Sin un permiso especial de longitud, ¿cuál es la longitud total máxima de la mayoría de las combinaciones de camión tractor y semirremolque en las carreteras generales de Oregón?","options":["50 pies","55 pies","60 pies","75 pies"],"explanation":"En las carreteras generales de Oregón, la longitud total máxima para una combinación de vehículos es de 60 pies; las combinaciones más largas solo se permiten en rutas designadas o con permiso. Fuente: ORS 818.080 y Oregon DOT Legal Vehicle Dimensions."},"3":{"q":"En las rutas designadas de Oregón que permiten una longitud total ilimitada, ¿cuál es la longitud máxima de un solo semirremolque en una combinación de tractor y semirremolque?","options":["48 pies","53 pies","57 pies","60 pies"],"explanation":"Oregón permite una longitud máxima de semirremolque de 53 pies; en rutas designadas la longitud total de la combinación puede ser ilimitada, pero el semirremolque en sí no puede exceder los 53 pies. Fuente: ORS 818.080 y Oregon DOT Legal Vehicle Dimensions."},"4":{"q":"¿Cuál es la longitud máxima de un vehículo individual (solo) en las carreteras de Oregón sin un permiso?","options":["35 pies","40 pies","45 pies","53 pies"],"explanation":"Un vehículo individual que circula solo en Oregón no puede exceder los 40 pies de longitud sin un permiso. Fuente: ORS 818.080 (Límites máximos de tamaño)."},"5":{"q":"En Oregón, ¿cuál es el peso máximo permitido en un solo eje sin un permiso de sobrepeso?","options":["18,000 libras","20,000 libras","22,400 libras","34,000 libras"],"explanation":"Oregón limita cualquier eje individual a 20,000 libras. Fuente: ORS 818.010 (Peso máximo permitido)."},"6":{"q":"¿Cuál es el peso máximo permitido en un grupo de ejes tándem en Oregón sin un permiso de sobrepeso?","options":["32,000 libras","34,000 libras","36,000 libras","40,000 libras"],"explanation":"Oregón limita un eje tándem (dos ejes) a 34,000 libras, igualando el estándar federal. Fuente: ORS 818.010 (Peso máximo permitido)."},"7":{"q":"¿Cuál es el peso bruto vehicular máximo generalmente permitido en las carreteras de Oregón sin un permiso de sobrepeso o de peso extendido?","options":["73,280 libras","80,000 libras","88,000 libras","105,500 libras"],"explanation":"El peso bruto combinado máximo estándar en Oregón es de 80,000 libras; las cargas divisibles más pesadas requieren un permiso de peso extendido de ODOT. Fuente: ORS 818.010 y Oregon DOT Commerce and Compliance Division."},"8":{"q":"Bajo un permiso de peso extendido (carga divisible) de ODOT, ¿cuál es el peso bruto combinado máximo que un vehículo que califica puede transportar en Oregón?","options":["90,000 libras","98,000 libras","105,500 libras","129,000 libras"],"explanation":"El permiso de peso extendido de Oregón permite que las combinaciones de múltiples ejes que califican operen hasta 105,500 libras de peso bruto al transportar cargas divisibles. Fuente: Oregon DOT Commerce and Compliance Division, Extended Weight (Divisible Load) Permit."},"9":{"q":"La ley de Oregón limita la carga que se puede llevar sobre los neumáticos según el ancho del neumático. ¿Cuál es el máximo de libras por pulgada de ancho de neumático permitido?","options":["500 libras por pulgada","550 libras por pulgada","600 libras por pulgada","650 libras por pulgada"],"explanation":"Oregón usa la clasificación del fabricante en la pared lateral del neumático, pero sin exceder 600 libras por pulgada de ancho de neumático, multiplicado por la suma de los anchos de los neumáticos. Fuente: ORS 818.010 (Peso máximo permitido)."},"10":{"q":"¿Qué fórmula aplica Oregón para determinar el peso bruto máximo permitido en un grupo de ejes consecutivos según su espaciamiento?","options":["La Fórmula Federal de Puentes (Bridge Gross Weight Formula)","La fórmula de clasificación GAWR","La fórmula del impuesto por millaje de Oregón","La Fórmula de Aseguramiento de Carga"],"explanation":"Oregón adopta la Fórmula Federal de Puentes, W = 500[LN/(N-1) + 12N + 36], para limitar el peso en cualquier grupo de dos o más ejes consecutivos según el espaciamiento de los ejes y el número de ejes. Fuente: ORS 818.010 y 23 CFR 658 según lo aplica Oregon DOT."},"11":{"q":"En la Fórmula Federal de Puentes utilizada en Oregón, ¿qué representa la variable 'L'?","options":["El límite legal de carga en toneladas","La distancia en pies entre los ejes exteriores del grupo","La longitud del remolque en pies","El número de placas de matrícula requeridas"],"explanation":"En la fórmula de puentes W = 500[LN/(N-1) + 12N + 36], L es la distancia en pies entre los ejes más externos del grupo, N es el número de ejes y W es el peso bruto permitido. Fuente: Fórmula Federal de Puentes según lo aplica Oregon DOT; ORS 818.010."},"12":{"q":"¿Cuándo se requiere un permiso de sobredimensión o sobrepeso de Oregon DOT para un vehículo comercial?","options":["Solo al cruzar la línea estatal","Siempre que el vehículo o la carga exceda los límites legales de tamaño o peso","Solo los fines de semana y días festivos","Solo para vehículos registrados fuera del estado"],"explanation":"Cualquier vehículo o carga que exceda los límites legales de Oregón en ancho, altura, longitud o peso debe obtener un permiso de sobredimensión/sobrepeso antes de operar. Fuente: ORS 818.200 y Oregon DOT Commerce and Compliance Division, Over-Dimension Operations."},"13":{"q":"¿Qué agencia de Oregón emite los permisos de sobredimensión y sobrepeso para vehículos comerciales?","options":["La Policía Estatal de Oregón","La Oregon DOT Commerce and Compliance Division","La oficina del alguacil del condado","La Administración Federal de Seguridad de Autotransportes (FMCSA)"],"explanation":"Los permisos de sobredimensión y sobrepeso en Oregón son emitidos por la Commerce and Compliance Division del Departamento de Transporte de Oregón (Oregon DOT) (anteriormente Motor Carrier Transportation Division), disponibles en línea o en los puertos de entrada. Fuente: Oregon DOT Commerce and Compliance Division."},"14":{"q":"¿Cuál es el peso máximo que Oregón permite en cualquier rueda individual?","options":["8,000 libras","10,000 libras","12,000 libras","17,000 libras"],"explanation":"Oregón limita el peso en cualquier rueda individual a 10,000 libras. Fuente: ORS 818.010 (Peso máximo permitido)."},"15":{"q":"Una 'carga divisible' que excede el límite de 80,000 libras de Oregón es aquella que:","options":["No puede separarse sin un gasto excesivo o riesgo de daño","Puede dividirse razonablemente en cargas más pequeñas y legales","Siempre se clasifica como material peligroso","Debe transportarse solo de noche"],"explanation":"Una carga divisible puede dividirse razonablemente en cargas legales más pequeñas; en Oregón dichas cargas pueden exceder las 80,000 libras solo bajo un permiso de peso extendido (carga divisible) de ODOT, a diferencia de las cargas no divisibles que usan permisos de variación de sobredimensión. Fuente: Oregon DOT Commerce and Compliance Division."},"16":{"q":"Sin un permiso, ¿cuál es el voladizo máximo de carga permitido por el FRENTE de un vehículo en Oregón?","options":["3 pies","4 pies","5 pies","6 pies"],"explanation":"Oregón permite un voladizo máximo de carga frontal de 4 pies sin un permiso; un voladizo frontal mayor requiere un permiso de sobredimensión y banderines. Fuente: ORS 818.080 y Oregon DOT Legal Vehicle Dimensions."},"17":{"q":"En la Fórmula Federal de Puentes según se aplica en Oregón, aumentar el espaciamiento entre los ejes exteriores de un grupo, manteniendo el mismo número de ejes, generalmente:","options":["Disminuye el peso bruto permitido","No tiene efecto sobre el peso permitido","Aumenta el peso bruto permitido","Anula el registro del camión"],"explanation":"Debido a que L (espaciamiento de los ejes) está en el numerador, una mayor distancia entre los ejes exteriores aumenta el peso bruto permitido para ese grupo de ejes; los ejes muy juntos están limitados para proteger los puentes. Fuente: Fórmula Federal de Puentes según lo aplica Oregon DOT; ORS 818.010."},"18":{"q":"Oregón otorga ciertas tolerancias de peso y permisos con tarifas reducidas para ¿qué tipo de transporte que es importante para la economía del estado?","options":["Autobuses charter de pasajeros","Transporte de productos agrícolas y forestales (madera)","Camionetas de entrega de paquetes interestatales","Camiones de mudanza de alquiler"],"explanation":"Oregón proporciona permisos específicos y disposiciones de peso para productos agrícolas y productos forestales/madereros (por ejemplo, tolerancias de peso reducidas o de peso de registro y permisos de peso extendido para madera) que reflejan la importancia de la agricultura y la industria maderera para el estado. Fuente: Oregon DOT Commerce and Compliance Division y disposiciones de permisos del Capítulo 818 de ORS."},"19":{"q":"En Oregón, ¿qué clase de CDL se requiere para conducir cualquier combinación de vehículos con una Clasificación de Peso Bruto Combinado (GCWR) de 26,001 libras o más, siempre que el vehículo remolcado pese más de 10,000 libras?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Oregón sigue las clases estándar de CDL: una CDL de Clase A cubre cualquier combinación de vehículos con un GCWR de 26,001 lbs o más donde la unidad remolcada exceda las 10,000 lbs. Fuente: Oregon Commercial Driver Manual / Oregon DMV Driver License Classes (refleja 49 CFR 383.91; ORS 807.031)."},"20":{"q":"Según las reglas de Oregón, ¿qué clase de CDL cubre un vehículo individual con una Clasificación de Peso Bruto Vehicular (GVWR) de 26,001 libras o más, o ese vehículo remolcando una unidad que no supere las 10,000 libras?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"Una CDL de Clase B en Oregón cubre un vehículo individual con un GVWR de 26,001 lbs o más, o ese vehículo remolcando un remolque que no exceda las 10,000 lbs. Fuente: Oregon Commercial Driver Manual / Oregon DMV Driver License Classes (49 CFR 383.91)."},"21":{"q":"En Oregón, un vehículo más pequeño que no cumple con los umbrales de peso de Clase A o Clase B aún requiere una CDL de Clase C si está diseñado para transportar al menos ¿cuántas personas, incluyendo al conductor?","options":["10","12","16","24"],"explanation":"Se requiere una CDL de Clase C para un vehículo (que no cumple con la Clase A o B) diseñado para transportar 16 o más personas incluyendo al conductor, o utilizado para transportar materiales peligrosos con rótulos (placarded). Fuente: Oregon Commercial Driver Manual / Oregon DMV Driver License Classes (49 CFR 383.91)."},"22":{"q":"Además de transportar 16 o más pasajeros, ¿cuál es la otra condición que requiere una CDL de Clase C en Oregón para un vehículo demasiado pequeño para ser Clase A o B?","options":["Remolcar cualquier remolque de más de 5,000 libras","Transportar materiales peligrosos en cantidades que requieran rótulos (placards)","Operar después del anochecer en una carretera estatal","Transportar cualquier producto agrícola por contrato"],"explanation":"Oregón requiere una CDL de Clase C para un vehículo más pequeño utilizado para transportar materiales peligrosos en cantidades que requieran rótulos (placards) (o para transportar 16 o más personas). Fuente: Oregon Commercial Driver Manual; Oregon DMV CDL Classes (49 CFR 383.91)."},"23":{"q":"¿Qué código de aprobación (endorsement) usa Oregón para la aprobación de Materiales Peligrosos en una CDL?","options":["H","N","T","X"],"explanation":"La aprobación de Materiales Peligrosos tiene el código 'H' en Oregón. (El código 'X' representa una aprobación combinada de Tanque y HazMat). Fuente: Oregon DMV CDL Endorsements & Restrictions; Oregon Commercial Driver Manual."},"24":{"q":"Un conductor de Oregón necesita operar un vehículo comercial que jale remolques dobles o triples. ¿Qué aprobación (endorsement) se requiere?","options":["Aprobación P","Aprobación N","Aprobación T","Aprobación S"],"explanation":"La aprobación 'T' (Dobles/Triples) se requiere en Oregón para conducir cualquier vehículo motorizado comercial que jale remolques dobles o triples, y se obtiene aprobando un examen de conocimientos. Fuente: Oregon DMV CDL Endorsements; Oregon Commercial Driver Manual."},"25":{"q":"En Oregón, la aprobación de Vehículo Cisterna (N) se requiere cuando un CMV está diseñado para transportar líquido o gas en un tanque con clasificación de más de 119 galones individualmente Y con una capacidad nominal agregada de al menos ¿cuántos galones?","options":["500 galones","750 galones","1,000 galones","1,500 galones"],"explanation":"Oregón requiere la aprobación N (Tanque) para un vehículo que transporta líquido o gas en un tanque con clasificación de más de 119 galones individualmente con una capacidad nominal agregada de 1,000 galones o más. Fuente: Oregon Commercial Driver Manual; Oregon DMV CDL Endorsements (49 CFR 383.5)."},"26":{"q":"¿Qué aprobación (endorsement) de CDL de Oregón se requiere para conducir un vehículo diseñado para transportar 16 o más personas, incluyendo al conductor?","options":["P (Pasajeros)","S (Autobús Escolar)","T (Dobles/Triples)","N (Tanque)"],"explanation":"La aprobación 'P' (Pasajeros) se requiere en Oregón para operar un vehículo diseñado para transportar 16 o más pasajeros incluyendo al conductor; requiere un examen de conocimientos y uno de habilidades. Fuente: Oregon DMV CDL Endorsements; Oregon Commercial Driver Manual."},"27":{"q":"Para conducir un autobús escolar en Oregón, ¿qué aprobación (endorsement) debe agregar un titular de CDL además de cumplir con los requisitos de vehículos de pasajeros?","options":["Aprobación H","Aprobación S","Aprobación T","Aprobación X"],"explanation":"La aprobación 'S' (Autobús Escolar) se requiere para conducir un autobús escolar en Oregón; el solicitante también debe tener la aprobación P y aprobar un examen de conocimientos y de habilidades de autobús escolar. Fuente: Oregon DMV CDL Endorsements; Oregon Commercial Driver Manual."},"28":{"q":"¿Cuál es la edad mínima para obtener una CDL de Oregón restringida a la conducción comercial intraestatal (solo dentro de Oregón)?","options":["16 años","18 años","21 años","25 años"],"explanation":"Oregón requiere que el solicitante tenga al menos 18 años para una CDL intraestatal; la conducción interestatal requiere tener 21 años. Fuente: Oregon DMV 'Getting a CDL or CLP'; Oregon Commercial Driver Manual."},"29":{"q":"Según las reglas de Oregón, ¿cuál es la edad mínima para conducir un vehículo motorizado comercial en el comercio interestatal?","options":["18 años","19 años","21 años","23 años"],"explanation":"Oregón requiere que un conductor tenga al menos 21 años para operar un CMV en el comercio interestatal; la operación solo intraestatal se permite a los 18 años. Fuente: Oregon DMV 'Getting a CDL or CLP'; Oregon Commercial Driver Manual."},"30":{"q":"En Oregón, ¿cuánto tiempo debe tener una persona un Permiso de Aprendizaje Comercial (CLP) válido antes de poder tomar el examen de habilidades de la CDL?","options":["Al menos 7 días","Al menos 14 días","Al menos 30 días","Al menos 60 días"],"explanation":"Oregón requiere que el solicitante tenga un CLP válido durante al menos 14 días antes de tomar el examen de habilidades de la CDL, reflejando el período de espera obligatorio federal. Fuente: Oregon Commercial Driver Manual (Oregon Information); Oregon DMV (49 CFR 383.25)."},"31":{"q":"¿Por cuánto tiempo son válidos los resultados del examen de conocimientos comerciales en Oregón cuando se está tramitando una CDL?","options":["Tres meses","Seis meses","Un año","Dos años"],"explanation":"Oregón establece que los resultados del examen de conocimientos comerciales son válidos por seis meses; la solicitud de la CDL debe completarse dentro de ese plazo. Fuente: Oregon Commercial Driver Manual (Oregon Information); Oregon DMV 'Getting a CDL or CLP.'"},"32":{"q":"¿Cuál de los siguientes debe presentar un solicitante al Oregon DMV al solicitar una CDL o CLP?","options":["Solo una carta notariada del empleador","Prueba del nombre legal completo, identidad, fecha de nacimiento, estatus legal en EE. UU., domicilio de residencia y un Número de Seguro Social","Solo un pasaporte y nada más","Un diploma de secundaria y dos referencias"],"explanation":"El Oregon DMV requiere prueba del nombre legal completo, identidad, fecha de nacimiento, estatus legal en EE. UU., domicilio de residencia en Oregón y el Número de Seguro Social del solicitante. Fuente: Oregon Commercial Driver Manual (Oregon Information); Oregon DMV 'Getting a CDL or CLP.'"},"33":{"q":"Antes de tomar el examen de habilidades de la CDL para una primera licencia de Clase A o Clase B en Oregón, ¿dónde debe completar un solicitante la Capacitación para Conductores de Nivel de Entrada (ELDT)?","options":["Cualquier curso de colegio comunitario","Un proveedor listado en el FMCSA Training Provider Registry","Una oficina de campo del Oregon DMV","Un programa interno de un empleador de cualquier tipo"],"explanation":"Oregón requiere ELDT de un proveedor listado en el Training Provider Registry de FMCSA (tpr.fmcsa.dot.gov) antes de programar el examen de habilidades para una primera CDL de Clase A/B, una actualización de B a A, o una primera aprobación P, S o H. Fuente: Oregon Commercial Driver Manual; Oregon DMV (49 CFR Part 380)."},"34":{"q":"La ELDT en Oregón se requiere antes de hacer el examen para ¿cuál de estas aprobaciones (endorsements) por primera vez?","options":["Dobles/Triples (T)","Tanque (N)","Materiales Peligrosos (H)","Ninguna de las aprobaciones requiere ELDT"],"explanation":"Oregón requiere ELDT antes de tomar el examen de conocimientos de HazMat (H) por primera vez, así como para las primeras aprobaciones P o S y las primeras CDL de Clase A/B. Las aprobaciones T y N no están en la lista de ELDT. Fuente: Oregon DMV; Oregon Commercial Driver Manual (49 CFR Part 380)."},"35":{"q":"Un solicitante de CDL de Oregón que conducirá solo dentro de Oregón y no está sujeto a las reglas médicas federales debe autocertificarse bajo ¿cuál categoría?","options":["No exceptuado Interestatal (NI)","Exceptuado Interestatal (EI)","No exceptuado Intraestatal (NA)","Exceptuado Intraestatal (EA)"],"explanation":"Oregón ofrece tipos de autocertificación; un conductor que opera un CMV de Clase A, B o C solo en el comercio intraestatal certifica No exceptuado Intraestatal y debe cumplir con los estándares médicos de CDL de Oregón en lugar de los estándares federales completos. Fuente: Oregon DMV CDL Medical/Self-Certification; Oregon Commercial Driver Manual."},"36":{"q":"¿Qué categoría de autocertificación recomienda el Oregon DMV para la mayoría de los conductores de CDL para que su licencia no quede innecesariamente restringida al uso solo en Oregón?","options":["Exceptuado Interestatal","No exceptuado Interestatal","No exceptuado Intraestatal","Exceptuado Intraestatal"],"explanation":"El Oregon DMV recomienda que la mayoría de los conductores certifiquen No exceptuado Interestatal, lo cual requiere cumplir con todas las calificaciones médicas federales y también permite la operación exceptuada interestatal e intraestatal. Fuente: Oregon DMV CDL Self-Certification; Oregon Commercial Driver Manual."},"37":{"q":"Para obtener y mantener una aprobación de HazMat (H) de Oregón, un conductor debe aprobar una evaluación de amenazas a la seguridad de la Administración de Seguridad en el Transporte (TSA), que incluye toma de huellas dactilares, que debe renovarse ¿con qué frecuencia?","options":["Cada 2 años","Cada 3 años","Cada 5 años","Cada 8 años"],"explanation":"La aprobación de HazMat de Oregón requiere una evaluación de amenazas a la seguridad de la TSA con una verificación de antecedentes basada en huellas dactilares que debe renovarse cada cinco años. Fuente: Oregon DMV CDL Endorsements & Restrictions (49 CFR 1572)."},"38":{"q":"Un conductor que se autocertifica como Exceptuado Interestatal en Oregón aún debe cumplir con ¿cuál estándar médico?","options":["Ningún estándar médico en absoluto","Los estándares médicos interestatales federales completos","Los estándares médicos de CDL de Oregón","Solo un examen de la vista en la renovación"],"explanation":"Un conductor de Oregón que certifica Exceptuado Interestatal participa solo en operaciones exceptuadas bajo las reglas federales (por ejemplo, 49 CFR 390.3(f), 391.2) y no está sujeto a los estándares médicos federales completos, pero aún debe cumplir con los estándares médicos de CDL de Oregón. Fuente: Oregon DMV CDL Self-Certification; Oregon Commercial Driver Manual."},"39":{"q":"En Oregón, ¿cuál es la concentración de alcohol en sangre (BAC) en la que, o por encima de la cual, es ilegal operar un vehículo motorizado comercial (CMV)?","options":["0.08%","0.04%","0.02%","0.10%"],"explanation":"Oregón adopta el estándar federal para CMV: es ilegal operar un CMV con un BAC de 0.04% o más, la mitad del límite de 0.08% para conductores no comerciales. Fuente: Oregon Commercial Driver Manual, Section 1 (Disqualifications); 49 CFR 383.51."},"40":{"q":"Bajo la regla de consentimiento implícito de Oregón para conductores comerciales, ¿qué es cierto cuando usted opera un CMV?","options":["Puede rechazar todas las pruebas sin penalización","Se considera que ha dado su consentimiento para las pruebas de alcohol","Las pruebas requieren una exención firmada por separado en cada viaje","El consentimiento solo aplica por encima de 0.08% de BAC"],"explanation":"El Manual de CDL de Oregón establece que al operar un CMV se considera que usted ha dado su consentimiento para las pruebas de alcohol. Rechazar la prueba conlleva la misma descalificación que una infracción mayor. Fuente: Oregon Commercial Driver Manual, Section 1; ORS 813.100."},"41":{"q":"Un titular de CDL de Oregón es condenado por conducir un CMV con un BAC de 0.04% o más por PRIMERA vez, sin transportar materiales peligrosos. ¿Cuál es el período mínimo de descalificación?","options":["60 días","90 días","1 año","3 años"],"explanation":"Una primera infracción mayor, incluyendo un BAC de 0.04% o más en un CMV, descalifica al conductor por al menos 1 año en Oregón. Fuente: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"42":{"q":"Si una primera infracción mayor (como un BAC de 0.04%) ocurre mientras el conductor opera un CMV con rótulos (placarded) para materiales peligrosos, ¿cuál es la descalificación mínima en Oregón?","options":["1 año","18 meses","3 años","5 años"],"explanation":"Cuando una primera infracción mayor ocurre en un CMV con rótulos (placarded) para materiales peligrosos, la descalificación aumenta a al menos 3 años. Fuente: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"43":{"q":"¿Cuál es la descalificación en Oregón por una SEGUNDA infracción mayor cometida por un titular de CDL?","options":["3 años","5 años","10 años","De por vida"],"explanation":"Una segunda infracción mayor (por ejemplo, un segundo DUI en un CMV, o una infracción mayor después de una previa) resulta en una descalificación de CDL de por vida en Oregón. Fuente: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"44":{"q":"Un titular de CDL de Oregón rechaza someterse a las pruebas de alcohol mientras opera un CMV (primera ocurrencia). ¿Cómo se trata esto a efectos de descalificación?","options":["Sin penalización de CDL, solo una multa","Se trata como una infracción mayor: descalificación de al menos 1 año","Descalificación de 30 días","Se trata como una violación grave: 60 días"],"explanation":"Rechazar las pruebas de alcohol está incluido entre las infracciones mayores y conlleva una descalificación de al menos 1 año (3 años si lleva rótulos para hazmat), igual que el incumplimiento del BAC. Fuente: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51; ORS 813.100."},"45":{"q":"Un titular de CDL de Oregón usa un CMV para cometer un delito grave que involucra una sustancia controlada (fabricación, distribución o dispensación). ¿Cuál es la descalificación?","options":["1 año","3 años","10 años","De por vida, sin posibilidad de restitución"],"explanation":"Usar un CMV para cometer un delito grave que involucra sustancias controladas resulta en una descalificación de por vida sin posibilidad de restitución. Fuente: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"46":{"q":"Se determina que un conductor de CDL en Oregón tiene una cantidad detectable de alcohol POR DEBAJO de 0.04% mientras está de servicio. ¿Qué sucede?","options":["Nada, está por debajo del límite legal","Se le pone fuera de servicio (out-of-service) por 24 horas","Descalificación de 1 año","Se le pone fuera de servicio (out-of-service) por 1 hora"],"explanation":"Cualquier alcohol detectable por debajo de 0.04% no desencadena una descalificación por infracción mayor, pero sí pone al conductor fuera de servicio (out-of-service) por 24 horas. Fuente: Oregon Commercial Driver Manual, Section 1; 49 CFR 392.5."},"47":{"q":"¿Cuál de las siguientes se clasifica como una 'violación de tránsito grave' para un titular de CDL de Oregón?","options":["Estacionarse en una zona de prohibido estacionar","Exceso de velocidad, 15 mph o más por encima del límite","Una luz de marcador (marker lamp) fundida","Conducir 5 mph por encima del límite"],"explanation":"Las violaciones de tránsito graves incluyen el exceso de velocidad definido como 15 mph o más por encima del límite señalizado, conducción imprudente, cambios de carril indebidos o erráticos, y seguir demasiado de cerca. Fuente: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"48":{"q":"¿Cuántas violaciones de tránsito graves dentro de un período de 3 años desencadenan una descalificación en Oregón, y por cuánto tiempo es la PRIMERA de dichas descalificaciones?","options":["1 violación; 30 días","2 violaciones; al menos 60 días","2 violaciones; al menos 30 días","3 violaciones; al menos 60 días"],"explanation":"Dos violaciones de tránsito graves dentro de 3 años resultan en una descalificación de al menos 60 días. Fuente: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"49":{"q":"Un titular de CDL de Oregón comete TRES violaciones de tránsito graves dentro de un período de 3 años. ¿Cuál es la descalificación mínima?","options":["60 días","90 días","120 días","1 año"],"explanation":"Tres o más violaciones de tránsito graves dentro de 3 años resultan en una descalificación de al menos 120 días. Fuente: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"50":{"q":"¿Las violaciones de tránsito graves cuentan para la descalificación de la CDL cuando se cometen en el vehículo PERSONAL (no comercial) del conductor?","options":["No, solo cuentan las violaciones en un CMV","Sí, si resultan en la suspensión o revocación de la licencia","Solo si hay alcohol involucrado","Solo cuentan las violaciones en carreteras interestatales"],"explanation":"Las violaciones de tránsito graves cometidas en un vehículo que no es CMV cuentan contra un titular de CDL si la condena resulta en la suspensión o revocación de la licencia de conducir. Fuente: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"51":{"q":"Para una SEGUNDA violación de cruce a nivel de ferrocarril y carretera dentro de 3 años, ¿cuál es la descalificación mínima en Oregón?","options":["60 días","120 días","180 días","1 año"],"explanation":"Una segunda violación de cruce a nivel de ferrocarril y carretera dentro de un período de 3 años resulta en una descalificación de al menos 120 días. Fuente: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"52":{"q":"¿Cuál es la descalificación mínima en Oregón por una TERCERA violación de cruce a nivel de ferrocarril y carretera dentro de un período de 3 años?","options":["120 días","180 días","1 año","3 años"],"explanation":"Una tercera o subsiguiente violación de cruce a nivel de ferrocarril y carretera dentro de 3 años resulta en una descalificación de al menos 1 año. Fuente: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51."},"53":{"q":"Un titular de CDL de Oregón viola una orden de fuera de servicio (out-of-service) por PRIMERA vez mientras NO transporta materiales peligrosos ni pasajeros. ¿Cuál es la descalificación mínima?","options":["60 días","90 días","180 días","1 año"],"explanation":"Una primera violación de una orden de fuera de servicio (out-of-service) (sin hazmat, sin pasajeros) resulta en una descalificación de al menos 180 días. Fuente: Oregon Commercial Driver Manual, Section 1 / ODOT Commercial Driver Convictions page; 49 CFR 383.51."},"54":{"q":"Un conductor viola una orden de fuera de servicio (out-of-service) por PRIMERA vez mientras transporta materiales peligrosos (o conduce un vehículo diseñado para 16 o más pasajeros). ¿Cuál es la descalificación mínima en Oregón?","options":["180 días","1 año","3 años","5 años"],"explanation":"Una primera violación de fuera de servicio (out-of-service) mientras se transporta hazmat o se opera un vehículo de 16 o más pasajeros resulta en una descalificación de al menos 1 año, más larga que la base de 180 días. Fuente: ODOT Commercial Driver Convictions page; 49 CFR 383.51."},"55":{"q":"¿Cuál es la descalificación mínima por una SEGUNDA violación de una orden de fuera de servicio (out-of-service) dentro de 10 años, que no involucre hazmat ni pasajeros?","options":["1 año","2 años","3 años","5 años"],"explanation":"Una segunda violación de fuera de servicio (out-of-service) dentro de 10 años (sin hazmat, sin pasajeros) resulta en una descalificación de al menos 3 años; si hubo hazmat o pasajeros involucrados, aumenta a al menos 5 años. Fuente: ODOT Commercial Driver Convictions page; 49 CFR 383.51."},"56":{"q":"Además de la descalificación de la licencia, ¿qué sanción civil impone Oregón/ODOT a un conductor por una PRIMERA violación de una orden de fuera de servicio (out-of-service)?","options":["$650","$1,000","$3,861","$7,723"],"explanation":"ODOT impone una sanción civil de $3,861 por una primera violación de una orden de fuera de servicio (out-of-service) y $7,723 por una segunda o subsiguiente violación, además de la descalificación. Fuente: ODOT Commercial Driver Convictions page; 49 CFR 383.53."},"57":{"q":"Según las reglas que aplican a los conductores de CDL de Oregón, ¿qué está prohibido con respecto a los teléfonos móviles mientras se conduce un CMV?","options":["Toda comunicación por radio está prohibida","Sostener un teléfono para una llamada, marcar presionando más de un botón, o enviar mensajes de texto","Las llamadas con manos libres también están prohibidas","Los teléfonos deben estar apagados en todo momento"],"explanation":"Los conductores de CMV no pueden sostener un teléfono móvil para hablar, marcar presionando más de un solo botón, ni enviar/leer mensajes de texto mientras conducen; una violación por mensajes de texto/teléfono en mano es una violación de tránsito grave (multa federal máxima de $2,750) que cuenta para la descalificación de 60/120 días. Fuente: Oregon Commercial Driver Manual, Section 1; 49 CFR 392.80-392.82, 383.51."},"58":{"q":"Según la Ley de Cambio de Carril (Move Over Law) de Oregón, cuando te acercas a un vehículo de emergencia, de remolque, de asistencia en carretera o con luces de peligro detenido en una vía de varios carriles y NO puedes cambiarte con seguridad a un carril no adyacente, ¿qué debes hacer?","options":["Reducir a una velocidad de al menos 5 mph por debajo del límite de velocidad publicado o designado","Detenerte por completo hasta que el vehículo se retire","Reducir a exactamente 10 mph por debajo del límite de velocidad publicado","Mantener la velocidad publicada pero tocar la bocina"],"explanation":"La Ley de Cambio de Carril de Oregón (ORS 811.147) exige que los conductores se cambien a un carril no adyacente si es posible; si no es posible, deben reducir a al menos 5 mph por debajo del límite de velocidad publicado o designado y proceder con precaución. Fuente: ORS 811.147; Manual del Conductor de Oregón."},"59":{"q":"Una infracción de la Ley de Cambio de Carril de Oregón (no mantener una distancia segura de un vehículo de emergencia, de asistencia en carretera, de remolque o una ambulancia detenidos) se clasifica como ¿qué tipo de infracción?","options":["Una infracción de tránsito Clase B","Una infracción de tránsito Clase A","Un delito menor Clase C","Una infracción de tránsito Clase D"],"explanation":"No mantener una distancia segura de un vehículo de emergencia, de asistencia en carretera, de remolque o una ambulancia bajo la Ley de Cambio de Carril de Oregón es una infracción de tránsito Clase B. Fuente: ORS 811.147."},"60":{"q":"En Oregón, cuando un autobús escolar está detenido en una calle de doble sentido con sus luces rojas intermitentes encendidas, ¿a qué distancia debe detenerse un conductor que se aproxima?","options":["20 pies o más del autobús","10 pies o más del autobús","30 pies o más del autobús","50 pies o más del autobús"],"explanation":"Oregón exige que los conductores se detengan a 20 pies o más de un autobús escolar que muestre luces rojas de advertencia intermitentes y que permanezcan detenidos hasta que las luces dejen de parpadear. Fuente: ORS 811.155; Manual del Conductor de Oregón."},"61":{"q":"Según la ley de Oregón, ¿cuál es la ÚNICA situación en la que un conductor que circula en sentido contrario NO está obligado a detenerse ante un autobús escolar que muestra luces rojas intermitentes?","options":["El autobús está detenido en una calzada diferente, separada por una mediana o barrera física","El autobús está detenido en una zona residencial de 25 mph","Hay un carril central de giro a la izquierda de doble sentido entre el conductor y el autobús","La vía está pintada con una línea central amarilla continua"],"explanation":"En Oregón, un conductor no necesita detenerse solo si el autobús que muestra luces rojas está en una calzada diferente, lo que significa que la carretera está dividida por una mediana o barrera física en calzadas separadas. Una línea amarilla pintada o un carril central de giro NO crean calzadas separadas, por lo que todos los carriles deben detenerse. Fuente: ORS 811.155; Manual del Conductor de Oregón."},"62":{"q":"No detenerse ante las luces rojas intermitentes de seguridad de un autobús escolar en Oregón ¿de qué nivel de infracción de tránsito se trata?","options":["Una infracción de tránsito Clase A","Una infracción de tránsito Clase B","Una infracción de tránsito Clase C","Un delito menor Clase A"],"explanation":"No detenerse ante las luces de seguridad del autobús según la ORS 811.155 es una infracción de tránsito Clase A, la clase de infracción de tránsito más grave de Oregón. Fuente: ORS 811.155."},"63":{"q":"Cuando un conductor con CDL de Oregón debe detenerse en un cruce de ferrocarril en un vehículo con carteles de materiales peligrosos (hazmat) (y no hay una línea de alto marcada), ¿dónde debe detenerse el vehículo?","options":["No menos de 15 pies ni más de 50 pies del riel más cercano","No menos de 10 pies ni más de 25 pies del riel más cercano","No menos de 5 pies ni más de 15 pies del riel más cercano","No menos de 50 pies ni más de 100 pies del riel más cercano"],"explanation":"Un conductor de un vehículo con carteles de hazmat, una carga de cloro o un tanque de carga de hazmat (cargado o vacío) debe detenerse no menos de 15 pies ni más de 50 pies del riel más cercano cuando no hay línea de alto. Fuente: Manual del Conductor Comercial de Oregón, Sección 9; ORS 811.460."},"64":{"q":"Al cruzar las vías del ferrocarril en un vehículo con carteles de hazmat en Oregón, ¿qué prohíbe específicamente la regla?","options":["Cambiar de marcha manualmente mientras se está sobre las vías","Usar el freno motor mientras se está sobre las vías","Encender las luces intermitentes de cuatro direcciones mientras se está sobre las vías","Tocar la bocina mientras se está sobre las vías"],"explanation":"La regla de cruces de alto riesgo de Oregón exige que el conductor cruce en una marcha que no requiera cambiar de marcha manualmente, por lo que no debes cambiar de marcha mientras estás sobre las vías; avanza solo cuando estés seguro de que puedes despejar las vías sin detenerte. Fuente: ORS 811.460; Manual del Conductor Comercial de Oregón, Sección 9."},"65":{"q":"¿Cuál de estos vehículos NO está entre los vehículos de \"alto riesgo\" que la ley de Oregón exige que se detengan en todos los cruces de ferrocarril?","options":["Un camión de plataforma vacío que transporta carga ordinaria","Un autobús escolar","Un tanque de carga, cargado o vacío, que transporta materiales peligrosos","Un autobús comercial que transporta pasajeros"],"explanation":"La ORS 811.460 enumera los vehículos de alto riesgo que deben detenerse en los cruces: autobuses escolares, ciertos autobuses de actividades escolares y de transporte de trabajadores, autobuses comerciales, vehículos que transportan explosivos/inflamables/corrosivos y vehículos cisterna de hazmat (cargados o vacíos). Un camión de carga ordinaria con mercancía no peligrosa no está obligado a detenerse a menos que las señales lo requieran. Fuente: ORS 811.460."},"66":{"q":"En Oregón, ¿cuál es el límite de velocidad máximo estándar para un vehículo comercial de más de 10,000 libras de GVWR a menos que se publique una velocidad diferente?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"A menos que se publique una velocidad diferente, el máximo predeterminado para vehículos comerciales de más de 10,000 lbs de GVWR (o camiones tractores de más de 8,000 lbs de GVWR) es de 55 mph. Fuente: ORS 811.111; ORS 810.180."},"67":{"q":"Según la norma de Oregón, la velocidad máxima que el Departamento de Transporte puede designar para vehículos comerciales en una autopista interestatal es:","options":["65 mph","70 mph","60 mph","75 mph"],"explanation":"ODOT puede establecer velocidades interestatales designadas pero no puede exceder 65 mph para vehículos comerciales (el tope para otros vehículos es de 70 mph). Algunos tramos interestatales de Oregón se han elevado a 60 mph para camiones donde los automóviles circulan a 65. Fuente: ORS 810.180; OAR 734-020-0010."},"68":{"q":"En una vía de Oregón con dos o más carriles que van en la misma dirección, ¿qué vehículos están obligados a circular por el carril derecho excepto al rebasar o girar?","options":["Campers, vehículos que remolcan un tráiler y vehículos con un peso de registro de 10,000 libras o más","Solo vehículos con tres o más ejes","Solo vehículos que muestran carteles de hazmat","Todos los vehículos que circulan a menos de 45 mph"],"explanation":"La ORS 811.325 exige que cualquier camper, cualquier vehículo con un tráiler y cualquier vehículo con un peso de registro de 10,000 lbs o más utilice el carril derecho en vías de un solo sentido con varios carriles, excepto al rebasar, girar a la izquierda, responder a una emergencia, evitar tráfico que se incorpora o según lo indiquen los dispositivos de control de tránsito. Fuente: ORS 811.325."},"69":{"q":"No mantener un camper, tráiler o camión (10,000 lbs o más) en el carril derecho en una autopista de varios carriles de Oregón ¿qué tipo de infracción es?","options":["Una infracción de tránsito Clase B","Una infracción de tránsito Clase A","Una infracción de tránsito Clase C","Una infracción de tránsito Clase D"],"explanation":"Violar el requisito del carril derecho de la ORS 811.325 es una infracción de tránsito Clase B. Fuente: ORS 811.325."},"70":{"q":"¿Cuál es una excepción legal reconocida que permite que un camión de Oregón (10,000 lbs o más) abandone el carril derecho en una autopista de varios carriles?","options":["Alcanzar y rebasar a otro vehículo que va en la misma dirección","Querer mantener una velocidad de crucero más rápida","Mantener una distancia de seguimiento más larga con el vehículo de adelante","Evitar el desgaste del pavimento del carril derecho"],"explanation":"La ORS 811.325 permite abandonar el carril derecho para alcanzar y rebasar legalmente, para prepararse para un giro a la izquierda, para responder a condiciones de emergencia, para evitar el tráfico que ingresa desde carriles de incorporación/aceleración o según lo indiquen los dispositivos de control de tránsito. Fuente: ORS 811.325."},"71":{"q":"En una autopista dividida o de un solo sentido en Oregón, ¿dónde debe colocar un conductor con CDL los tres triángulos de advertencia de emergencia cuando se detiene en la vía?","options":["A no más de 10 pies de la parte trasera, y a 100 pies y 200 pies hacia el tráfico que se aproxima","A no más de 25 pies de la parte trasera, y a 50 pies y 150 pies hacia el tráfico que se aproxima","A no más de 10 pies de la parte delantera, y a 100 pies y 300 pies hacia el tráfico que se aproxima","A no más de 50 pies de la parte trasera, y a 100 pies y 250 pies hacia el tráfico que se aproxima"],"explanation":"En una autopista de un solo sentido o dividida, coloca un dispositivo de advertencia a no más de 10 pies de la parte trasera hacia el tráfico que se aproxima, uno a unos 100 pies atrás y uno a unos 200 pies atrás. Esta norma federal (49 CFR 392.22) se enseña en el Manual del Conductor Comercial de Oregón. Fuente: Manual del Conductor Comercial de Oregón; 49 CFR 392.22."},"72":{"q":"En una vía de dos carriles y doble sentido de Oregón, después de que un vehículo con CDL se detiene en la parte transitada, ¿dentro de cuántos minutos debe el conductor tener colocados los dispositivos de advertencia de emergencia?","options":["Dentro de 10 minutos","Dentro de 5 minutos","Dentro de 15 minutos","Dentro de 30 minutos"],"explanation":"Un conductor con CDL debe colocar los dispositivos de advertencia (tres triángulos o equivalente) dentro de los 10 minutos de haberse detenido en la parte transitada o el arcén de una vía. Fuente: Manual del Conductor Comercial de Oregón; 49 CFR 392.22."},"73":{"q":"En Oregón, ¿cuál es el ANCHO máximo legal del vehículo/carga antes de que se requiera un permiso de sobredimensión?","options":["8 pies 6 pulgadas","8 pies 0 pulgadas","9 pies 0 pulgadas","10 pies 0 pulgadas"],"explanation":"El ancho máximo legal de Oregón es de 8 pies 6 pulgadas; las cargas que excedan esto requieren un permiso de sobredimensión de la Commerce and Compliance Division de ODOT. Fuente: ORS 818.080; Dimensiones Legales de Vehículos de ODOT."},"74":{"q":"¿Cuál es la ALTURA máxima legal del vehículo en Oregón antes de que se requiera un permiso de sobredimensión?","options":["14 pies 0 pulgadas","13 pies 6 pulgadas","13 pies 0 pulgadas","15 pies 0 pulgadas"],"explanation":"La altura máxima legal de Oregón es de 14 pies 0 pulgadas; las cargas que excedan esto requieren un permiso de sobredimensión. (Ten en cuenta que muchos otros estados usan 13'6\".) Fuente: ORS 818.080; Dimensiones Legales de Vehículos de ODOT."},"75":{"q":"Oregón exige que todos los vehículos de más de 10,000 lbs de GVW lleven cadenas para neumáticos durante la temporada de nieve:","options":["Siempre que existan condiciones en las que su uso pueda ser necesario o requerido","Solo al viajar al este de las Cascadas","Solo los fines de semana de diciembre a febrero","Solo si el vehículo carece de neumáticos con tachuelas"],"explanation":"La ley de Oregón exige que los vehículos de más de 10,000 lbs de GVW lleven cadenas siempre que existan condiciones en las que las cadenas puedan ser necesarias o requeridas, y que las instalen cuando la ley de cadenas esté en vigor (por lo general de octubre a marzo en los pasos de montaña). Fuente: Commerce and Compliance Division de ODOT, Cadenas y Neumáticos de Tracción."},"76":{"q":"¿Durante qué período es legal usar neumáticos con tachuelas en las vías de Oregón?","options":["Del 1 de noviembre al 31 de marzo","Del 1 de octubre al 30 de abril","Del 15 de noviembre al 15 de abril","Del 1 de diciembre al 1 de marzo"],"explanation":"Los neumáticos con tachuelas son legales en Oregón solo del 1 de noviembre al 31 de marzo; usarlos fuera de este período puede acarrear una multa. Fuente: ODOT / Oregon TripCheck; disposiciones de la ORS sobre neumáticos con tachuelas."},"77":{"q":"Oregón se destaca por una de las primeras características de escape para camiones desbocados en una pendiente pronunciada de la Interestatal 5. ¿Dónde se construyó y probó el primer lecho de detención de camiones con pendiente negativa (cuesta abajo) del país?","options":["Cerca de Siskiyou Summit en la I-5 en el sur de Oregón","En la pendiente de Cabbage Hill de la I-84","En Government Camp en la US 26 sobre el Monte Hood","En el Paso de Santiam de la US 20"],"explanation":"El primer lecho de detención de camiones con pendiente negativa (cuesta abajo) de los Estados Unidos se construyó y probó en 1977 a lo largo de la I-5 cerca de Siskiyou Summit en el sur de Oregón, una pendiente de montaña notablemente pronunciada donde se enfatiza el uso de rampas de escape. Fuente: ODOT; guía de conducción en montaña del Manual del Conductor Comercial de Oregón."},"78":{"q":"En Oregón, ¿qué agencia estatal emite las Licencias de Conducir Comerciales (CDL) y administra el proceso de exámenes?","options":["El Oregon DMV, parte de los Servicios de Conductores y Vehículos Motorizados del Departamento de Transporte de Oregón (ODOT)","La División de Vehículos Comerciales de la Policía Estatal de Oregón","La oficina regional de la Administración Federal de Seguridad de Autotransportes (FMCSA)","La División de Corporaciones y Licencias del Secretario de Estado de Oregón"],"explanation":"Las CDL de Oregón son emitidas por el Oregon DMV, que forma parte de los Servicios de Conductores y Vehículos Motorizados del Departamento de Transporte de Oregón (ODOT). Fuente: página \"Getting a CDL or CLP\" del Oregon DMV; Manual del Conductor Comercial de Oregón."},"79":{"q":"Un vehículo requiere una CDL de Oregón según el peso cuando su clasificación de peso bruto vehicular (GVWR) es de al menos cuántas libras?","options":["26,001 libras","10,001 libras","18,000 libras","33,000 libras"],"explanation":"Oregón requiere una CDL para operar un vehículo con un GVWR de 26,001 libras o más (y para combinaciones donde la unidad remolcada supere las 10,000 lbs). Fuente: Manual del Conductor Comercial de Oregón, Sección 1."},"80":{"q":"Aparte del peso, ¿qué umbral de pasajeros hace que un vehículo requiera una CDL de Oregón?","options":["Diseñado para transportar 16 o más personas, incluido el conductor","Diseñado para transportar 9 o más personas, incluido el conductor","Diseñado para transportar 24 o más personas, sin contar al conductor","Diseñado para transportar 12 o más personas, incluido el conductor"],"explanation":"Se requiere una CDL para un vehículo diseñado para transportar 16 o más personas, incluido el conductor. El tercer factor es el transporte de materiales peligrosos que requieran carteles. Fuente: Manual del Conductor Comercial de Oregón, Sección 1; 49 CFR 383.5 según se aplica en Oregón."},"81":{"q":"Al solicitar una CDL o un permiso de aprendizaje comercial de Oregón, el solicitante debe \"autocertificar\" en qué tipo de comercio operará. ¿Qué conjunto de categorías ofrece Oregón?","options":["Interestatal No Exceptuado, Interestatal Exceptuado e Intraestatal No Exceptuado","Hazmat Interestatal, Hazmat Intraestatal y Solo No Hazmat","Transportista Federal, Transportista Estatal y Transportista Privado","Operación Clase A, Clase B y Clase C"],"explanation":"El Oregon DMV ofrece tres categorías de autocertificación: Interestatal No Exceptuado, Interestatal Exceptuado e Intraestatal No Exceptuado. (Intraestatal Exceptuado es la cuarta categoría de FMCSA; Oregón no la enumera por separado.) Fuente: solicitud/autocertificación de CDL del Oregon DMV; 49 CFR 383.71."},"82":{"q":"A un solicitante de CDL de Oregón que se autocertifica como \"Interestatal No Exceptuado\" se le exige qué con respecto a la calificación médica?","options":["Proporcionar al DMV una copia de un certificado válido de examinador médico del DOT y mantener uno vigente en el archivo","Llevar la tarjeta médica en papel en el camión pero nunca entregarla al DMV","Presentar una declaración notariada de que no se necesita un examen médico","Aprobar una prueba de aptitud física en carretera adicional administrada por el DMV"],"explanation":"Un conductor interestatal no exceptuado debe proporcionar al Oregon DMV una copia de un certificado válido de examinador médico (tarjeta médica del DOT) y es responsable de mantener uno vigente en el archivo, o la CDL se degrada. Fuente: certificación médica de CDL del Oregon DMV; 49 CFR 383.71/391.45."},"83":{"q":"¿Quién está calificado para realizar el examen físico del DOT que produce el certificado de examinador médico utilizado para una CDL de Oregón?","options":["Un examinador médico incluido en el Registro Nacional de Examinadores Médicos Certificados de la FMCSA","Cualquier farmacéutico con licencia en Oregón","Un examinador de una oficina del Oregon DMV","Cualquier médico, siempre que tenga licencia en cualquier estado de EE. UU."],"explanation":"El examen médico del DOT debe ser realizado por un examinador médico incluido en el Registro Nacional de Examinadores Médicos Certificados de la FMCSA. Fuente: \"Getting a CDL or CLP\" del Oregon DMV; 49 CFR 390.103."},"84":{"q":"Antes de que un solicitante pueda tomar el examen de habilidades de la CDL en Oregón, primero debe obtener ¿qué credencial?","options":["Un Permiso de Aprendizaje Comercial (CLP)","Una CDL provisional Clase C","Una autorización federal de operación interestatal (número MC)","Una exención temporal de fuera de servicio"],"explanation":"Los solicitantes que requieren el examen de habilidades primero deben obtener un Permiso de Aprendizaje Comercial (CLP) aprobando el o los exámenes de conocimientos requeridos. Fuente: proceso de CDL del Oregon DMV; OAR 735-063-0250 / 735-063-0260."},"85":{"q":"Para obtener un Permiso de Aprendizaje Comercial Clase A de Oregón, ¿qué exámenes de conocimientos debe aprobar el solicitante?","options":["El examen de Conocimientos Generales y el examen de Vehículos Combinados (más Frenos de Aire si corresponde)","Solo el examen de Conocimientos Generales","El examen de Conocimientos Generales y el examen de Materiales Peligrosos","Solo el examen de Vehículos Combinados"],"explanation":"Un CLP Clase A requiere aprobar el examen de Conocimientos Generales y el examen de Vehículos Combinados, más el examen de Frenos de Aire si el vehículo tiene frenos de aire. Fuente: OAR 735-063-0250; Manual del Conductor Comercial de Oregón."},"86":{"q":"¿Cuál es la puntuación mínima para aprobar los exámenes de conocimientos de la CDL de Oregón?","options":["80 por ciento de respuestas correctas","70 por ciento de respuestas correctas","90 por ciento de respuestas correctas","75 por ciento de respuestas correctas"],"explanation":"Se requiere una puntuación de al menos 80 por ciento de respuestas correctas para aprobar cada examen de conocimientos de la CDL de Oregón (por ejemplo, 40 de 50 preguntas en el examen de Conocimientos Generales). Fuente: Manual del Conductor Comercial de Oregón / Oregon DMV; 49 CFR 383.135."},"87":{"q":"El examen de habilidades de la CDL de Oregón se compone de tres partes que deben tomarse en un orden establecido. ¿Cuál es ese orden?","options":["Inspección del vehículo previa al viaje, luego habilidades básicas de control, luego conducción en carretera","Conducción en carretera, luego inspección previa al viaje, luego habilidades básicas de control","Habilidades básicas de control, luego conducción en carretera, luego inspección previa al viaje","Inspección previa al viaje, luego conducción en carretera, luego habilidades básicas de control"],"explanation":"El examen de habilidades se administra en orden: primero la inspección del vehículo previa al viaje, luego las habilidades básicas de control, luego la conducción en carretera; cada parte debe aprobarse antes de continuar. Fuente: OAR 735-063-0260 / OAR 735-060-0120."},"88":{"q":"La Capacitación Federal para Conductores Principiantes (ELDT) debe completarse antes de los exámenes en Oregón para ¿cuál de los siguientes casos?","options":["Obtener una CDL Clase A o B por primera vez, ascender de Clase B a A, o obtener por primera vez los endosos de pasajeros/autobús escolar/hazmat","Cada renovación de CDL, independientemente de la clase","Solo para conductores menores de 21 años","Solo al agregar un endoso de dobles/triples"],"explanation":"La ELDT es requerida antes de los exámenes para obtener una CDL Clase A o B por primera vez, ascender de una Clase B a Clase A, u obtener por primera vez un endoso de pasajeros, autobús escolar o materiales peligrosos. Fuente: Oregon DMV; 49 CFR Parte 380 Subparte F."},"89":{"q":"La Capacitación para Conductores Principiantes (ELDT) para una CDL de Oregón debe ser proporcionada por una entidad que esté incluida ¿dónde?","options":["En el Registro de Proveedores de Capacitación (TPR) de la FMCSA","En la lista de escuelas secundarias aprobadas del Oregon DMV","En la lista de miembros de las Asociaciones de Transportistas de Oregón","En la oficina de aprendizaje del Departamento de Trabajo de EE. UU."],"explanation":"La instrucción de ELDT debe completarse a través de una escuela o entidad incluida en el Registro de Proveedores de Capacitación (TPR) de la FMCSA antes de programar un examen de habilidades o tomar el examen de conocimientos de hazmat. Fuente: Oregon DMV; Registro de Proveedores de Capacitación de la FMCSA."},"90":{"q":"¿Por cuánto tiempo debe mantenerse un Permiso de Aprendizaje Comercial de Oregón antes de que el titular pueda tomar el examen de habilidades de la CDL?","options":["Al menos 14 días","Al menos 30 días","Al menos 7 días","Al menos 60 días"],"explanation":"El Oregon DMV debe haber emitido el CLP no vencido no menos de 14 días antes del examen de habilidades. Fuente: OAR 735-063-0260."},"91":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendizaje Comercial (CLP) de Oregón, y puede renovarse?","options":["Válido por un año y no es renovable","Válido por 180 días y puede renovarse una vez","Válido por dos años y es renovable anualmente","Válido por 90 días y no es renovable"],"explanation":"Un CLP de Oregón es válido por un año desde su emisión y no es renovable. Fuente: ORS 807.285."},"92":{"q":"Una puntuación aprobatoria en los exámenes de conocimientos de la CDL de Oregón (y en un examen de habilidades completado) permanece válida por cuánto tiempo antes de que deba emitirse la CDL?","options":["Seis meses","Tres meses","Un año","Treinta días"],"explanation":"Una puntuación aprobatoria del examen de conocimientos es válida por seis meses, y una puntuación aprobatoria de un examen de habilidades de la CDL completado es válida por seis meses. Fuente: OAR 735-063-0250 y OAR 735-063-0260."},"93":{"q":"Una vez emitida, ¿por cuánto tiempo es válida una CDL de Oregón antes de que deba renovarse?","options":["8 años","4 años","5 años","10 años"],"explanation":"Una CDL de Oregón emitida a un ciudadano estadounidense o residente permanente es válida por 8 años, el mismo ciclo estándar que una licencia de conducir regular de Oregón. Fuente: Oregon DMV; Capítulo 807 de la ORS."},"94":{"q":"¿Cuál es el período de renovación de la CDL de Oregón en relación con la fecha de vencimiento?","options":["Hasta 12 meses antes del vencimiento y hasta 2 años después del vencimiento","Solo en o después de la fecha de vencimiento, sin renovación anticipada","Hasta 30 días antes y hasta 30 días después del vencimiento","Solo hasta 6 meses antes del vencimiento"],"explanation":"Una CDL de Oregón puede renovarse hasta 12 meses antes de que venza y hasta 2 años después de que venza; pasado ese plazo, el conductor debe solicitar una nueva licencia. Fuente: \"Renewing a Commercial Driver License\" del Oregon DMV."},"95":{"q":"¿Qué documentos debe proporcionar un solicitante de CDL/CLP de Oregón para establecer su elegibilidad al momento de la solicitud?","options":["Prueba de nombre legal completo, ciudadanía estadounidense o residencia permanente legal, identidad, fecha de nacimiento, domicilio y Número de Seguro Social","Solo una foto de pasaporte actual y una tarjeta de crédito","Una carta notariada del empleador y un título de vehículo","Prueba de tres años de experiencia en conducción comercial"],"explanation":"Los solicitantes deben proporcionar prueba de nombre legal completo, ciudadanía estadounidense o residencia permanente legal, identidad, fecha de nacimiento y domicilio, además de su Número de Seguro Social. Fuente: \"Getting a CDL or CLP\" del Oregon DMV; OAR 735-063-0250."},"96":{"q":"Al renovar una CDL de Oregón que tiene un endoso de Materiales Peligrosos, ¿qué requisito adicional aplica?","options":["Aprobar el examen de conocimientos de HazMat y tener una verificación de antecedentes de seguridad de la TSA vigente (evaluación de amenazas)","Proporcionar una carta notariada del último expedidor registrado","Entregar la CDL por 30 días durante la revisión de antecedentes","Aprobar un segundo examen de habilidades en carretera en un vehículo con carteles"],"explanation":"Renovar una CDL con un endoso de HazMat requiere aprobar el examen de conocimientos de HazMat y tener una evaluación de amenazas de seguridad de la TSA vigente (verificación de antecedentes). Fuente: \"Renewing a CDL\" del Oregon DMV; 49 CFR Parte 1572."},"97":{"q":"Si un titular de una CDL de Oregón deja vencer un certificado de examinador médico requerido (para una autocertificación no exceptuada), ¿qué hace el Oregon DMV?","options":["Degrada la CDL, retirando los privilegios de conducción comercial hasta que haya un certificado médico válido en el archivo","Suspende también los privilegios de conducción regular (Clase C)","Emite una exención médica automática de 90 días sin necesidad de acción","Remite al conductor a la Policía Estatal de Oregón para una citación"],"explanation":"Si el certificado médico de un conductor no exceptuado vence y no hay uno vigente en el archivo, el Oregon DMV degrada la CDL, retirando los privilegios comerciales hasta que se presente un certificado válido; la licencia regular permanece. Fuente: certificación médica de CDL del Oregon DMV; 49 CFR 383.73."}},"hi":{"0":{"q":"ओवर-डाइमेंशन परमिट के बिना ओरेगन के राजमार्गों पर अधिकांश वाणिज्यिक वाहनों के लिए अधिकतम कानूनी चौड़ाई क्या है?","options":["8 फीट (96 इंच)","8 फीट 6 इंच (102 इंच)","9 फीट (108 इंच)","10 फीट (120 इंच)"],"explanation":"ओरेगन सार्वजनिक राजमार्गों पर वाहन की कुल बाहरी चौड़ाई को 8 फीट 6 इंच (102 इंच) तक सीमित करता है; इससे अधिक चौड़े किसी भी वाहन के लिए ओवर-डाइमेंशन परमिट आवश्यक है। स्रोत: ORS 818.080 (अधिकतम आकार सीमाएँ) और Oregon DOT Commerce and Compliance Division, Legal Vehicle Dimensions।"},"1":{"q":"परमिट के बिना ओरेगन के राजमार्गों पर चलने वाले वाहन के लिए, लोड सहित, अधिकतम कानूनी ऊँचाई क्या है?","options":["13 फीट 6 इंच","14 फीट","14 फीट 6 इंच","15 फीट"],"explanation":"ओरेगन किसी भी लोड सहित अधिकतम ऊँचाई 14 फीट निर्धारित करता है; इससे अधिक होने पर ओवर-डाइमेंशन परमिट और मार्ग क्लीयरेंस आवश्यक है। स्रोत: ORS 818.080 और Oregon DOT Legal Vehicle Dimensions।"},"2":{"q":"विशेष लंबाई परमिट के बिना, ओरेगन के सामान्य राजमार्गों पर अधिकांश ट्रक-ट्रैक्टर और सेमीट्रेलर संयोजनों की अधिकतम समग्र लंबाई क्या है?","options":["50 फीट","55 फीट","60 फीट","75 फीट"],"explanation":"ओरेगन के सामान्य राजमार्गों पर वाहनों के संयोजन के लिए अधिकतम समग्र लंबाई 60 फीट है; लंबे संयोजनों की अनुमति केवल निर्दिष्ट मार्गों पर या परमिट के तहत है। स्रोत: ORS 818.080 और Oregon DOT Legal Vehicle Dimensions।"},"3":{"q":"ओरेगन के निर्दिष्ट मार्गों पर जो असीमित समग्र लंबाई की अनुमति देते हैं, ट्रैक्टर-सेमीट्रेलर संयोजन में एक एकल सेमीट्रेलर की अधिकतम लंबाई क्या है?","options":["48 फीट","53 फीट","57 फीट","60 फीट"],"explanation":"ओरेगन अधिकतम सेमीट्रेलर लंबाई 53 फीट की अनुमति देता है; निर्दिष्ट मार्गों पर समग्र संयोजन लंबाई असीमित हो सकती है, लेकिन सेमीट्रेलर स्वयं 53 फीट से अधिक नहीं हो सकता। स्रोत: ORS 818.080 और Oregon DOT Legal Vehicle Dimensions।"},"4":{"q":"परमिट के बिना ओरेगन के राजमार्गों पर एक एकल (सोलो) वाहन की अधिकतम लंबाई क्या है?","options":["35 फीट","40 फीट","45 फीट","53 फीट"],"explanation":"ओरेगन में अकेले चलने वाला एक एकल वाहन परमिट के बिना लंबाई में 40 फीट से अधिक नहीं हो सकता। स्रोत: ORS 818.080 (अधिकतम आकार सीमाएँ)।"},"5":{"q":"ओरेगन में, ओवरवेट परमिट के बिना किसी भी एकल एक्सल पर अधिकतम अनुमेय भार क्या है?","options":["18,000 पाउंड","20,000 पाउंड","22,400 पाउंड","34,000 पाउंड"],"explanation":"ओरेगन किसी भी एकल एक्सल को 20,000 पाउंड तक सीमित करता है। स्रोत: ORS 818.010 (अधिकतम अनुमेय भार)।"},"6":{"q":"ओवरवेट परमिट के बिना ओरेगन में एक टैंडेम एक्सल समूह पर अधिकतम अनुमेय भार क्या है?","options":["32,000 पाउंड","34,000 पाउंड","36,000 पाउंड","40,000 पाउंड"],"explanation":"ओरेगन एक टैंडेम एक्सल (दो एक्सल) को 34,000 पाउंड तक सीमित करता है, जो संघीय मानक से मेल खाता है। स्रोत: ORS 818.010 (अधिकतम अनुमेय भार)।"},"7":{"q":"ओवरवेट या एक्सटेंडेड-वेट परमिट के बिना ओरेगन के राजमार्गों पर आमतौर पर अनुमत अधिकतम सकल वाहन भार क्या है?","options":["73,280 पाउंड","80,000 पाउंड","88,000 पाउंड","105,500 पाउंड"],"explanation":"ओरेगन में मानक अधिकतम सकल संयोजन भार 80,000 पाउंड है; भारी विभाज्य लोड के लिए ODOT एक्सटेंडेड वेट परमिट आवश्यक है। स्रोत: ORS 818.010 और Oregon DOT Commerce and Compliance Division।"},"8":{"q":"ODOT एक्सटेंडेड (विभाज्य लोड) वेट परमिट के तहत, ओरेगन में एक योग्य वाहन अधिकतम कितना सकल संयोजन भार ढो सकता है?","options":["90,000 पाउंड","98,000 पाउंड","105,500 पाउंड","129,000 पाउंड"],"explanation":"ओरेगन का एक्सटेंडेड वेट परमिट विभाज्य लोड ढोते समय योग्य बहु-एक्सल संयोजनों को 105,500 पाउंड सकल भार तक संचालित करने की अनुमति देता है। स्रोत: Oregon DOT Commerce and Compliance Division, Extended Weight (Divisible Load) Permit।"},"9":{"q":"ओरेगन कानून टायर की चौड़ाई के आधार पर टायरों पर ढोए जा सकने वाले भार को सीमित करता है। टायर की चौड़ाई के प्रति इंच अधिकतम कितने पाउंड की अनुमति है?","options":["500 पाउंड प्रति इंच","550 पाउंड प्रति इंच","600 पाउंड प्रति इंच","650 पाउंड प्रति इंच"],"explanation":"ओरेगन निर्माता की साइडवॉल टायर रेटिंग का उपयोग करता है, लेकिन टायर की चौड़ाई के प्रति इंच 600 पाउंड से अधिक नहीं, जिसे टायर चौड़ाइयों के योग से गुणा किया जाता है। स्रोत: ORS 818.010 (अधिकतम अनुमेय भार)।"},"10":{"q":"ओरेगन लगातार एक्सल के समूह पर उनके अंतराल के आधार पर अनुमत अधिकतम सकल भार निर्धारित करने के लिए कौन सा सूत्र लागू करता है?","options":["फेडरल ब्रिज फॉर्मूला (Bridge Gross Weight Formula)","GAWR रेटिंग सूत्र","ओरेगन माइलेज-टैक्स सूत्र","कार्गो सिक्योरमेंट फॉर्मूला"],"explanation":"ओरेगन फेडरल ब्रिज फॉर्मूला, W = 500[LN/(N-1) + 12N + 36], को अपनाता है ताकि एक्सल अंतराल और एक्सल की संख्या के आधार पर दो या अधिक लगातार एक्सल के किसी भी समूह पर भार को सीमित किया जा सके। स्रोत: ORS 818.010 और 23 CFR 658 जैसा कि Oregon DOT द्वारा लागू किया गया है।"},"11":{"q":"ओरेगन में उपयोग किए जाने वाले फेडरल ब्रिज फॉर्मूला में, चर 'L' किसका प्रतिनिधित्व करता है?","options":["टन में कानूनी भार सीमा","समूह के बाहरी एक्सल के बीच फीट में दूरी","फीट में ट्रेलर की लंबाई","आवश्यक लाइसेंस प्लेटों की संख्या"],"explanation":"ब्रिज फॉर्मूला W = 500[LN/(N-1) + 12N + 36] में, L समूह के सबसे बाहरी एक्सल के बीच फीट में दूरी है, N एक्सल की संख्या है, और W अनुमेय सकल भार है। स्रोत: फेडरल ब्रिज फॉर्मूला जैसा कि Oregon DOT द्वारा लागू किया गया है; ORS 818.010।"},"12":{"q":"वाणिज्यिक वाहन के लिए Oregon DOT ओवर-डाइमेंशन या ओवरवेट परमिट कब आवश्यक होता है?","options":["केवल जब राज्य की सीमा पार करते हैं","जब भी वाहन या लोड कानूनी आकार या भार सीमाओं से अधिक हो","केवल सप्ताहांत और छुट्टियों पर","केवल राज्य के बाहर पंजीकृत वाहनों के लिए"],"explanation":"कोई भी वाहन या लोड जो चौड़ाई, ऊँचाई, लंबाई या भार के लिए ओरेगन की कानूनी सीमाओं से अधिक हो, उसे संचालन से पहले ओवर-डाइमेंशन/ओवरवेट परमिट प्राप्त करना होगा। स्रोत: ORS 818.200 और Oregon DOT Commerce and Compliance Division, Over-Dimension Operations।"},"13":{"q":"कौन सी ओरेगन एजेंसी वाणिज्यिक वाहनों के लिए ओवरसाइज और ओवरवेट (ओवर-डाइमेंशन) परमिट जारी करती है?","options":["Oregon State Police","Oregon DOT Commerce and Compliance Division","काउंटी शेरिफ का कार्यालय","Federal Motor Carrier Safety Administration"],"explanation":"ओरेगन में ओवर-डाइमेंशन और ओवरवेट परमिट Oregon Department of Transportation के Commerce and Compliance Division (पूर्व में Motor Carrier Transportation Division) द्वारा जारी किए जाते हैं, जो ऑनलाइन या प्रवेश बंदरगाहों पर उपलब्ध हैं। स्रोत: Oregon DOT Commerce and Compliance Division।"},"14":{"q":"ओरेगन किसी भी व्यक्तिगत पहिए पर अधिकतम कितना भार अनुमति देता है?","options":["8,000 पाउंड","10,000 पाउंड","12,000 पाउंड","17,000 पाउंड"],"explanation":"ओरेगन किसी भी व्यक्तिगत पहिए पर भार को 10,000 पाउंड तक सीमित करता है। स्रोत: ORS 818.010 (अधिकतम अनुमेय भार)।"},"15":{"q":"ओरेगन की 80,000-पाउंड सीमा से अधिक एक 'विभाज्य लोड' वह है जो:","options":["अत्यधिक खर्च या क्षति के जोखिम के बिना अलग नहीं किया जा सकता","उचित रूप से छोटे, कानूनी लोड में विभाजित किया जा सकता है","हमेशा खतरनाक सामग्री के रूप में वर्गीकृत किया जाता है","केवल रात में ढोया जाना चाहिए"],"explanation":"एक विभाज्य लोड को उचित रूप से छोटे कानूनी लोड में तोड़ा जा सकता है; ओरेगन में ऐसे लोड केवल ODOT एक्सटेंडेड (विभाज्य लोड) वेट परमिट के तहत ही 80,000 पाउंड से अधिक हो सकते हैं, जबकि गैर-विभाज्य लोड ओवर-डाइमेंशन वैरिएंस परमिट का उपयोग करते हैं। स्रोत: Oregon DOT Commerce and Compliance Division।"},"16":{"q":"परमिट के बिना, ओरेगन में किसी वाहन के आगे (FRONT) से अधिकतम कितना लोड ओवरहैंग अनुमत है?","options":["3 फीट","4 फीट","5 फीट","6 फीट"],"explanation":"ओरेगन परमिट के बिना अधिकतम सामने (फ्रंट) लोड ओवरहैंग 4 फीट की अनुमति देता है; अधिक फ्रंट ओवरहैंग के लिए ओवर-डाइमेंशन परमिट और फ्लैगिंग आवश्यक है। स्रोत: ORS 818.080 और Oregon DOT Legal Vehicle Dimensions।"},"17":{"q":"ओरेगन में लागू फेडरल ब्रिज फॉर्मूला में, एक्सल की संख्या समान रखते हुए, समूह के बाहरी एक्सल के बीच के अंतराल को बढ़ाने से आमतौर पर:","options":["अनुमेय सकल भार घटता है","अनुमेय भार पर कोई प्रभाव नहीं पड़ता","अनुमेय सकल भार बढ़ता है","ट्रक का पंजीकरण अमान्य हो जाता है"],"explanation":"चूँकि L (एक्सल अंतराल) अंश में है, बाहरी एक्सल के बीच अधिक दूरी उस एक्सल समूह के लिए अनुमेय सकल भार को बढ़ाती है; पुलों की रक्षा के लिए निकट दूरी वाले एक्सल सीमित होते हैं। स्रोत: फेडरल ब्रिज फॉर्मूला जैसा कि Oregon DOT द्वारा लागू किया गया है; ORS 818.010।"},"18":{"q":"ओरेगन किस प्रकार की ढुलाई के लिए कुछ भार छूट और कम-शुल्क परमिट प्रदान करता है जो राज्य की अर्थव्यवस्था के लिए महत्वपूर्ण है?","options":["पैसेंजर चार्टर बसें","कृषि और वन (लॉग) उत्पादों की ढुलाई","अंतरराज्यीय पैकेज डिलीवरी वैन","किराये के मूविंग ट्रक"],"explanation":"ओरेगन कृषि वस्तुओं और वन/लॉग उत्पादों के लिए विशिष्ट परमिट और भार प्रावधान प्रदान करता है (जैसे कम या पंजीकरण-भार छूट और एक्सटेंडेड-वेट लॉग परमिट) जो राज्य के लिए खेती और लकड़ी के महत्व को दर्शाता है। स्रोत: Oregon DOT Commerce and Compliance Division और ORS Chapter 818 परमिट प्रावधान।"},"19":{"q":"ओरेगन में, 26,001 पाउंड या उससे अधिक के Gross Combination Weight Rating (GCWR) वाले वाहनों के किसी भी संयोजन को चलाने के लिए कौन सा CDL वर्ग आवश्यक है, बशर्ते खींचा जा रहा वाहन 10,000 पाउंड से भारी हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"ओरेगन मानक CDL वर्गों का पालन करता है: एक Class A CDL 26,001 पाउंड या उससे अधिक के GCWR वाले वाहनों के किसी भी संयोजन को कवर करता है जहाँ खींची गई इकाई 10,000 पाउंड से अधिक हो। स्रोत: Oregon Commercial Driver Manual / Oregon DMV Driver License Classes (49 CFR 383.91 का प्रतिबिंब; ORS 807.031)।"},"20":{"q":"ओरेगन के नियमों के तहत, कौन सा CDL वर्ग 26,001 पाउंड या उससे अधिक के Gross Vehicle Weight Rating (GVWR) वाले एकल वाहन को, या ऐसे वाहन को जो 10,000 पाउंड से अधिक न होने वाली इकाई खींच रहा हो, कवर करता है?","options":["Class A","Class B","Class C","Class M"],"explanation":"ओरेगन में एक Class B CDL 26,001 पाउंड या उससे अधिक के GVWR वाले एकल वाहन को, या ऐसे वाहन को जो 10,000 पाउंड से अधिक न होने वाला ट्रेलर खींच रहा हो, कवर करता है। स्रोत: Oregon Commercial Driver Manual / Oregon DMV Driver License Classes (49 CFR 383.91)।"},"21":{"q":"ओरेगन में, एक छोटा वाहन जो Class A या Class B की भार सीमाओं को पूरा नहीं करता, फिर भी Class C CDL की आवश्यकता होती है यदि इसे चालक सहित कम से कम कितने लोगों को ले जाने के लिए डिज़ाइन किया गया हो?","options":["10","12","16","24"],"explanation":"एक Class C CDL एक वाहन (जो Class A या B को पूरा नहीं करता) के लिए आवश्यक है जिसे चालक सहित 16 या अधिक व्यक्तियों को ले जाने के लिए डिज़ाइन किया गया हो, या जिसका उपयोग प्लेकार्ड वाली खतरनाक सामग्री के परिवहन के लिए किया जाता हो। स्रोत: Oregon Commercial Driver Manual / Oregon DMV Driver License Classes (49 CFR 383.91)।"},"22":{"q":"16 या अधिक यात्रियों को ले जाने के अलावा, वह दूसरी शर्त क्या है जिसके लिए ओरेगन में एक ऐसे वाहन के लिए Class C CDL आवश्यक है जो Class A या B होने के लिए बहुत छोटा है?","options":["5,000 पाउंड से अधिक का कोई भी ट्रेलर खींचना","प्लेकार्ड की आवश्यकता वाली मात्रा में खतरनाक सामग्री का परिवहन","राज्य राजमार्ग पर अंधेरे के बाद संचालन","किराये के लिए कोई भी कृषि उत्पाद ले जाना"],"explanation":"ओरेगन एक छोटे वाहन के लिए Class C CDL की आवश्यकता रखता है जिसका उपयोग प्लेकार्ड की आवश्यकता वाली मात्रा में खतरनाक सामग्री के परिवहन के लिए किया जाता है (या 16+ व्यक्तियों को ले जाने के लिए)। स्रोत: Oregon Commercial Driver Manual; Oregon DMV CDL Classes (49 CFR 383.91)।"},"23":{"q":"CDL पर Hazardous Materials एंडोर्समेंट के लिए ओरेगन किस एंडोर्समेंट कोड का उपयोग करता है?","options":["H","N","T","X"],"explanation":"ओरेगन में Hazardous Materials एंडोर्समेंट को 'H' कोडित किया जाता है। (कोड 'X' एक संयुक्त Tank और HazMat एंडोर्समेंट का प्रतिनिधित्व करता है।) स्रोत: Oregon DMV CDL Endorsements & Restrictions; Oregon Commercial Driver Manual।"},"24":{"q":"एक ओरेगन चालक को डबल या ट्रिपल ट्रेलर खींचने वाला वाणिज्यिक वाहन चलाने की आवश्यकता है। कौन सा एंडोर्समेंट आवश्यक है?","options":["P एंडोर्समेंट","N एंडोर्समेंट","T एंडोर्समेंट","S एंडोर्समेंट"],"explanation":"ओरेगन में डबल या ट्रिपल ट्रेलर खींचने वाले किसी भी वाणिज्यिक मोटर वाहन को चलाने के लिए 'T' (Doubles/Triples) एंडोर्समेंट आवश्यक है, और यह एक ज्ञान परीक्षा पास करके प्राप्त किया जाता है। स्रोत: Oregon DMV CDL Endorsements; Oregon Commercial Driver Manual।"},"25":{"q":"ओरेगन में, Tank Vehicle (N) एंडोर्समेंट तब आवश्यक होता है जब एक CMV को व्यक्तिगत रूप से 119 गैलन से अधिक रेटेड टैंक में तरल या गैस ढोने के लिए डिज़ाइन किया गया हो और कुल रेटेड क्षमता कम से कम कितने गैलन हो?","options":["500 गैलन","750 गैलन","1,000 गैलन","1,500 गैलन"],"explanation":"ओरेगन एक ऐसे वाहन के लिए N (Tank) एंडोर्समेंट की आवश्यकता रखता है जो व्यक्तिगत रूप से 119 गैलन से अधिक रेटेड टैंक में 1,000 गैलन या अधिक की कुल रेटेड क्षमता के साथ तरल या गैस का परिवहन करता है। स्रोत: Oregon Commercial Driver Manual; Oregon DMV CDL Endorsements (49 CFR 383.5)।"},"26":{"q":"चालक सहित 16 या अधिक लोगों को ले जाने के लिए डिज़ाइन किए गए वाहन को चलाने के लिए कौन सा ओरेगन CDL एंडोर्समेंट आवश्यक है?","options":["P (Passenger)","S (School Bus)","T (Doubles/Triples)","N (Tank)"],"explanation":"ओरेगन में चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किए गए वाहन को संचालित करने के लिए 'P' (Passenger) एंडोर्समेंट आवश्यक है; इसके लिए एक ज्ञान और एक कौशल परीक्षा आवश्यक है। स्रोत: Oregon DMV CDL Endorsements; Oregon Commercial Driver Manual।"},"27":{"q":"ओरेगन में स्कूल बस चलाने के लिए, पैसेंजर-वाहन आवश्यकताओं को पूरा करने के अलावा एक CDL धारक को कौन सा एंडोर्समेंट जोड़ना होगा?","options":["H एंडोर्समेंट","S एंडोर्समेंट","T एंडोर्समेंट","X एंडोर्समेंट"],"explanation":"ओरेगन में स्कूल बस चलाने के लिए 'S' (School Bus) एंडोर्समेंट आवश्यक है; आवेदक के पास P एंडोर्समेंट भी होना चाहिए और एक स्कूल-बस ज्ञान और कौशल परीक्षा पास करनी होगी। स्रोत: Oregon DMV CDL Endorsements; Oregon Commercial Driver Manual।"},"28":{"q":"अंतरराज्यीय (केवल ओरेगन में) वाणिज्यिक ड्राइविंग तक सीमित ओरेगन CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["16 वर्ष","18 वर्ष","21 वर्ष","25 वर्ष"],"explanation":"ओरेगन इंट्रास्टेट CDL के लिए आवेदक को कम से कम 18 वर्ष का होने की आवश्यकता रखता है; इंटरस्टेट ड्राइविंग के लिए आयु 21 आवश्यक है। स्रोत: Oregon DMV 'Getting a CDL or CLP'; Oregon Commercial Driver Manual।"},"29":{"q":"ओरेगन के नियमों के तहत, अंतरराज्यीय वाणिज्य में वाणिज्यिक मोटर वाहन चलाने के लिए न्यूनतम आयु क्या है?","options":["18 वर्ष","19 वर्ष","21 वर्ष","23 वर्ष"],"explanation":"ओरेगन इंटरस्टेट वाणिज्य में CMV संचालित करने के लिए चालक को कम से कम 21 वर्ष का होने की आवश्यकता रखता है; केवल इंट्रास्टेट संचालन की अनुमति 18 वर्ष में दी जाती है। स्रोत: Oregon DMV 'Getting a CDL or CLP'; Oregon Commercial Driver Manual।"},"30":{"q":"ओरेगन में, CDL कौशल परीक्षा लेने की अनुमति मिलने से पहले एक व्यक्ति को कब तक एक वैध Commercial Learner Permit (CLP) रखना होगा?","options":["कम से कम 7 दिन","कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 60 दिन"],"explanation":"ओरेगन आवेदक को CDL कौशल परीक्षा लेने से पहले कम से कम 14 दिनों तक एक वैध CLP रखने की आवश्यकता रखता है, जो संघीय अनिवार्य होल्ड अवधि को दर्शाता है। स्रोत: Oregon Commercial Driver Manual (Oregon Information); Oregon DMV (49 CFR 383.25)।"},"31":{"q":"CDL की दिशा में काम करते समय ओरेगन में वाणिज्यिक ज्ञान परीक्षा के अंक कब तक वैध रहते हैं?","options":["तीन महीने","छह महीने","एक वर्ष","दो वर्ष"],"explanation":"ओरेगन कहता है कि वाणिज्यिक ज्ञान परीक्षा के अंक छह महीने के लिए वैध हैं; CDL आवेदन उस अवधि के भीतर पूरा किया जाना चाहिए। स्रोत: Oregon Commercial Driver Manual (Oregon Information); Oregon DMV 'Getting a CDL or CLP'।"},"32":{"q":"CDL या CLP के लिए आवेदन करते समय एक आवेदक को Oregon DMV को निम्नलिखित में से क्या प्रस्तुत करना होगा?","options":["केवल एक नोटरीकृत नियोक्ता पत्र","पूर्ण कानूनी नाम, पहचान, जन्म तिथि, वैध U.S. स्थिति, निवास पता और एक Social Security Number का प्रमाण","एक पासपोर्ट और कुछ नहीं","एक हाई स्कूल डिप्लोमा और दो संदर्भ"],"explanation":"Oregon DMV को पूर्ण कानूनी नाम, पहचान, जन्म तिथि, U.S. में वैध स्थिति, ओरेगन निवास पता और आवेदक के Social Security Number के प्रमाण की आवश्यकता होती है। स्रोत: Oregon Commercial Driver Manual (Oregon Information); Oregon DMV 'Getting a CDL or CLP'।"},"33":{"q":"ओरेगन में पहली Class A या Class B लाइसेंस के लिए CDL कौशल परीक्षा लेने से पहले, एक आवेदक को Entry-Level Driver Training (ELDT) कहाँ पूरा करना होगा?","options":["कोई भी सामुदायिक कॉलेज पाठ्यक्रम","FMCSA Training Provider Registry पर सूचीबद्ध एक प्रदाता","एक Oregon DMV फील्ड कार्यालय","किसी भी प्रकार का नियोक्ता का इन-हाउस कार्यक्रम"],"explanation":"ओरेगन पहली Class A/B CDL, B-to-A अपग्रेड, या पहली P, S, या H एंडोर्समेंट के लिए कौशल परीक्षा शेड्यूल करने से पहले FMCSA की Training Provider Registry (tpr.fmcsa.dot.gov) पर सूचीबद्ध एक प्रदाता से ELDT की आवश्यकता रखता है। स्रोत: Oregon Commercial Driver Manual; Oregon DMV (49 CFR Part 380)।"},"34":{"q":"ओरेगन में पहली बार इनमें से किस एंडोर्समेंट के लिए परीक्षा देने से पहले ELDT आवश्यक है?","options":["Doubles/Triples (T)","Tank (N)","Hazardous Materials (H)","किसी भी एंडोर्समेंट के लिए ELDT आवश्यक नहीं"],"explanation":"ओरेगन पहली बार HazMat (H) ज्ञान परीक्षा लेने से पहले ELDT की आवश्यकता रखता है, साथ ही पहली P या S एंडोर्समेंट और पहली Class A/B CDL के लिए भी। T और N एंडोर्समेंट ELDT सूची में नहीं हैं। स्रोत: Oregon DMV; Oregon Commercial Driver Manual (49 CFR Part 380)।"},"35":{"q":"एक ओरेगन CDL आवेदक जो केवल ओरेगन के भीतर ड्राइव करेगा और संघीय चिकित्सा नियमों के अधीन नहीं है, उसे किस श्रेणी के तहत स्व-प्रमाणन करना चाहिए?","options":["Non-excepted Interstate (NI)","Excepted Interstate (EI)","Non-excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"ओरेगन स्व-प्रमाणन प्रकार प्रदान करता है; एक चालक जो केवल इंट्रास्टेट वाणिज्य में Class A, B, या C CMV संचालित करता है, वह Non-excepted Intrastate प्रमाणित करता है और उसे पूर्ण संघीय मानकों के बजाय ओरेगन CDL चिकित्सा मानकों को पूरा करना होगा। स्रोत: Oregon DMV CDL Medical/Self-Certification; Oregon Commercial Driver Manual।"},"36":{"q":"Oregon DMV अधिकांश CDL चालकों के लिए किस स्व-प्रमाणन श्रेणी की सिफारिश करता है ताकि उनका लाइसेंस अनावश्यक रूप से केवल ओरेगन-उपयोग तक सीमित न हो?","options":["Excepted Interstate","Non-excepted Interstate","Non-excepted Intrastate","Excepted Intrastate"],"explanation":"Oregon DMV अधिकांश चालकों को Non-excepted Interstate प्रमाणित करने की सिफारिश करता है, जिसके लिए सभी संघीय चिकित्सा योग्यताओं को पूरा करना आवश्यक है और जो excepted-interstate तथा intrastate संचालन की भी अनुमति देता है। स्रोत: Oregon DMV CDL Self-Certification; Oregon Commercial Driver Manual।"},"37":{"q":"एक ओरेगन HazMat (H) एंडोर्समेंट प्राप्त करने और बनाए रखने के लिए, एक चालक को Transportation Security Administration (TSA) सुरक्षा खतरा मूल्यांकन पास करना होगा, जिसमें फिंगरप्रिंटिंग शामिल है, जिसे कितनी बार नवीनीकृत करना होगा?","options":["हर 2 वर्ष","हर 3 वर्ष","हर 5 वर्ष","हर 8 वर्ष"],"explanation":"ओरेगन के HazMat एंडोर्समेंट के लिए फिंगरप्रिंट-आधारित पृष्ठभूमि जाँच के साथ एक TSA सुरक्षा खतरा मूल्यांकन आवश्यक है जिसे हर पाँच वर्ष में नवीनीकृत किया जाना चाहिए। स्रोत: Oregon DMV CDL Endorsements & Restrictions (49 CFR 1572)।"},"38":{"q":"ओरेगन में Excepted Interstate के रूप में स्व-प्रमाणन करने वाले चालक को फिर भी किस चिकित्सा मानक को पूरा करना होगा?","options":["कोई चिकित्सा मानक बिल्कुल नहीं","पूर्ण संघीय इंटरस्टेट चिकित्सा मानक","ओरेगन CDL चिकित्सा मानक","केवल नवीनीकरण पर एक दृष्टि जाँच"],"explanation":"एक ओरेगन चालक जो Excepted Interstate प्रमाणित करता है, वह केवल संघीय नियमों के तहत छूट प्राप्त संचालन (जैसे 49 CFR 390.3(f), 391.2) में संलग्न होता है और उसे पूर्ण संघीय चिकित्सा मानकों के अधीन नहीं रखा जाता, लेकिन उसे फिर भी ओरेगन CDL चिकित्सा मानकों को पूरा करना होगा। स्रोत: Oregon DMV CDL Self-Certification; Oregon Commercial Driver Manual।"},"39":{"q":"ओरेगन में, रक्त अल्कोहल सांद्रता (BAC) किस स्तर पर या उससे ऊपर वाणिज्यिक मोटर वाहन (CMV) चलाना अवैध है?","options":["0.08%","0.04%","0.02%","0.10%"],"explanation":"ओरेगन संघीय CMV मानक को अपनाता है: 0.04% या अधिक BAC के साथ CMV संचालित करना अवैध है, जो गैर-वाणिज्यिक चालकों के लिए 0.08% सीमा का आधा है। स्रोत: Oregon Commercial Driver Manual, Section 1 (Disqualifications); 49 CFR 383.51।"},"40":{"q":"वाणिज्यिक चालकों के लिए ओरेगन के निहित-सहमति नियम के तहत, जब आप एक CMV संचालित करते हैं तो क्या सत्य है?","options":["आप बिना किसी दंड के सभी परीक्षण से इनकार कर सकते हैं","माना जाता है कि आपने अल्कोहल परीक्षण के लिए सहमति दी है","परीक्षण के लिए प्रत्येक यात्रा पर एक अलग हस्ताक्षरित छूट की आवश्यकता होती है","सहमति केवल 0.08% BAC से ऊपर लागू होती है"],"explanation":"Oregon CDL Manual कहता है कि एक CMV संचालित करके माना जाता है कि आपने अल्कोहल परीक्षण के लिए सहमति दी है। परीक्षण से इनकार करने पर एक प्रमुख अपराध के समान अयोग्यता होती है। स्रोत: Oregon Commercial Driver Manual, Section 1; ORS 813.100।"},"41":{"q":"एक ओरेगन CDL धारक को पहली बार 0.04% या अधिक BAC के साथ CMV चलाने के लिए दोषी ठहराया जाता है, खतरनाक सामग्री नहीं ले जा रहा। न्यूनतम अयोग्यता अवधि क्या है?","options":["60 दिन","90 दिन","1 वर्ष","3 वर्ष"],"explanation":"एक पहला प्रमुख अपराध, जिसमें 0.04% या अधिक का CMV BAC शामिल है, ओरेगन में चालक को कम से कम 1 वर्ष के लिए अयोग्य ठहराता है। स्रोत: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51।"},"42":{"q":"यदि एक पहला प्रमुख अपराध (जैसे 0.04% BAC) तब होता है जब चालक खतरनाक सामग्री के लिए प्लेकार्ड वाली CMV संचालित कर रहा हो, तो न्यूनतम ओरेगन अयोग्यता क्या है?","options":["1 वर्ष","18 महीने","3 वर्ष","5 वर्ष"],"explanation":"जब खतरनाक सामग्री के लिए प्लेकार्ड वाली CMV में पहला प्रमुख अपराध होता है, तो अयोग्यता बढ़कर कम से कम 3 वर्ष हो जाती है। स्रोत: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51।"},"43":{"q":"एक CDL धारक द्वारा किए गए दूसरे प्रमुख अपराध के लिए ओरेगन अयोग्यता क्या है?","options":["3 वर्ष","5 वर्ष","10 वर्ष","आजीवन"],"explanation":"एक दूसरा प्रमुख अपराध (उदाहरण के लिए, CMV में दूसरा DUI, या पूर्व अपराध के बाद एक प्रमुख अपराध) ओरेगन में आजीवन CDL अयोग्यता में परिणत होता है। स्रोत: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51।"},"44":{"q":"एक ओरेगन CDL धारक एक CMV संचालित करते समय अल्कोहल परीक्षण के लिए प्रस्तुत होने से इनकार करता है (पहली घटना)। अयोग्यता उद्देश्यों के लिए इसे कैसे माना जाता है?","options":["कोई CDL दंड नहीं, केवल जुर्माना","एक प्रमुख अपराध के रूप में माना जाता है: कम से कम 1-वर्ष की अयोग्यता","30-दिन की अयोग्यता","एक गंभीर उल्लंघन के रूप में माना जाता है: 60 दिन"],"explanation":"अल्कोहल परीक्षण से इनकार करना प्रमुख अपराधों में सूचीबद्ध है और इसमें कम से कम 1-वर्ष की अयोग्यता होती है (हैज़मैट के लिए प्लेकार्ड होने पर 3 वर्ष), जो एक BAC विफलता के समान है। स्रोत: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51; ORS 813.100।"},"45":{"q":"एक ओरेगन CDL धारक एक नियंत्रित पदार्थ से जुड़े अपराध (निर्माण, वितरण या वितरण) करने के लिए एक CMV का उपयोग करता है। अयोग्यता क्या है?","options":["1 वर्ष","3 वर्ष","10 वर्ष","आजीवन, बिना पुनर्बहाली के"],"explanation":"नियंत्रित पदार्थों से जुड़े अपराध करने के लिए CMV का उपयोग करने से बिना पुनर्बहाली की संभावना के आजीवन अयोग्यता होती है। स्रोत: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51।"},"46":{"q":"ओरेगन में एक CDL चालक के बारे में पाया जाता है कि ड्यूटी पर रहते हुए उसके पास 0.04% से कम पता लगाने योग्य मात्रा में अल्कोहल है। क्या होता है?","options":["कुछ नहीं, यह कानूनी सीमा के अंतर्गत है","24 घंटे के लिए आउट-ऑफ-सर्विस रखा जाता है","1-वर्ष की अयोग्यता","1 घंटे के लिए आउट-ऑफ-सर्विस रखा जाता है"],"explanation":"0.04% से कम कोई भी पता लगाने योग्य अल्कोहल एक प्रमुख-अपराध अयोग्यता को ट्रिगर नहीं करता लेकिन चालक को 24 घंटे के लिए आउट-ऑफ-सर्विस रखता है। स्रोत: Oregon Commercial Driver Manual, Section 1; 49 CFR 392.5।"},"47":{"q":"एक ओरेगन CDL धारक के लिए निम्नलिखित में से किसे 'गंभीर यातायात उल्लंघन' के रूप में वर्गीकृत किया जाता है?","options":["नो-पार्किंग ज़ोन में पार्किंग","अत्यधिक तेज़ गति, सीमा से 15 mph या अधिक","एक खराब मार्कर लैंप","सीमा से 5 mph तेज़ गति से चलना"],"explanation":"गंभीर यातायात उल्लंघनों में अत्यधिक तेज़ गति शामिल है जिसे पोस्ट की गई सीमा से 15 mph या अधिक के रूप में परिभाषित किया गया है, लापरवाह ड्राइविंग, अनुचित या अनियमित लेन परिवर्तन, और बहुत निकट से पीछा करना। स्रोत: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51।"},"48":{"q":"ओरेगन में 3-वर्ष की अवधि के भीतर कितने गंभीर यातायात उल्लंघन एक अयोग्यता को ट्रिगर करते हैं, और ऐसी पहली अयोग्यता कितने समय के लिए होती है?","options":["1 उल्लंघन; 30 दिन","2 उल्लंघन; कम से कम 60 दिन","2 उल्लंघन; कम से कम 30 दिन","3 उल्लंघन; कम से कम 60 दिन"],"explanation":"3 वर्ष के भीतर दो गंभीर यातायात उल्लंघन कम से कम 60 दिनों की अयोग्यता में परिणत होते हैं। स्रोत: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51।"},"49":{"q":"एक ओरेगन CDL धारक 3-वर्ष की अवधि के भीतर तीन गंभीर यातायात उल्लंघन करता है। न्यूनतम अयोग्यता क्या है?","options":["60 दिन","90 दिन","120 दिन","1 वर्ष"],"explanation":"3 वर्ष के भीतर तीन या अधिक गंभीर यातायात उल्लंघन कम से कम 120 दिनों की अयोग्यता में परिणत होते हैं। स्रोत: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51।"},"50":{"q":"क्या गंभीर यातायात उल्लंघन CDL अयोग्यता की ओर गिने जाते हैं जब वे चालक के व्यक्तिगत (गैर-वाणिज्यिक) वाहन में किए जाते हैं?","options":["नहीं, केवल CMV में उल्लंघन गिने जाते हैं","हाँ, यदि उनके परिणामस्वरूप लाइसेंस निलंबन या निरस्तीकरण होता है","केवल यदि अल्कोहल शामिल हो","केवल अंतरराज्यीय राजमार्गों पर उल्लंघन गिने जाते हैं"],"explanation":"गैर-CMV में किए गए गंभीर यातायात उल्लंघन एक CDL धारक के विरुद्ध गिने जाते हैं यदि दोषसिद्धि के परिणामस्वरूप चालक के लाइसेंस का निलंबन या निरस्तीकरण होता है। स्रोत: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51।"},"51":{"q":"3 वर्ष के भीतर दूसरे रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए, न्यूनतम ओरेगन अयोग्यता क्या है?","options":["60 दिन","120 दिन","180 दिन","1 वर्ष"],"explanation":"3-वर्ष की अवधि के भीतर दूसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन कम से कम 120 दिनों की अयोग्यता में परिणत होता है। स्रोत: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51।"},"52":{"q":"3-वर्ष की अवधि के भीतर तीसरे रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए न्यूनतम ओरेगन अयोग्यता क्या है?","options":["120 दिन","180 दिन","1 वर्ष","3 वर्ष"],"explanation":"3 वर्ष के भीतर तीसरा या उसके बाद का रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन कम से कम 1 वर्ष की अयोग्यता में परिणत होता है। स्रोत: Oregon Commercial Driver Manual, Section 1; 49 CFR 383.51।"},"53":{"q":"एक ओरेगन CDL धारक पहली बार आउट-ऑफ-सर्विस आदेश का उल्लंघन करता है जबकि खतरनाक सामग्री या यात्रियों का परिवहन नहीं कर रहा। न्यूनतम अयोग्यता क्या है?","options":["60 दिन","90 दिन","180 दिन","1 वर्ष"],"explanation":"एक पहला आउट-ऑफ-सर्विस आदेश उल्लंघन (गैर-हैज़मैट, गैर-यात्री) कम से कम 180 दिनों की अयोग्यता में परिणत होता है। स्रोत: Oregon Commercial Driver Manual, Section 1 / ODOT Commercial Driver Convictions page; 49 CFR 383.51।"},"54":{"q":"एक चालक पहली बार आउट-ऑफ-सर्विस आदेश का उल्लंघन करता है जबकि खतरनाक सामग्री का परिवहन कर रहा है (या 16+ यात्रियों के लिए डिज़ाइन किया गया वाहन चला रहा है)। न्यूनतम ओरेगन अयोग्यता क्या है?","options":["180 दिन","1 वर्ष","3 वर्ष","5 वर्ष"],"explanation":"हैज़मैट ढोते समय या 16-या-अधिक-यात्री वाहन संचालित करते समय एक पहला आउट-ऑफ-सर्विस उल्लंघन कम से कम 1 वर्ष की अयोग्यता में परिणत होता है, जो 180-दिन की आधार रेखा से अधिक है। स्रोत: ODOT Commercial Driver Convictions page; 49 CFR 383.51।"},"55":{"q":"10 वर्ष के भीतर दूसरे आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए न्यूनतम अयोग्यता क्या है, जिसमें हैज़मैट या यात्री शामिल नहीं हैं?","options":["1 वर्ष","2 वर्ष","3 वर्ष","5 वर्ष"],"explanation":"10 वर्ष के भीतर एक दूसरा आउट-ऑफ-सर्विस उल्लंघन (गैर-हैज़मैट, गैर-यात्री) कम से कम 3 वर्ष की अयोग्यता में परिणत होता है; यदि हैज़मैट या यात्री शामिल थे तो यह बढ़कर कम से कम 5 वर्ष हो जाता है। स्रोत: ODOT Commercial Driver Convictions page; 49 CFR 383.51।"},"56":{"q":"लाइसेंस अयोग्यता के अलावा, आउट-ऑफ-सर्विस आदेश के पहले उल्लंघन के लिए ओरेगन/ODOT एक चालक पर क्या नागरिक दंड लगाता है?","options":["$650","$1,000","$3,861","$7,723"],"explanation":"ODOT एक पहले आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए $3,861 और दूसरे या उसके बाद के उल्लंघन के लिए $7,723 का नागरिक दंड लगाता है, अयोग्यता के अतिरिक्त। स्रोत: ODOT Commercial Driver Convictions page; 49 CFR 383.53।"},"57":{"q":"ओरेगन CDL चालकों पर लागू नियमों के तहत, एक CMV चलाते समय मोबाइल फोन के संबंध में क्या निषिद्ध है?","options":["सभी रेडियो संचार प्रतिबंधित है","कॉल के लिए फोन पकड़ना, एक से अधिक बटन डायल करना, या टेक्स्टिंग","हैंड्स-फ्री कॉलिंग भी प्रतिबंधित है","फोन हर समय बंद रखना चाहिए"],"explanation":"CMV चालक ड्राइविंग के दौरान बात करने के लिए मोबाइल फोन नहीं पकड़ सकते, एक बटन से अधिक दबाकर डायल नहीं कर सकते, या टेक्स्ट संदेश भेज/पढ़ नहीं सकते; एक टेक्स्टिंग/हैंडहेल्ड उल्लंघन एक गंभीर यातायात उल्लंघन है (अधिकतम संघीय जुर्माना $2,750) जो 60/120-दिन की अयोग्यता की ओर गिना जाता है। स्रोत: Oregon Commercial Driver Manual, Section 1; 49 CFR 392.80-392.82, 383.51।"},"58":{"q":"ऑरेगन के मूव ओवर लॉ के तहत, जब आप किसी बहु-लेन सड़क पर रुके हुए आपातकालीन, टो, रोडसाइड-असिस्टेंस, या हैज़र्ड-लाइट वाले वाहन के पास पहुँचते हैं और आप सुरक्षित रूप से किसी गैर-समीपवर्ती लेन में नहीं बदल सकते, तो आपको क्या करना चाहिए?","options":["गति को पोस्ट की गई या निर्धारित गति सीमा से कम से कम 5 mph नीचे धीमा करें","वाहन के हटने तक पूरी तरह रुक जाएँ","गति को पोस्ट की गई गति सीमा से ठीक 10 mph नीचे धीमा करें","पोस्ट की गई गति बनाए रखें लेकिन अपना हॉर्न बजाएँ"],"explanation":"ऑरेगन का मूव ओवर लॉ (ORS 811.147) चालकों से अपेक्षा करता है कि यदि संभव हो तो वे किसी गैर-समीपवर्ती लेन में चले जाएँ; यदि वह संभव नहीं है, तो उन्हें गति को पोस्ट की गई या निर्धारित गति सीमा से कम से कम 5 mph नीचे धीमा करना चाहिए और सावधानी से आगे बढ़ना चाहिए। स्रोत: ORS 811.147; Oregon Driver Manual।"},"59":{"q":"ऑरेगन के मूव ओवर लॉ का उल्लंघन (किसी रुके हुए आपातकालीन, रोडसाइड-असिस्टेंस, टो वाहन, या एम्बुलेंस से सुरक्षित दूरी बनाए रखने में विफलता) किस प्रकार के अपराध के रूप में वर्गीकृत किया जाता है?","options":["एक Class B यातायात उल्लंघन","एक Class A यातायात उल्लंघन","एक Class C दुष्कर्म (misdemeanor)","एक Class D यातायात उल्लंघन"],"explanation":"ऑरेगन के मूव ओवर लॉ के तहत किसी आपातकालीन, रोडसाइड-असिस्टेंस, टो वाहन, या एम्बुलेंस से सुरक्षित दूरी बनाए रखने में विफलता एक Class B यातायात उल्लंघन है। स्रोत: ORS 811.147।"},"60":{"q":"ऑरेगन में, जब कोई स्कूल बस दो-तरफ़ा सड़क पर अपनी लाल बत्तियाँ चमकाते हुए रुकी होती है, तो पास आ रहे चालक को कितनी दूरी पर रुकना चाहिए?","options":["बस से 20 फ़ीट या अधिक","बस से 10 फ़ीट या अधिक","बस से 30 फ़ीट या अधिक","बस से 50 फ़ीट या अधिक"],"explanation":"ऑरेगन चालकों से अपेक्षा करता है कि वे चमकती लाल चेतावनी बत्तियाँ दिखाने वाली स्कूल बस से 20 फ़ीट या अधिक दूरी पर रुकें और तब तक रुके रहें जब तक बत्तियाँ चमकना बंद न कर दें। स्रोत: ORS 811.155; Oregon Driver Manual।"},"61":{"q":"ऑरेगन कानून के तहत, वह एकमात्र स्थिति कौन-सी है जिसमें सामने से आ रहे चालक को चमकती लाल बत्तियाँ दिखाने वाली स्कूल बस के लिए रुकना आवश्यक नहीं है?","options":["बस किसी भिन्न सड़कमार्ग पर रुकी है, जो किसी भौतिक मेडियन या अवरोध से अलग है","बस 25 mph वाले आवासीय क्षेत्र में रुकी है","चालक और बस के बीच एक केंद्रीय दो-तरफ़ा बाएँ-मोड़ लेन है","सड़क पर एक ठोस पीली केंद्र रेखा पेंट की गई है"],"explanation":"ऑरेगन में किसी चालक को केवल तभी रुकने की आवश्यकता नहीं है जब लाल बत्तियाँ दिखाने वाली बस किसी भिन्न सड़कमार्ग पर हो, अर्थात राजमार्ग किसी भौतिक मेडियन या अवरोध द्वारा अलग-अलग सड़कमार्गों में विभाजित हो। एक पेंट की गई पीली रेखा या केंद्रीय मोड़ लेन अलग-अलग सड़कमार्ग नहीं बनाती, इसलिए सभी लेनों को रुकना होगा। स्रोत: ORS 811.155; Oregon Driver Manual।"},"62":{"q":"ऑरेगन में किसी स्कूल बस की चमकती लाल सुरक्षा बत्तियों के लिए रुकने में विफलता किस स्तर का यातायात अपराध है?","options":["एक Class A यातायात उल्लंघन","एक Class B यातायात उल्लंघन","एक Class C यातायात उल्लंघन","एक Class A दुष्कर्म (misdemeanor)"],"explanation":"ORS 811.155 के तहत बस सुरक्षा बत्तियों के लिए रुकने में विफलता एक Class A यातायात उल्लंघन है, जो ऑरेगन का सबसे गंभीर यातायात-उल्लंघन वर्ग है। स्रोत: ORS 811.155।"},"63":{"q":"जब किसी ऑरेगन CDL चालक को प्लेकार्ड लगे हैज़मैट वाहन में किसी रेलमार्ग क्रॉसिंग पर रुकना हो (और कोई चिह्नित स्टॉप लाइन न हो), तो वाहन को कहाँ रुकना चाहिए?","options":["निकटतम रेल से 15 फ़ीट से कम नहीं और 50 फ़ीट से अधिक नहीं","निकटतम रेल से 10 फ़ीट से कम नहीं और 25 फ़ीट से अधिक नहीं","निकटतम रेल से 5 फ़ीट से कम नहीं और 15 फ़ीट से अधिक नहीं","निकटतम रेल से 50 फ़ीट से कम नहीं और 100 फ़ीट से अधिक नहीं"],"explanation":"किसी प्लेकार्ड लगे हैज़मैट वाहन, क्लोरीन लोड, या हैज़मैट कार्गो टैंक (भरे या खाली) के चालक को, जब कोई स्टॉप लाइन न हो, तो निकटतम रेल से 15 फ़ीट से कम नहीं और 50 फ़ीट से अधिक नहीं की दूरी पर रुकना चाहिए। स्रोत: Oregon Commercial Driver Manual Section 9; ORS 811.460।"},"64":{"q":"ऑरेगन में किसी प्लेकार्ड लगे हैज़मैट वाहन में रेलमार्ग पटरियों को पार करते समय, नियम विशेष रूप से किस चीज़ को प्रतिबंधित करता है?","options":["पटरियों पर रहते हुए मैन्युअल रूप से गियर बदलना","पटरियों पर रहते हुए इंजन ब्रेक का उपयोग करना","पटरियों पर रहते हुए चार-तरफ़ा फ़्लैशर चालू करना","पटरियों पर रहते हुए हॉर्न बजाना"],"explanation":"ऑरेगन के उच्च-जोखिम क्रॉसिंग नियम के तहत चालक को ऐसे गियर में पार करना होता है जिसमें मैन्युअल रूप से गियर बदलने की आवश्यकता न हो, इसलिए आपको पटरियों पर रहते हुए गियर नहीं बदलने चाहिए; केवल तभी आगे बढ़ें जब आप सुनिश्चित हों कि आप बिना रुके पटरियों को पार कर सकते हैं। स्रोत: ORS 811.460; Oregon Commercial Driver Manual Section 9।"},"65":{"q":"इनमें से कौन-सा वाहन उन 'उच्च-जोखिम' वाहनों में शामिल नहीं है जिन्हें ऑरेगन कानून हर रेलमार्ग क्रॉसिंग पर रुकने के लिए बाध्य करता है?","options":["सामान्य माल ढोने वाला एक खाली फ़्लैटबेड ट्रक","एक स्कूल बस","खतरनाक सामग्री ढोने वाला एक भरा या खाली कार्गो टैंक","यात्रियों को ले जाने वाली एक वाणिज्यिक बस"],"explanation":"ORS 811.460 उन उच्च-जोखिम वाहनों को सूचीबद्ध करता है जिन्हें क्रॉसिंग पर रुकना चाहिए: स्कूल बसें, कुछ स्कूल गतिविधि और कर्मचारी-परिवहन बसें, वाणिज्यिक बसें, विस्फोटक/ज्वलनशील/संक्षारक पदार्थ ले जाने वाले वाहन, और हैज़मैट टैंक वाहन (भरे या खाली)। गैर-खतरनाक माल वाले सामान्य माल ट्रक को रुकना आवश्यक नहीं है जब तक कि सिग्नल इसकी माँग न करें। स्रोत: ORS 811.460।"},"66":{"q":"ऑरेगन में, 10,000 पाउंड GVWR से अधिक के वाणिज्यिक वाहन के लिए मानक अधिकतम गति सीमा क्या है, जब तक कोई भिन्न गति पोस्ट न की गई हो?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"जब तक कोई भिन्न गति पोस्ट न की गई हो, 10,000 lbs GVWR से अधिक के वाणिज्यिक वाहनों (या 8,000 lbs GVWR से अधिक के ट्रक ट्रैक्टर) के लिए डिफ़ॉल्ट अधिकतम गति 55 mph है। स्रोत: ORS 811.111; ORS 810.180।"},"67":{"q":"ऑरेगन नियम के अनुसार, परिवहन विभाग किसी इंटरस्टेट राजमार्ग पर वाणिज्यिक वाहनों के लिए जो सर्वोच्च गति निर्धारित कर सकता है, वह है:","options":["65 mph","70 mph","60 mph","75 mph"],"explanation":"ODOT निर्धारित इंटरस्टेट गति तय कर सकता है लेकिन वाणिज्यिक वाहनों के लिए 65 mph से अधिक नहीं कर सकता (अन्य वाहनों के लिए सीमा 70 mph है)। कुछ ऑरेगन इंटरस्टेट खंडों पर ट्रकों के लिए इसे 60 mph तक बढ़ाया गया है जहाँ कारें 65 चलती हैं। स्रोत: ORS 810.180; OAR 734-020-0010।"},"68":{"q":"किसी ऑरेगन सड़कमार्ग पर जहाँ एक ही दिशा में दो या अधिक लेन हों, किन वाहनों को ओवरटेक करने या मुड़ने के अलावा दाहिनी लेन में चलना आवश्यक है?","options":["कैंपर, ट्रेलर खींचने वाले वाहन, और 10,000 पाउंड या अधिक पंजीकरण वजन वाले वाहन","केवल तीन या अधिक एक्सल वाले वाहन","केवल हैज़मैट प्लेकार्ड दिखाने वाले वाहन","45 mph से नीचे चलने वाले सभी वाहन"],"explanation":"ORS 811.325 किसी भी कैंपर, ट्रेलर वाले किसी भी वाहन, और 10,000 lbs या अधिक पंजीकरण वजन वाले किसी भी वाहन से अपेक्षा करता है कि वे बहु-लेन एक-दिशा वाले सड़कमार्गों पर दाहिनी लेन का उपयोग करें, सिवाय ओवरटेक करते समय, बाएँ मुड़ते समय, किसी आपातकाल पर प्रतिक्रिया देते समय, विलय करते यातायात से बचते समय, या यातायात नियंत्रण उपकरणों द्वारा निर्देशित होने पर। स्रोत: ORS 811.325।"},"69":{"q":"ऑरेगन बहु-लेन राजमार्ग पर किसी कैंपर, ट्रेलर, या ट्रक (10,000 lbs+) को दाहिनी लेन में रखने में विफलता किस प्रकार का अपराध है?","options":["एक Class B यातायात उल्लंघन","एक Class A यातायात उल्लंघन","एक Class C यातायात उल्लंघन","एक Class D यातायात उल्लंघन"],"explanation":"ORS 811.325 की दाहिनी-लेन आवश्यकता का उल्लंघन एक Class B यातायात उल्लंघन है। स्रोत: ORS 811.325।"},"70":{"q":"इनमें से कौन-सा एक मान्यता प्राप्त कानूनी अपवाद है जो किसी ऑरेगन ट्रक (10,000 lbs+) को बहु-लेन राजमार्ग पर दाहिनी लेन छोड़ने की अनुमति देता है?","options":["एक ही दिशा में जा रहे किसी अन्य वाहन को ओवरटेक करना और पास करना","अधिक तेज़ क्रूज़िंग गति बनाए रखने की इच्छा","आगे वाले वाहन से अधिक लंबी अनुसरण दूरी बनाए रखना","दाहिनी-लेन की सड़क पर घिसाव से बचना"],"explanation":"ORS 811.325 कानूनी रूप से ओवरटेक करने और पास करने, बाएँ मोड़ की तैयारी करने, आपातकालीन परिस्थितियों पर प्रतिक्रिया देने, विलय/त्वरण लेनों से प्रवेश करते यातायात से बचने, या यातायात नियंत्रण उपकरणों द्वारा निर्देशित होने के लिए दाहिनी लेन छोड़ने की अनुमति देता है। स्रोत: ORS 811.325।"},"71":{"q":"ऑरेगन में किसी विभाजित या एक-तरफ़ा राजमार्ग पर, जब कोई CDL चालक सड़क पर रुका हो तो उसे तीन आपातकालीन चेतावनी त्रिकोण कहाँ रखने चाहिए?","options":["पिछले हिस्से के 10 फ़ीट के भीतर, और पास आ रहे यातायात की ओर 100 फ़ीट और 200 फ़ीट पर","पिछले हिस्से के 25 फ़ीट के भीतर, और पास आ रहे यातायात की ओर 50 फ़ीट और 150 फ़ीट पर","अगले हिस्से के 10 फ़ीट के भीतर, और पास आ रहे यातायात की ओर 100 फ़ीट और 300 फ़ीट पर","पिछले हिस्से के 50 फ़ीट के भीतर, और पास आ रहे यातायात की ओर 100 फ़ीट और 250 फ़ीट पर"],"explanation":"किसी एक-तरफ़ा या विभाजित राजमार्ग पर, एक चेतावनी उपकरण पास आ रहे यातायात की ओर पिछले हिस्से के 10 फ़ीट के भीतर, एक लगभग 100 फ़ीट पीछे, और एक लगभग 200 फ़ीट पीछे रखें। यह संघीय मानक (49 CFR 392.22) Oregon Commercial Driver Manual में सिखाया जाता है। स्रोत: Oregon Commercial Driver Manual; 49 CFR 392.22।"},"72":{"q":"किसी दो-लेन, दो-तरफ़ा ऑरेगन सड़क पर, किसी CDL वाहन के सड़क के चलने वाले हिस्से पर रुकने के बाद, चालक को आपातकालीन चेतावनी उपकरण कितने मिनट के भीतर रख देने चाहिए?","options":["10 मिनट के भीतर","5 मिनट के भीतर","15 मिनट के भीतर","30 मिनट के भीतर"],"explanation":"किसी CDL चालक को सड़क के चलने वाले हिस्से या किनारे पर रुकने के 10 मिनट के भीतर चेतावनी उपकरण (तीन त्रिकोण या समतुल्य) रखने चाहिए। स्रोत: Oregon Commercial Driver Manual; 49 CFR 392.22।"},"73":{"q":"ऑरेगन में, ओवर-डाइमेंशन परमिट की आवश्यकता होने से पहले अधिकतम कानूनी वाहन/लोड चौड़ाई क्या है?","options":["8 फ़ीट 6 इंच","8 फ़ीट 0 इंच","9 फ़ीट 0 इंच","10 फ़ीट 0 इंच"],"explanation":"ऑरेगन की कानूनी अधिकतम चौड़ाई 8 फ़ीट 6 इंच है; इससे अधिक लोड के लिए ODOT के Commerce and Compliance Division से ओवर-डाइमेंशन परमिट की आवश्यकता होती है। स्रोत: ORS 818.080; ODOT Legal Vehicle Dimensions।"},"74":{"q":"ओवर-डाइमेंशन परमिट की आवश्यकता होने से पहले ऑरेगन की कानूनी अधिकतम वाहन ऊँचाई क्या है?","options":["14 फ़ीट 0 इंच","13 फ़ीट 6 इंच","13 फ़ीट 0 इंच","15 फ़ीट 0 इंच"],"explanation":"ऑरेगन की कानूनी अधिकतम ऊँचाई 14 फ़ीट 0 इंच है; इससे अधिक लोड के लिए ओवर-डाइमेंशन परमिट की आवश्यकता होती है। (ध्यान दें कि कई अन्य राज्य 13'6\" का उपयोग करते हैं।) स्रोत: ORS 818.080; ODOT Legal Vehicle Dimensions।"},"75":{"q":"ऑरेगन बर्फ़ के मौसम के दौरान 10,000 lbs GVW से अधिक के सभी वाहनों से टायर चेन ले जाने की अपेक्षा करता है:","options":["जब भी ऐसी परिस्थितियाँ हों जहाँ उनके उपयोग की आवश्यकता हो सकती है या जरूरी हो सकती है","केवल जब Cascades के पूर्व में यात्रा कर रहे हों","केवल दिसंबर से फ़रवरी तक सप्ताहांत पर","केवल यदि वाहन में स्टडेड टायर न हों"],"explanation":"ऑरेगन कानून 10,000 lbs GVW से अधिक के वाहनों से अपेक्षा करता है कि वे चेन तब ले जाएँ जब भी ऐसी परिस्थितियाँ हों जहाँ चेन की आवश्यकता हो सकती है या जरूरी हो सकती है, और जब चेन कानून लागू हो (आमतौर पर पहाड़ी दर्रों पर अक्टूबर से मार्च तक) तो उन्हें लगाएँ। स्रोत: ODOT Commerce and Compliance Division, Chains and Traction Tires।"},"76":{"q":"किस अवधि के दौरान ऑरेगन की सड़कों पर स्टडेड टायरों का उपयोग कानूनी है?","options":["1 नवंबर से 31 मार्च तक","1 अक्टूबर से 30 अप्रैल तक","15 नवंबर से 15 अप्रैल तक","1 दिसंबर से 1 मार्च तक"],"explanation":"स्टडेड टायर ऑरेगन में केवल 1 नवंबर से 31 मार्च तक कानूनी हैं; इस अवधि के बाहर उनका उपयोग करने पर जुर्माना लग सकता है। स्रोत: ODOT / Oregon TripCheck; ORS स्टडेड-टायर प्रावधान।"},"77":{"q":"ऑरेगन एक खड़ी Interstate 5 ढलान पर एक प्रारंभिक रनअवे-ट्रक एस्केप सुविधा के लिए उल्लेखनीय है। देश का पहला नेगेटिव-ग्रेड (ढलान वाला) ट्रक अरेस्टर बेड कहाँ बनाया और परखा गया था?","options":["दक्षिणी ऑरेगन में I-5 पर Siskiyou Summit के पास","I-84 की Cabbage Hill ढलान पर","Mount Hood के ऊपर US 26 पर Government Camp में","US 20 के Santiam Pass पर"],"explanation":"संयुक्त राज्य में पहला नेगेटिव-ग्रेड (ढलान वाला) ट्रक अरेस्टर बेड 1977 में दक्षिणी ऑरेगन में Siskiyou Summit के पास I-5 के साथ बनाया और परखा गया था, जो एक उल्लेखनीय रूप से खड़ी पहाड़ी ढलान है जहाँ रनअवे-रैंप के उपयोग पर ज़ोर दिया जाता है। स्रोत: ODOT; Oregon Commercial Driver Manual पर्वतीय-ड्राइविंग मार्गदर्शन।"},"78":{"q":"ऑरेगन में, कौन-सी राज्य एजेंसी वाणिज्यिक चालक लाइसेंस (CDL) जारी करती है और परीक्षण प्रक्रिया का प्रशासन करती है?","options":["Oregon DMV, जो Oregon Department of Transportation (ODOT) Driver & Motor Vehicle Services का हिस्सा है","Oregon State Police Commercial Vehicle Division","संघीय Motor Carrier Safety Administration (FMCSA) क्षेत्रीय कार्यालय","Oregon Secretary of State, Corporations and Licensing Division"],"explanation":"ऑरेगन CDL Oregon DMV द्वारा जारी किए जाते हैं, जो Oregon Department of Transportation (ODOT) Driver & Motor Vehicle Services का हिस्सा है। स्रोत: Oregon DMV 'Getting a CDL or CLP' पृष्ठ; Oregon Commercial Driver Manual।"},"79":{"q":"किसी वाहन को वजन के आधार पर ऑरेगन CDL की आवश्यकता तब होती है जब उसका सकल वाहन वजन रेटिंग (GVWR) कम से कम कितने पाउंड हो?","options":["26,001 पाउंड","10,001 पाउंड","18,000 पाउंड","33,000 पाउंड"],"explanation":"ऑरेगन को 26,001 पाउंड या अधिक GVWR वाले वाहन को चलाने के लिए CDL की आवश्यकता होती है (और उन संयोजनों के लिए जहाँ खींची जाने वाली इकाई 10,000 lbs से अधिक हो)। स्रोत: Oregon Commercial Driver Manual, Section 1।"},"80":{"q":"वजन के अलावा, कौन-सी यात्री सीमा किसी वाहन को ऑरेगन CDL की आवश्यकता वाला बनाती है?","options":["चालक सहित 16 या अधिक लोगों को ले जाने के लिए डिज़ाइन किया गया","चालक सहित 9 या अधिक लोगों को ले जाने के लिए डिज़ाइन किया गया","चालक को छोड़कर 24 या अधिक लोगों को ले जाने के लिए डिज़ाइन किया गया","चालक सहित 12 या अधिक लोगों को ले जाने के लिए डिज़ाइन किया गया"],"explanation":"चालक सहित 16 या अधिक लोगों को ले जाने के लिए डिज़ाइन किए गए वाहन के लिए CDL आवश्यक है। तीसरा ट्रिगर प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री का परिवहन करना है। स्रोत: Oregon Commercial Driver Manual, Section 1; ऑरेगन में लागू 49 CFR 383.5।"},"81":{"q":"ऑरेगन CDL या वाणिज्यिक शिक्षार्थी परमिट के लिए आवेदन करते समय, आवेदक को यह 'स्व-प्रमाणित' करना होता है कि वे किस प्रकार के वाणिज्य में काम करेंगे। ऑरेगन कौन-सा श्रेणी समूह प्रदान करता है?","options":["Non-excepted Interstate, Excepted Interstate, और Non-excepted Intrastate","Interstate Hazmat, Intrastate Hazmat, और केवल Non-Hazmat","Federal Carrier, State Carrier, और Private Carrier","Class A, Class B, और Class C संचालन"],"explanation":"Oregon DMV तीन स्व-प्रमाणन श्रेणियाँ प्रदान करता है: Non-excepted Interstate, Excepted Interstate, और Non-excepted Intrastate। (Excepted Intrastate चौथी FMCSA श्रेणी है; ऑरेगन इसे अलग से सूचीबद्ध नहीं करता।) स्रोत: Oregon DMV CDL आवेदन/स्व-प्रमाणन; 49 CFR 383.71।"},"82":{"q":"एक ऑरेगन CDL आवेदक जो स्वयं को 'Non-excepted Interstate' के रूप में प्रमाणित करता है, उसे चिकित्सा योग्यता के संबंध में क्या करना आवश्यक है?","options":["DMV को एक वैध DOT चिकित्सा परीक्षक प्रमाणपत्र की प्रति प्रदान करें और एक मौजूदा प्रमाणपत्र फ़ाइल में रखें","कागज़ी चिकित्सा कार्ड को ट्रक में रखें लेकिन इसे कभी DMV को न दें","एक नोटरीकृत बयान जमा करें कि किसी चिकित्सा परीक्षा की आवश्यकता नहीं है","एक अतिरिक्त DMV-संचालित शारीरिक फिटनेस रोड टेस्ट पास करें"],"explanation":"एक non-excepted interstate चालक को Oregon DMV को एक वैध चिकित्सा परीक्षक प्रमाणपत्र (DOT चिकित्सा कार्ड) की प्रति प्रदान करनी चाहिए और एक मौजूदा प्रमाणपत्र फ़ाइल में रखने के लिए ज़िम्मेदार है, अन्यथा CDL को डाउनग्रेड कर दिया जाता है। स्रोत: Oregon DMV CDL चिकित्सा प्रमाणन; 49 CFR 383.71/391.45।"},"83":{"q":"ऑरेगन CDL के लिए उपयोग किए जाने वाले चिकित्सा परीक्षक प्रमाणपत्र को बनाने वाली DOT शारीरिक परीक्षा करने के लिए कौन योग्य है?","options":["FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध एक चिकित्सा परीक्षक","ऑरेगन में कोई भी लाइसेंस प्राप्त फ़ार्मासिस्ट","एक Oregon DMV फ़ील्ड ऑफ़िस परीक्षक","कोई भी चिकित्सक, जब तक वे किसी भी U.S. राज्य में लाइसेंस प्राप्त हों"],"explanation":"DOT चिकित्सा परीक्षा FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध एक चिकित्सा परीक्षक द्वारा की जानी चाहिए। स्रोत: Oregon DMV 'Getting a CDL or CLP'; 49 CFR 390.103।"},"84":{"q":"किसी आवेदक के ऑरेगन में CDL स्किल्स टेस्ट देने से पहले, उन्हें पहले कौन-सा क्रेडेंशियल प्राप्त करना चाहिए?","options":["एक Commercial Learner Permit (CLP)","एक Class C अनंतिम CDL","एक संघीय इंटरस्टेट संचालन प्राधिकरण (MC नंबर)","एक अस्थायी आउट-ऑफ़-सर्विस छूट"],"explanation":"जिन आवेदकों को स्किल्स टेस्टिंग की आवश्यकता होती है उन्हें पहले आवश्यक ज्ञान परीक्षा(ओं) को पास करके एक Commercial Learner Permit (CLP) प्राप्त करना चाहिए। स्रोत: Oregon DMV CDL प्रक्रिया; OAR 735-063-0250 / 735-063-0260।"},"85":{"q":"ऑरेगन Class A Commercial Learner Permit प्राप्त करने के लिए, आवेदक को कौन-सी ज्ञान परीक्षाएँ पास करनी चाहिए?","options":["General Knowledge परीक्षा और Combination Vehicles परीक्षा (साथ ही Air Brakes यदि लागू हो)","केवल General Knowledge परीक्षा","General Knowledge परीक्षा और Hazardous Materials परीक्षा","केवल Combination Vehicles परीक्षा"],"explanation":"एक Class A CLP के लिए General Knowledge परीक्षा और Combination Vehicles परीक्षा पास करना आवश्यक है, साथ ही यदि वाहन में एयर ब्रेक हों तो Air Brakes परीक्षा भी। स्रोत: OAR 735-063-0250; Oregon Commercial Driver Manual।"},"86":{"q":"ऑरेगन CDL ज्ञान परीक्षाओं पर न्यूनतम उत्तीर्ण अंक क्या है?","options":["80 प्रतिशत सही","70 प्रतिशत सही","90 प्रतिशत सही","75 प्रतिशत सही"],"explanation":"प्रत्येक ऑरेगन CDL ज्ञान परीक्षा पास करने के लिए कम से कम 80 प्रतिशत सही अंक आवश्यक हैं (उदाहरण के लिए, General Knowledge परीक्षा पर 50 में से 40 प्रश्न)। स्रोत: Oregon Commercial Driver Manual / Oregon DMV; 49 CFR 383.135।"},"87":{"q":"ऑरेगन CDL स्किल्स टेस्ट तीन भागों से बना होता है जिन्हें एक निर्धारित क्रम में लेना होता है। वह क्रम क्या है?","options":["प्री-ट्रिप वाहन निरीक्षण, फिर बुनियादी नियंत्रण कौशल, फिर ऑन-रोड ड्राइविंग","ऑन-रोड ड्राइविंग, फिर प्री-ट्रिप निरीक्षण, फिर बुनियादी नियंत्रण कौशल","बुनियादी नियंत्रण कौशल, फिर ऑन-रोड ड्राइविंग, फिर प्री-ट्रिप निरीक्षण","प्री-ट्रिप निरीक्षण, फिर ऑन-रोड ड्राइविंग, फिर बुनियादी नियंत्रण कौशल"],"explanation":"स्किल्स टेस्ट इस क्रम में संचालित किया जाता है: पहले प्री-ट्रिप वाहन निरीक्षण, फिर बुनियादी नियंत्रण कौशल, फिर ऑन-रोड ड्राइव; आगे बढ़ने से पहले प्रत्येक भाग को पास करना होगा। स्रोत: OAR 735-063-0260 / OAR 735-060-0120।"},"88":{"q":"ऑरेगन में निम्नलिखित में से किसके लिए परीक्षण से पहले संघीय Entry-Level Driver Training (ELDT) पूरा करना आवश्यक है?","options":["पहली बार Class A या B CDL प्राप्त करना, Class B को A में अपग्रेड करना, या पहली बार यात्री/स्कूल बस/हैज़मैट एंडोर्समेंट","हर CDL नवीनीकरण, वर्ग की परवाह किए बिना","केवल 21 वर्ष से कम आयु के चालकों के लिए","केवल जब डबल्स/ट्रिपल्स एंडोर्समेंट जोड़ा जाए"],"explanation":"पहली बार Class A या B CDL के लिए, Class B को Class A में अपग्रेड करने के लिए, या पहली बार यात्री, स्कूल बस, या खतरनाक सामग्री एंडोर्समेंट प्राप्त करने के लिए परीक्षण से पहले ELDT आवश्यक है। स्रोत: Oregon DMV; 49 CFR Part 380 Subpart F।"},"89":{"q":"ऑरेगन CDL के लिए Entry-Level Driver Training (ELDT) ऐसी इकाई द्वारा प्रदान की जानी चाहिए जो कहाँ सूचीबद्ध हो?","options":["FMCSA Training Provider Registry (TPR) पर","Oregon DMV की अनुमोदित हाई स्कूलों की सूची में","Oregon Trucking Associations सदस्य रोस्टर पर","U.S. Department of Labor अप्रेंटिसशिप कार्यालय के साथ"],"explanation":"ELDT निर्देश स्किल्स टेस्ट निर्धारित करने या हैज़मैट ज्ञान परीक्षा देने से पहले FMCSA Training Provider Registry (TPR) पर मौजूद किसी स्कूल या इकाई के माध्यम से पूरा किया जाना चाहिए। स्रोत: Oregon DMV; FMCSA Training Provider Registry।"},"90":{"q":"धारक द्वारा CDL स्किल्स टेस्ट देने से पहले किसी ऑरेगन Commercial Learner Permit को कितने समय तक रखना आवश्यक है?","options":["कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 7 दिन","कम से कम 60 दिन"],"explanation":"Oregon DMV ने अमान्य न हुआ CLP स्किल्स टेस्ट से कम से कम 14 दिन पहले जारी किया होना चाहिए। स्रोत: OAR 735-063-0260।"},"91":{"q":"एक ऑरेगन Commercial Learner Permit (CLP) कितने समय तक वैध है, और क्या इसका नवीनीकरण किया जा सकता है?","options":["एक वर्ष के लिए वैध और नवीकरणीय नहीं है","180 दिनों के लिए वैध और एक बार नवीनीकृत किया जा सकता है","दो वर्षों के लिए वैध और सालाना नवीकरणीय है","90 दिनों के लिए वैध और नवीकरणीय नहीं है"],"explanation":"एक ऑरेगन CLP जारी होने से एक वर्ष के लिए वैध है और नवीकरणीय नहीं है। स्रोत: ORS 807.285।"},"92":{"q":"ऑरेगन CDL ज्ञान परीक्षाओं पर (और किसी पूर्ण किए गए स्किल्स टेस्ट पर) एक उत्तीर्ण अंक CDL जारी होने से पहले कितने समय तक वैध रहता है?","options":["छह महीने","तीन महीने","एक वर्ष","तीस दिन"],"explanation":"एक उत्तीर्ण ज्ञान-परीक्षा अंक छह महीने के लिए वैध है, और किसी पूर्ण किए गए CDL स्किल्स टेस्ट के लिए एक उत्तीर्ण अंक छह महीने के लिए वैध है। स्रोत: OAR 735-063-0250 और OAR 735-063-0260।"},"93":{"q":"एक बार जारी होने के बाद, नवीनीकरण से पहले एक ऑरेगन CDL कितने समय तक वैध है?","options":["8 वर्ष","4 वर्ष","5 वर्ष","10 वर्ष"],"explanation":"किसी U.S. नागरिक या स्थायी निवासी को जारी किया गया ऑरेगन CDL 8 वर्षों के लिए वैध है, जो एक नियमित ऑरेगन चालक लाइसेंस के समान मानक चक्र है। स्रोत: Oregon DMV; ORS Chapter 807।"},"94":{"q":"समाप्ति तिथि के सापेक्ष ऑरेगन CDL नवीनीकरण विंडो क्या है?","options":["समाप्ति से 12 महीने पहले तक और समाप्ति के 2 वर्ष बाद तक","केवल समाप्ति तिथि पर या उसके बाद, बिना किसी जल्दी नवीनीकरण के","समाप्ति से 30 दिन पहले तक और 30 दिन बाद तक","केवल समाप्ति से 6 महीने पहले तक"],"explanation":"एक ऑरेगन CDL को इसकी समाप्ति से 12 महीने पहले तक और इसकी समाप्ति के 2 वर्ष बाद तक नवीनीकृत किया जा सकता है; उसके बाद, चालक को एक नए लाइसेंस के लिए आवेदन करना होगा। स्रोत: Oregon DMV 'Renewing a Commercial Driver License'।"},"95":{"q":"आवेदन के समय पात्रता स्थापित करने के लिए किसी ऑरेगन CDL/CLP आवेदक को कौन-से दस्तावेज़ प्रदान करने चाहिए?","options":["पूर्ण कानूनी नाम, U.S. नागरिकता या वैध स्थायी निवास, पहचान, जन्म तिथि, निवास पता, और Social Security Number का प्रमाण","केवल एक मौजूदा पासपोर्ट फ़ोटो और एक क्रेडिट कार्ड","एक नोटरीकृत नियोक्ता पत्र और एक वाहन शीर्षक","तीन वर्षों के वाणिज्यिक ड्राइविंग अनुभव का प्रमाण"],"explanation":"आवेदकों को पूर्ण कानूनी नाम, U.S. नागरिकता या वैध स्थायी निवास, पहचान, जन्म तिथि, और निवास पते का प्रमाण, साथ ही अपना Social Security Number प्रदान करना चाहिए। स्रोत: Oregon DMV 'Getting a CDL or CLP'; OAR 735-063-0250।"},"96":{"q":"Hazardous Materials एंडोर्समेंट वाले ऑरेगन CDL का नवीनीकरण करते समय, कौन-सी अतिरिक्त आवश्यकता लागू होती है?","options":["HazMat ज्ञान परीक्षा पास करें और एक मौजूदा TSA सुरक्षा पृष्ठभूमि जाँच (खतरा मूल्यांकन) रखें","अंतिम रिकॉर्ड के शिपर से एक नोटरीकृत पत्र प्रदान करें","पृष्ठभूमि समीक्षा के दौरान CDL को 30 दिनों के लिए सरेंडर करें","एक प्लेकार्ड लगे वाहन में दूसरा ऑन-रोड स्किल्स टेस्ट पास करें"],"explanation":"HazMat एंडोर्समेंट वाले CDL के नवीनीकरण के लिए HazMat ज्ञान परीक्षा पास करना और एक मौजूदा TSA सुरक्षा खतरा मूल्यांकन (पृष्ठभूमि जाँच) रखना आवश्यक है। स्रोत: Oregon DMV 'Renewing a CDL'; 49 CFR Part 1572।"},"97":{"q":"यदि कोई ऑरेगन CDL धारक एक आवश्यक चिकित्सा परीक्षक प्रमाणपत्र को समाप्त होने देता है (एक non-excepted स्व-प्रमाणन के लिए), तो Oregon DMV क्या करता है?","options":["CDL को डाउनग्रेड करता है, जब तक एक वैध चिकित्सा प्रमाणपत्र फ़ाइल में न हो तब तक वाणिज्यिक ड्राइविंग विशेषाधिकार हटा देता है","नियमित (Class C) ड्राइविंग विशेषाधिकारों को भी निलंबित कर देता है","बिना किसी कार्रवाई की आवश्यकता के एक स्वचालित 90-दिन की चिकित्सा छूट जारी करता है","चालक को साइटेशन के लिए Oregon State Police को रेफ़र करता है"],"explanation":"यदि किसी non-excepted चालक का चिकित्सा प्रमाणपत्र समाप्त हो जाता है और कोई मौजूदा प्रमाणपत्र फ़ाइल में नहीं है, तो Oregon DMV CDL को डाउनग्रेड कर देता है, जब तक एक वैध प्रमाणपत्र जमा नहीं किया जाता तब तक वाणिज्यिक विशेषाधिकार हटा देता है; नियमित लाइसेंस बना रहता है। स्रोत: Oregon DMV CDL चिकित्सा प्रमाणन; 49 CFR 383.73।"}},"ar":{"0":{"q":"ما هو الحد الأقصى القانوني لعرض معظم المركبات التجارية على طرق ولاية أوريغون السريعة دون تصريح تجاوز الأبعاد؟","options":["8 feet (96 inches)","8 feet 6 inches (102 inches)","9 feet (108 inches)","10 feet (120 inches)"],"explanation":"تحدد ولاية أوريغون إجمالي العرض الخارجي للمركبة بـ 8 feet 6 inches (102 inches) على الطرق العامة السريعة؛ وأي عرض أكبر من ذلك يتطلب تصريح تجاوز الأبعاد. المصدر: ORS 818.080 (حدود الحجم القصوى) وOregon DOT Commerce and Compliance Division، أبعاد المركبات القانونية."},"1":{"q":"ما هو الحد الأقصى القانوني للارتفاع، بما في ذلك الحمولة، لمركبة تعمل على طرق ولاية أوريغون السريعة دون تصريح؟","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"تحدد ولاية أوريغون الحد الأقصى للارتفاع، بما في ذلك أي حمولة، بـ 14 feet؛ وتجاوز ذلك يتطلب تصريح تجاوز الأبعاد والتحقق من المسار. المصدر: ORS 818.080 وOregon DOT أبعاد المركبات القانونية."},"2":{"q":"دون تصريح طول خاص، ما هو الحد الأقصى للطول الإجمالي لمعظم تركيبات الجرار الشاحن والمقطورة النصفية على الطرق السريعة العامة في أوريغون؟","options":["50 feet","55 feet","60 feet","75 feet"],"explanation":"على الطرق السريعة العامة في أوريغون يبلغ الحد الأقصى للطول الإجمالي لتركيبة المركبات 60 feet؛ ولا يُسمح بالتركيبات الأطول إلا على مسارات محددة أو بموجب تصريح. المصدر: ORS 818.080 وOregon DOT أبعاد المركبات القانونية."},"3":{"q":"على المسارات المحددة في أوريغون التي تسمح بطول إجمالي غير محدود، ما هو الحد الأقصى لطول المقطورة النصفية الواحدة في تركيبة الجرار والمقطورة النصفية؟","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"تسمح ولاية أوريغون بحد أقصى لطول المقطورة النصفية يبلغ 53 feet؛ وعلى المسارات المحددة قد يكون الطول الإجمالي للتركيبة غير محدود، لكن المقطورة النصفية نفسها لا يجوز أن تتجاوز 53 feet. المصدر: ORS 818.080 وOregon DOT أبعاد المركبات القانونية."},"4":{"q":"ما هو الحد الأقصى لطول المركبة الواحدة (المنفردة) على طرق ولاية أوريغون السريعة دون تصريح؟","options":["35 feet","40 feet","45 feet","53 feet"],"explanation":"لا يجوز أن تتجاوز المركبة الواحدة التي تعمل منفردة في أوريغون 40 feet في الطول دون تصريح. المصدر: ORS 818.010 (حدود الحجم القصوى)."},"5":{"q":"في أوريغون، ما هو الوزن الأقصى المسموح به على أي محور واحد دون تصريح للوزن الزائد؟","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"تحدد ولاية أوريغون أي محور واحد بـ 20,000 pounds. المصدر: ORS 818.010 (الوزن الأقصى المسموح به)."},"6":{"q":"ما هو الوزن الأقصى المسموح به على مجموعة المحاور المزدوجة في أوريغون دون تصريح للوزن الزائد؟","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"تحدد ولاية أوريغون المحور المزدوج (محورين) بـ 34,000 pounds، بما يتطابق مع المعيار الفيدرالي. المصدر: ORS 818.010 (الوزن الأقصى المسموح به)."},"7":{"q":"ما هو الحد الأقصى لوزن المركبة الإجمالي المسموح به عموماً على طرق ولاية أوريغون السريعة دون تصريح للوزن الزائد أو الوزن الممدد؟","options":["73,280 pounds","80,000 pounds","88,000 pounds","105,500 pounds"],"explanation":"الحد الأقصى القياسي للوزن الإجمالي المركّب في أوريغون هو 80,000 pounds؛ وتتطلب الحمولات القابلة للتقسيم الأثقل تصريح وزن ممدد من ODOT. المصدر: ORS 818.010 وOregon DOT Commerce and Compliance Division."},"8":{"q":"بموجب تصريح الوزن الممدد من ODOT (الحمولة القابلة للتقسيم)، ما هو الحد الأقصى للوزن الإجمالي المركّب الذي يجوز لمركبة مؤهلة نقله في أوريغون؟","options":["90,000 pounds","98,000 pounds","105,500 pounds","129,000 pounds"],"explanation":"يسمح تصريح الوزن الممدد في أوريغون للتركيبات المؤهلة متعددة المحاور بالعمل حتى وزن إجمالي قدره 105,500 pounds عند نقل حمولات قابلة للتقسيم. المصدر: Oregon DOT Commerce and Compliance Division، تصريح الوزن الممدد (الحمولة القابلة للتقسيم)."},"9":{"q":"يحدد قانون أوريغون الحمولة التي يجوز حملها على الإطارات بناءً على عرض الإطار. ما هو الحد الأقصى المسموح به من الأرطال لكل بوصة من عرض الإطار؟","options":["500 pounds per inch","550 pounds per inch","600 pounds per inch","650 pounds per inch"],"explanation":"تستخدم ولاية أوريغون تصنيف الإطار الجانبي الذي تحدده الشركة المصنّعة، على ألا يتجاوز 600 pounds per inch من عرض الإطار، مضروباً في مجموع عروض الإطارات. المصدر: ORS 818.010 (الوزن الأقصى المسموح به)."},"10":{"q":"أي معادلة تطبقها ولاية أوريغون لتحديد الوزن الإجمالي الأقصى المسموح به على مجموعة من المحاور المتتالية بناءً على تباعدها؟","options":["The Federal Bridge Formula (Bridge Gross Weight Formula)","معادلة تصنيف GAWR","معادلة ضريبة الأميال في أوريغون","معادلة تثبيت الحمولة"],"explanation":"تعتمد ولاية أوريغون المعادلة الفيدرالية للجسور، W = 500[LN/(N-1) + 12N + 36]، للحد من الوزن على أي مجموعة من محورين أو أكثر متتالية بناءً على تباعد المحاور وعددها. المصدر: ORS 818.010 و23 CFR 658 كما تطبقها Oregon DOT."},"11":{"q":"في المعادلة الفيدرالية للجسور المستخدمة في أوريغون، ماذا يمثل المتغير 'L'؟","options":["حد الحمولة القانوني بالأطنان","المسافة بالأقدام بين المحاور الخارجية للمجموعة","طول المقطورة بالأقدام","عدد لوحات الترخيص المطلوبة"],"explanation":"في معادلة الجسور W = 500[LN/(N-1) + 12N + 36]، يمثل L المسافة بالأقدام بين أقصى محورين خارجيين للمجموعة، وN هو عدد المحاور، وW هو الوزن الإجمالي المسموح به. المصدر: المعادلة الفيدرالية للجسور كما تطبقها Oregon DOT؛ ORS 818.010."},"12":{"q":"متى يكون تصريح تجاوز الأبعاد أو الوزن الزائد من Oregon DOT مطلوباً لمركبة تجارية؟","options":["فقط عند عبور حدود الولاية","كلما تجاوزت المركبة أو الحمولة حدود الحجم أو الوزن القانونية","فقط في عطلات نهاية الأسبوع والعطلات الرسمية","فقط للمركبات المسجلة خارج الولاية"],"explanation":"يجب على أي مركبة أو حمولة تتجاوز الحدود القانونية لأوريغون من حيث العرض أو الارتفاع أو الطول أو الوزن الحصول على تصريح تجاوز الأبعاد/الوزن الزائد قبل العمل. المصدر: ORS 818.200 وOregon DOT Commerce and Compliance Division، عمليات تجاوز الأبعاد."},"13":{"q":"أي جهة في أوريغون تصدر تصاريح الحجم الزائد والوزن الزائد (تجاوز الأبعاد) للمركبات التجارية؟","options":["شرطة ولاية أوريغون","Oregon DOT Commerce and Compliance Division","مكتب عمدة المقاطعة","إدارة سلامة شاحنات النقل بالمحركات الفيدرالية"],"explanation":"تصدر تصاريح تجاوز الأبعاد والوزن الزائد في أوريغون عن قسم التجارة والامتثال (Commerce and Compliance Division) التابع لإدارة النقل في ولاية أوريغون (Oregon DOT) (المعروف سابقاً باسم Motor Carrier Transportation Division)، وهي متاحة عبر الإنترنت أو في موانئ الدخول. المصدر: Oregon DOT Commerce and Compliance Division."},"14":{"q":"ما هو الوزن الأقصى الذي تسمح به أوريغون على أي عجلة فردية؟","options":["8,000 pounds","10,000 pounds","12,000 pounds","17,000 pounds"],"explanation":"تحدد ولاية أوريغون الوزن على أي عجلة فردية بـ 10,000 pounds. المصدر: ORS 818.010 (الوزن الأقصى المسموح به)."},"15":{"q":"إن 'الحمولة القابلة للتقسيم' التي تتجاوز حد 80,000-pound في أوريغون هي تلك التي:","options":["لا يمكن فصلها دون تكلفة باهظة أو خطر التلف","يمكن تقسيمها بشكل معقول إلى حمولات أصغر قانونية","تُصنف دائماً على أنها مواد خطرة","يجب نقلها ليلاً فقط"],"explanation":"يمكن تقسيم الحمولة القابلة للتقسيم بشكل معقول إلى حمولات أصغر قانونية؛ وفي أوريغون قد تتجاوز هذه الحمولات 80,000 pounds فقط بموجب تصريح الوزن الممدد من ODOT (الحمولة القابلة للتقسيم)، على عكس الحمولات غير القابلة للتقسيم التي تستخدم تصاريح استثناء تجاوز الأبعاد. المصدر: Oregon DOT Commerce and Compliance Division."},"16":{"q":"دون تصريح، ما هو الحد الأقصى المسموح به لبروز الحمولة من مقدمة (FRONT) المركبة في أوريغون؟","options":["3 feet","4 feet","5 feet","6 feet"],"explanation":"تسمح ولاية أوريغون ببروز أمامي أقصى للحمولة قدره 4 feet دون تصريح؛ ويتطلب البروز الأمامي الأكبر تصريح تجاوز الأبعاد ووضع الأعلام. المصدر: ORS 818.080 وOregon DOT أبعاد المركبات القانونية."},"17":{"q":"في المعادلة الفيدرالية للجسور كما تُطبق في أوريغون، فإن زيادة التباعد بين المحاور الخارجية لمجموعة ما، مع الحفاظ على عدد المحاور نفسه، عموماً:","options":["تقلل الوزن الإجمالي المسموح به","ليس لها تأثير على الوزن المسموح به","تزيد الوزن الإجمالي المسموح به","تبطل تسجيل الشاحنة"],"explanation":"نظراً لأن L (تباعد المحاور) في البسط، فإن زيادة المسافة بين المحاور الخارجية تزيد الوزن الإجمالي المسموح به لتلك المجموعة من المحاور؛ وتُقيَّد المحاور المتقاربة لحماية الجسور. المصدر: المعادلة الفيدرالية للجسور كما تطبقها Oregon DOT؛ ORS 818.010."},"18":{"q":"تمنح أوريغون بعض تسامحات الوزن والتصاريح ذات الرسوم المخفضة لأي نوع من أنواع النقل المهمة لاقتصاد الولاية؟","options":["حافلات الركاب المستأجَرة","نقل المنتجات الزراعية ومنتجات الغابات (جذوع الأشجار)","شاحنات توصيل الطرود بين الولايات","شاحنات النقل المستأجَرة"],"explanation":"توفر ولاية أوريغون تصاريح وأحكام وزن محددة للسلع الزراعية ومنتجات الغابات/جذوع الأشجار (مثل تسامحات وزن التسجيل المخفضة وتصاريح وزن جذوع الأشجار الممددة) بما يعكس أهمية الزراعة والأخشاب للولاية. المصدر: Oregon DOT Commerce and Compliance Division وأحكام تصاريح الفصل 818 من ORS."},"19":{"q":"في أوريغون، أي فئة من رخصة القيادة التجارية CDL مطلوبة لقيادة أي تركيبة من المركبات بتصنيف وزن إجمالي مركّب (GCWR) قدره 26,001 pounds أو أكثر، بشرط أن تكون المركبة المقطورة أثقل من 10,000 pounds؟","options":["Class A","Class B","Class C","Class D"],"explanation":"تتبع ولاية أوريغون فئات CDL القياسية: تغطي رخصة CDL من Class A أي تركيبة من المركبات بتصنيف GCWR قدره 26,001 lbs أو أكثر حيث تتجاوز الوحدة المقطورة 10,000 lbs. المصدر: دليل السائق التجاري في أوريغون / فئات رخص القيادة في Oregon DMV (مطابق لـ 49 CFR 383.91؛ ORS 807.031)."},"20":{"q":"بموجب قواعد أوريغون، أي فئة من CDL تغطي مركبة واحدة بتصنيف وزن المركبة الإجمالي (GVWR) قدره 26,001 pounds أو أكثر، أو مركبة من هذا القبيل تقطر وحدة لا تتجاوز 10,000 pounds؟","options":["Class A","Class B","Class C","Class M"],"explanation":"تغطي رخصة CDL من Class B في أوريغون مركبة واحدة بتصنيف GVWR قدره 26,001 lbs أو أكثر، أو مركبة من هذا القبيل تقطر مقطورة لا تتجاوز 10,000 lbs. المصدر: دليل السائق التجاري في أوريغون / فئات رخص القيادة في Oregon DMV (49 CFR 383.91)."},"21":{"q":"في أوريغون، فإن مركبة أصغر لا تستوفي حدود وزن Class A أو Class B تظل تتطلب رخصة CDL من Class C إذا كانت مصممة لنقل عدد لا يقل عن كم شخصاً، بما في ذلك السائق؟","options":["10","12","16","24"],"explanation":"تُطلب رخصة CDL من Class C لمركبة (لا تستوفي Class A أو B) مصممة لحمل 16 شخصاً أو أكثر بما في ذلك السائق، أو تُستخدم لنقل مواد خطرة تتطلب لوحات تحذيرية. المصدر: دليل السائق التجاري في أوريغون / فئات CDL في Oregon DMV (49 CFR 383.91)."},"22":{"q":"إلى جانب حمل 16 راكباً أو أكثر، ما هو الشرط الآخر الذي يتطلب رخصة CDL من Class C في أوريغون لمركبة صغيرة جداً بحيث لا تكون Class A أو B؟","options":["قطر أي مقطورة تزيد عن 5,000 pounds","نقل المواد الخطرة بكميات تتطلب لوحات تحذيرية","العمل بعد حلول الظلام على طريق سريع تابع للولاية","حمل أي منتجات زراعية مقابل أجر"],"explanation":"تتطلب أوريغون رخصة CDL من Class C لمركبة أصغر تُستخدم لنقل المواد الخطرة بكميات تتطلب لوحات تحذيرية (أو لحمل 16 شخصاً أو أكثر). المصدر: دليل السائق التجاري في أوريغون؛ فئات CDL في Oregon DMV (49 CFR 383.91)."},"23":{"q":"أي رمز تأييد تستخدمه أوريغون لتأييد المواد الخطرة (HazMat) على رخصة CDL؟","options":["H","N","T","X"],"explanation":"يُرمز لتأييد المواد الخطرة بالرمز 'H' في أوريغون. (يمثل الرمز 'X' تأييداً مدمجاً للصهاريج والمواد الخطرة.) المصدر: تأييدات وقيود CDL في Oregon DMV؛ دليل السائق التجاري في أوريغون."},"24":{"q":"يحتاج سائق في أوريغون إلى تشغيل مركبة تجارية تجرّ مقطورات مزدوجة أو ثلاثية. أي تأييد مطلوب؟","options":["تأييد P","تأييد N","تأييد T","تأييد S"],"explanation":"تأييد 'T' (المزدوجة/الثلاثية) مطلوب في أوريغون لقيادة أي مركبة آلية تجارية تجرّ مقطورات مزدوجة أو ثلاثية، ويُحصل عليه باجتياز اختبار المعرفة. المصدر: تأييدات CDL في Oregon DMV؛ دليل السائق التجاري في أوريغون."},"25":{"q":"في أوريغون، يكون تأييد مركبة الصهريج (N) مطلوباً عندما تكون المركبة الآلية التجارية مصممة لنقل السوائل أو الغاز في صهريج بسعة مصنّفة تزيد عن 119 gallons لكل صهريج بشكل فردي، وبسعة إجمالية مصنّفة لا تقل عن كم gallons؟","options":["500 gallons","750 gallons","1,000 gallons","1,500 gallons"],"explanation":"تتطلب أوريغون تأييد N (الصهريج) لمركبة تنقل السوائل أو الغاز في صهريج بسعة مصنّفة تزيد عن 119 gallons بشكل فردي وبسعة إجمالية مصنّفة قدرها 1,000 gallons أو أكثر. المصدر: دليل السائق التجاري في أوريغون؛ تأييدات CDL في Oregon DMV (49 CFR 383.5)."},"26":{"q":"أي تأييد CDL في أوريغون مطلوب لقيادة مركبة مصممة لحمل 16 شخصاً أو أكثر، بما في ذلك السائق؟","options":["P (الركاب)","S (حافلة المدرسة)","T (المزدوجة/الثلاثية)","N (الصهريج)"],"explanation":"تأييد 'P' (الركاب) مطلوب في أوريغون لتشغيل مركبة مصممة لنقل 16 راكباً أو أكثر بما في ذلك السائق؛ ويتطلب اختبار معرفة واختبار مهارات. المصدر: تأييدات CDL في Oregon DMV؛ دليل السائق التجاري في أوريغون."},"27":{"q":"لقيادة حافلة مدرسية في أوريغون، أي تأييد يجب على حامل CDL إضافته بالإضافة إلى استيفاء متطلبات مركبة الركاب؟","options":["تأييد H","تأييد S","تأييد T","تأييد X"],"explanation":"تأييد 'S' (حافلة المدرسة) مطلوب لقيادة حافلة مدرسية في أوريغون؛ ويجب على مقدم الطلب أيضاً أن يحمل تأييد P ويجتاز اختبار معرفة ومهارات خاصاً بالحافلات المدرسية. المصدر: تأييدات CDL في Oregon DMV؛ دليل السائق التجاري في أوريغون."},"28":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في أوريغون مقيّدة بالقيادة التجارية داخل الولاية (داخل أوريغون فقط)؟","options":["16 years old","18 years old","21 years old","25 years old"],"explanation":"تتطلب أوريغون أن يكون عمر مقدم الطلب 18 عاماً على الأقل للحصول على CDL داخل الولاية؛ أما القيادة بين الولايات فتتطلب سن 21. المصدر: 'الحصول على CDL أو CLP' في Oregon DMV؛ دليل السائق التجاري في أوريغون."},"29":{"q":"بموجب قواعد أوريغون، ما هو الحد الأدنى للعمر لقيادة مركبة آلية تجارية في التجارة بين الولايات؟","options":["18 years old","19 years old","21 years old","23 years old"],"explanation":"تتطلب أوريغون أن يكون عمر السائق 21 عاماً على الأقل لتشغيل مركبة آلية تجارية في التجارة بين الولايات؛ ويُسمح بالعمل داخل الولاية فقط في سن 18. المصدر: 'الحصول على CDL أو CLP' في Oregon DMV؛ دليل السائق التجاري في أوريغون."},"30":{"q":"في أوريغون، كم من الوقت يجب أن يحمل الشخص تصريح متعلم تجاري (CLP) صالحاً قبل أن يُسمح له بإجراء اختبار مهارات CDL؟","options":["7 أيام على الأقل","14 يوماً على الأقل","30 يوماً على الأقل","60 يوماً على الأقل"],"explanation":"تتطلب أوريغون أن يحمل مقدم الطلب CLP صالحاً لمدة 14 يوماً على الأقل قبل إجراء اختبار مهارات CDL، بما يعكس فترة الانتظار الإلزامية الفيدرالية. المصدر: دليل السائق التجاري في أوريغون (معلومات أوريغون)؛ Oregon DMV (49 CFR 383.25)."},"31":{"q":"إلى متى تظل درجات اختبار المعرفة التجاري صالحة في أوريغون عند العمل للحصول على CDL؟","options":["ثلاثة أشهر","ستة أشهر","سنة واحدة","سنتان"],"explanation":"تنص أوريغون على أن درجات اختبار المعرفة التجاري صالحة لمدة ستة أشهر؛ ويجب إكمال طلب CDL ضمن هذه المدة. المصدر: دليل السائق التجاري في أوريغون (معلومات أوريغون)؛ 'الحصول على CDL أو CLP' في Oregon DMV."},"32":{"q":"أي مما يلي يجب على مقدم الطلب تقديمه إلى Oregon DMV عند التقدم بطلب للحصول على CDL أو CLP؟","options":["خطاب موثّق من صاحب العمل فقط","إثبات الاسم القانوني الكامل والهوية وتاريخ الميلاد والوضع القانوني في الولايات المتحدة وعنوان الإقامة ورقم الضمان الاجتماعي","جواز سفر ولا شيء غيره","شهادة الثانوية العامة ومرجعان"],"explanation":"يتطلب Oregon DMV إثبات الاسم القانوني الكامل والهوية وتاريخ الميلاد والوضع القانوني في الولايات المتحدة وعنوان الإقامة في أوريغون ورقم الضمان الاجتماعي لمقدم الطلب. المصدر: دليل السائق التجاري في أوريغون (معلومات أوريغون)؛ 'الحصول على CDL أو CLP' في Oregon DMV."},"33":{"q":"قبل إجراء اختبار مهارات CDL لأول رخصة Class A أو Class B في أوريغون، أين يجب على مقدم الطلب إكمال تدريب السائق المبتدئ (ELDT)؟","options":["أي دورة في كلية مجتمعية","مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA","مكتب ميداني لـ Oregon DMV","برنامج داخلي لصاحب العمل من أي نوع"],"explanation":"تتطلب أوريغون الحصول على تدريب ELDT من مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA (tpr.fmcsa.dot.gov) قبل تحديد موعد اختبار المهارات لأول رخصة CDL من Class A/B، أو الترقية من B إلى A، أو أول تأييد P أو S أو H. المصدر: دليل السائق التجاري في أوريغون؛ Oregon DMV (49 CFR Part 380)."},"34":{"q":"يُطلب تدريب ELDT في أوريغون قبل الاختبار لأي من هذه التأييدات لأول مرة؟","options":["المزدوجة/الثلاثية (T)","الصهريج (N)","المواد الخطرة (H)","لا يتطلب أي من التأييدات تدريب ELDT"],"explanation":"تتطلب أوريغون تدريب ELDT قبل إجراء اختبار معرفة المواد الخطرة (H) لأول مرة، وكذلك لأول تأييد P أو S ولأول رخصة CDL من Class A/B. التأييدان T وN ليسا على قائمة ELDT. المصدر: Oregon DMV؛ دليل السائق التجاري في أوريغون (49 CFR Part 380)."},"35":{"q":"إن مقدم طلب CDL في أوريغون الذي سيقود داخل أوريغون فقط ولا يخضع للقواعد الطبية الفيدرالية ينبغي أن يصادق ذاتياً تحت أي فئة؟","options":["بين الولايات غير مستثنى (NI)","بين الولايات مستثنى (EI)","داخل الولاية غير مستثنى (NA)","داخل الولاية مستثنى (EA)"],"explanation":"تقدم أوريغون أنواعاً من المصادقة الذاتية؛ فالسائق الذي يشغّل مركبة آلية تجارية من Class A أو B أو C داخل الولاية فقط يصادق على أنه داخل الولاية غير مستثنى ويجب أن يستوفي المعايير الطبية لـ CDL في أوريغون بدلاً من المعايير الفيدرالية الكاملة. المصدر: المعايير الطبية/المصادقة الذاتية لـ CDL في Oregon DMV؛ دليل السائق التجاري في أوريغون."},"36":{"q":"أي فئة من المصادقة الذاتية يوصي بها Oregon DMV لمعظم سائقي CDL حتى لا تكون رخصتهم مقيّدة دون داعٍ بالاستخدام داخل أوريغون فقط؟","options":["بين الولايات مستثنى","بين الولايات غير مستثنى","داخل الولاية غير مستثنى","داخل الولاية مستثنى"],"explanation":"يوصي Oregon DMV بأن يصادق معظم السائقين على أنهم بين الولايات غير مستثنين، وهو ما يتطلب استيفاء جميع المؤهلات الطبية الفيدرالية ويسمح أيضاً بالعمل المستثنى بين الولايات وداخل الولاية. المصدر: المصادقة الذاتية لـ CDL في Oregon DMV؛ دليل السائق التجاري في أوريغون."},"37":{"q":"للحصول على تأييد المواد الخطرة (H) في أوريغون والاحتفاظ به، يجب على السائق اجتياز تقييم تهديد أمني من إدارة أمن النقل (TSA)، بما في ذلك البصمات، الذي يجب تجديده كل كم؟","options":["كل سنتين","كل 3 سنوات","كل 5 سنوات","كل 8 سنوات"],"explanation":"يتطلب تأييد المواد الخطرة في أوريغون تقييم تهديد أمني من TSA مع فحص خلفية قائم على البصمات يجب تجديده كل خمس سنوات. المصدر: تأييدات وقيود CDL في Oregon DMV (49 CFR 1572)."},"38":{"q":"إن السائق الذي يصادق ذاتياً على أنه بين الولايات مستثنى في أوريغون يجب أن يستوفي أي معيار طبي؟","options":["لا يوجد معيار طبي على الإطلاق","المعايير الطبية الفيدرالية الكاملة بين الولايات","المعايير الطبية لـ CDL في أوريغون","فحص النظر فقط عند التجديد"],"explanation":"إن السائق في أوريغون الذي يصادق على أنه بين الولايات مستثنى يشارك فقط في عمليات مستثناة بموجب القواعد الفيدرالية (مثل 49 CFR 390.3(f) و391.2) ولا يخضع للمعايير الطبية الفيدرالية الكاملة، لكن يجب أن يستوفي المعايير الطبية لـ CDL في أوريغون. المصدر: المصادقة الذاتية لـ CDL في Oregon DMV؛ دليل السائق التجاري في أوريغون."},"39":{"q":"في أوريغون، ما هو تركيز الكحول في الدم (BAC) الذي يكون عنده أو فوقه من غير القانوني تشغيل مركبة آلية تجارية (CMV)؟","options":["0.08%","0.04%","0.02%","0.10%"],"explanation":"تعتمد أوريغون المعيار الفيدرالي للمركبات الآلية التجارية: من غير القانوني تشغيل مركبة آلية تجارية بتركيز BAC قدره 0.04% أو أكثر، أي نصف حد 0.08% للسائقين غير التجاريين. المصدر: دليل السائق التجاري في أوريغون، القسم 1 (حالات فقدان الأهلية)؛ 49 CFR 383.51."},"40":{"q":"بموجب قاعدة الموافقة الضمنية في أوريغون للسائقين التجاريين، ما الذي يكون صحيحاً عندما تشغّل مركبة آلية تجارية؟","options":["يجوز لك رفض جميع الفحوصات دون عقوبة","يُعتبر أنك قد أعطيت موافقتك على فحص الكحول","يتطلب الفحص تنازلاً موقعاً منفصلاً في كل رحلة","تنطبق الموافقة فقط فوق 0.08% BAC"],"explanation":"ينص دليل CDL في أوريغون على أنه بتشغيلك مركبة آلية تجارية يُعتبر أنك أعطيت موافقتك على فحص الكحول. ويحمل رفض الفحص نفس فقدان الأهلية المترتب على المخالفة الكبرى. المصدر: دليل السائق التجاري في أوريغون، القسم 1؛ ORS 813.100."},"41":{"q":"أُدين حامل CDL في أوريغون بقيادة مركبة آلية تجارية بتركيز BAC قدره 0.04% أو أعلى للمرة الأولى (FIRST)، دون حمل مواد خطرة. ما هو الحد الأدنى لفترة فقدان الأهلية؟","options":["60 days","90 days","1 year","3 years"],"explanation":"تؤدي أول مخالفة كبرى، بما في ذلك تركيز BAC في مركبة آلية تجارية قدره 0.04% أو أعلى، إلى فقدان أهلية السائق لمدة سنة واحدة على الأقل في أوريغون. المصدر: دليل السائق التجاري في أوريغون، القسم 1؛ 49 CFR 383.51."},"42":{"q":"إذا وقعت أول مخالفة كبرى (مثل BAC قدره 0.04%) أثناء تشغيل السائق لمركبة آلية تجارية تحمل لوحات تحذيرية للمواد الخطرة، فما هو الحد الأدنى لفقدان الأهلية في أوريغون؟","options":["1 year","18 months","3 years","5 years"],"explanation":"عندما تقع أول مخالفة كبرى في مركبة آلية تجارية تحمل لوحات تحذيرية للمواد الخطرة، يزداد فقدان الأهلية إلى 3 سنوات على الأقل. المصدر: دليل السائق التجاري في أوريغون، القسم 1؛ 49 CFR 383.51."},"43":{"q":"ما هو فقدان الأهلية في أوريغون لثاني (SECOND) مخالفة كبرى يرتكبها حامل CDL؟","options":["3 years","5 years","10 years","مدى الحياة"],"explanation":"تؤدي ثاني مخالفة كبرى (على سبيل المثال، ثانٍ قيادة تحت تأثير الكحول في مركبة آلية تجارية، أو مخالفة كبرى بعد مخالفة سابقة) إلى فقدان أهلية CDL مدى الحياة في أوريغون. المصدر: دليل السائق التجاري في أوريغون، القسم 1؛ 49 CFR 383.51."},"44":{"q":"يرفض حامل CDL في أوريغون الخضوع لفحص الكحول أثناء تشغيل مركبة آلية تجارية (أول حدوث). كيف يُعامل هذا لأغراض فقدان الأهلية؟","options":["لا عقوبة على CDL، فقط غرامة","يُعامل كمخالفة كبرى: فقدان أهلية لمدة سنة واحدة على الأقل","فقدان أهلية لمدة 30 يوماً","يُعامل كمخالفة خطيرة: 60 يوماً"],"explanation":"يُدرج رفض فحص الكحول ضمن المخالفات الكبرى ويحمل فقدان أهلية لمدة سنة واحدة على الأقل (3 سنوات إذا كانت المركبة تحمل لوحات تحذيرية للمواد الخطرة)، مثله مثل رسوب فحص BAC. المصدر: دليل السائق التجاري في أوريغون، القسم 1؛ 49 CFR 383.51؛ ORS 813.100."},"45":{"q":"يستخدم حامل CDL في أوريغون مركبة آلية تجارية لارتكاب جناية تتعلق بمادة خاضعة للرقابة (تصنيع أو توزيع أو صرف). ما هو فقدان الأهلية؟","options":["1 year","3 years","10 years","مدى الحياة، دون إمكانية إعادة الترخيص"],"explanation":"يؤدي استخدام مركبة آلية تجارية لارتكاب جناية تتعلق بالمواد الخاضعة للرقابة إلى فقدان أهلية مدى الحياة دون إمكانية إعادة الترخيص. المصدر: دليل السائق التجاري في أوريغون، القسم 1؛ 49 CFR 383.51."},"46":{"q":"تبيّن أن سائق CDL في أوريغون لديه كمية قابلة للكشف من الكحول أقل من (BELOW) 0.04% أثناء أداء الواجب. ماذا يحدث؟","options":["لا شيء، فهي أقل من الحد القانوني","يُوقف عن الخدمة لمدة 24 ساعة","فقدان أهلية لمدة سنة واحدة","يُوقف عن الخدمة لمدة ساعة واحدة"],"explanation":"إن أي كمية كحول قابلة للكشف أقل من 0.04% لا تستدعي فقدان أهلية بسبب مخالفة كبرى، لكنها تضع السائق خارج الخدمة لمدة 24 ساعة. المصدر: دليل السائق التجاري في أوريغون، القسم 1؛ 49 CFR 392.5."},"47":{"q":"أي مما يلي يُصنف على أنه 'مخالفة مرورية خطيرة' لحامل CDL في أوريغون؟","options":["الوقوف في منطقة ممنوع الوقوف فيها","السرعة المفرطة، 15 mph أو أكثر فوق الحد","مصباح علامة محترق","القيادة 5 mph فوق الحد"],"explanation":"تشمل المخالفات المرورية الخطيرة السرعة المفرطة المعرّفة على أنها 15 mph أو أكثر فوق الحد المعلن، والقيادة المتهورة، وتغيير المسار غير السليم أو المتقلب، والاقتراب الشديد. المصدر: دليل السائق التجاري في أوريغون، القسم 1؛ 49 CFR 383.51."},"48":{"q":"كم عدد المخالفات المرورية الخطيرة خلال فترة 3 سنوات التي تستدعي فقدان الأهلية في أوريغون، ولكم تكون مدة أول (FIRST) فقدان أهلية من هذا القبيل؟","options":["مخالفة واحدة؛ 30 يوماً","مخالفتان؛ 60 يوماً على الأقل","مخالفتان؛ 30 يوماً على الأقل","3 مخالفات؛ 60 يوماً على الأقل"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان خلال 3 سنوات إلى فقدان أهلية لمدة 60 يوماً على الأقل. المصدر: دليل السائق التجاري في أوريغون، القسم 1؛ 49 CFR 383.51."},"49":{"q":"يرتكب حامل CDL في أوريغون ثلاث (THREE) مخالفات مرورية خطيرة خلال فترة 3 سنوات. ما هو الحد الأدنى لفقدان الأهلية؟","options":["60 days","90 days","120 days","1 year"],"explanation":"تؤدي ثلاث مخالفات مرورية خطيرة أو أكثر خلال 3 سنوات إلى فقدان أهلية لمدة 120 يوماً على الأقل. المصدر: دليل السائق التجاري في أوريغون، القسم 1؛ 49 CFR 383.51."},"50":{"q":"هل تُحتسب المخالفات المرورية الخطيرة في فقدان أهلية CDL عند ارتكابها في مركبة السائق الشخصية (PERSONAL) (غير التجارية)؟","options":["لا، تُحتسب المخالفات في المركبة الآلية التجارية فقط","نعم، إذا أدت إلى تعليق الرخصة أو إلغائها","فقط إذا كان الكحول متورطاً","تُحتسب فقط المخالفات على الطرق السريعة بين الولايات"],"explanation":"تُحتسب المخالفات المرورية الخطيرة المرتكبة في مركبة غير تجارية ضد حامل CDL إذا أدت الإدانة إلى تعليق رخصة قيادة السائق أو إلغائها. المصدر: دليل السائق التجاري في أوريغون، القسم 1؛ 49 CFR 383.51."},"51":{"q":"بالنسبة لثاني (SECOND) مخالفة لمعبر السكة الحديدية مع الطريق السريع خلال 3 سنوات، ما هو الحد الأدنى لفقدان الأهلية في أوريغون؟","options":["60 days","120 days","180 days","1 year"],"explanation":"تؤدي ثاني مخالفة لمعبر السكة الحديدية مع الطريق السريع خلال فترة 3 سنوات إلى فقدان أهلية لمدة 120 يوماً على الأقل. المصدر: دليل السائق التجاري في أوريغون، القسم 1؛ 49 CFR 383.51."},"52":{"q":"ما هو الحد الأدنى لفقدان الأهلية في أوريغون لثالث (THIRD) مخالفة لمعبر السكة الحديدية مع الطريق السريع خلال فترة 3 سنوات؟","options":["120 days","180 days","1 year","3 years"],"explanation":"تؤدي ثالث مخالفة لمعبر السكة الحديدية مع الطريق السريع أو ما يليها خلال 3 سنوات إلى فقدان أهلية لمدة سنة واحدة على الأقل. المصدر: دليل السائق التجاري في أوريغون، القسم 1؛ 49 CFR 383.51."},"53":{"q":"ينتهك حامل CDL في أوريغون أمر إيقاف عن الخدمة لأول (FIRST) مرة بينما لا (NOT) ينقل مواد خطرة أو ركاباً. ما هو الحد الأدنى لفقدان الأهلية؟","options":["60 days","90 days","180 days","1 year"],"explanation":"يؤدي أول انتهاك لأمر إيقاف عن الخدمة (دون مواد خطرة، دون ركاب) إلى فقدان أهلية لمدة 180 يوماً على الأقل. المصدر: دليل السائق التجاري في أوريغون، القسم 1 / صفحة إدانات السائق التجاري في ODOT؛ 49 CFR 383.51."},"54":{"q":"ينتهك سائق أمر إيقاف عن الخدمة لأول (FIRST) مرة بينما ينقل مواد خطرة (أو يقود مركبة مصممة لـ 16 راكباً أو أكثر). ما هو الحد الأدنى لفقدان الأهلية في أوريغون؟","options":["180 days","1 year","3 years","5 years"],"explanation":"يؤدي أول انتهاك لأمر إيقاف عن الخدمة أثناء نقل مواد خطرة أو تشغيل مركبة لـ 16 راكباً أو أكثر إلى فقدان أهلية لمدة سنة واحدة على الأقل، أطول من خط الأساس البالغ 180 يوماً. المصدر: صفحة إدانات السائق التجاري في ODOT؛ 49 CFR 383.51."},"55":{"q":"ما هو الحد الأدنى لفقدان الأهلية لثاني (SECOND) انتهاك لأمر إيقاف عن الخدمة خلال 10 سنوات، لا يتعلق بمواد خطرة أو ركاب؟","options":["1 year","2 years","3 years","5 years"],"explanation":"يؤدي ثاني انتهاك لأمر إيقاف عن الخدمة خلال 10 سنوات (دون مواد خطرة، دون ركاب) إلى فقدان أهلية لمدة 3 سنوات على الأقل؛ وإذا تورطت مواد خطرة أو ركاب يرتفع إلى 5 سنوات على الأقل. المصدر: صفحة إدانات السائق التجاري في ODOT؛ 49 CFR 383.51."},"56":{"q":"إلى جانب فقدان أهلية الرخصة، ما هي العقوبة المدنية التي تفرضها أوريغون/ODOT على السائق لأول (FIRST) انتهاك لأمر إيقاف عن الخدمة؟","options":["$650","$1,000","$3,861","$7,723"],"explanation":"تفرض ODOT عقوبة مدنية قدرها $3,861 لأول انتهاك لأمر إيقاف عن الخدمة و$7,723 لثاني انتهاك أو ما يليه، بالإضافة إلى فقدان الأهلية. المصدر: صفحة إدانات السائق التجاري في ODOT؛ 49 CFR 383.53."},"57":{"q":"بموجب القواعد التي تنطبق على سائقي CDL في أوريغون، ما الممنوع فيما يتعلق بالهواتف المحمولة أثناء قيادة مركبة آلية تجارية؟","options":["جميع الاتصالات اللاسلكية محظورة","حمل هاتف لإجراء مكالمة، أو الضغط على أكثر من زر واحد، أو إرسال الرسائل النصية","الاتصال بدون استخدام اليدين محظور أيضاً","يجب إيقاف تشغيل الهواتف في جميع الأوقات"],"explanation":"لا يجوز لسائقي المركبات الآلية التجارية حمل هاتف محمول للتحدث، أو الاتصال بالضغط على أكثر من زر واحد، أو إرسال/قراءة الرسائل النصية أثناء القيادة؛ وتُعد مخالفة الرسائل النصية/الهاتف المحمول مخالفة مرورية خطيرة (الحد الأقصى للغرامة الفيدرالية $2,750) تُحتسب ضمن فقدان الأهلية لمدة 60/120 يوماً. المصدر: دليل السائق التجاري في أوريغون، القسم 1؛ 49 CFR 392.80-392.82، 383.51."},"58":{"q":"بموجب قانون \"أفسح الطريق\" في ولاية أوريغون، عندما تقترب من مركبة طوارئ أو سحب أو مساعدة على جانب الطريق أو مركبة تُشغّل أضواء التحذير وهي متوقفة على طريق متعدد الحارات، ولا تستطيع بأمان الانتقال إلى حارة غير مجاورة، فماذا يجب أن تفعل؟","options":["أن تُبطئ إلى سرعة أقل بمقدار 5 mph على الأقل من حد السرعة المُعلن أو المُحدد","أن تتوقف توقفاً تاماً حتى تغادر المركبة","أن تُبطئ إلى أقل بالضبط بمقدار 10 mph من حد السرعة المُعلن","أن تحافظ على السرعة المُعلنة لكن مع إطلاق البوق"],"explanation":"يقتضي قانون \"أفسح الطريق\" في أوريغون (ORS 811.147) أن ينتقل السائقون إلى حارة غير مجاورة إن أمكن؛ وإذا تعذّر ذلك، فعليهم الإبطاء إلى ما لا يقل عن 5 mph دون حد السرعة المُعلن أو المُحدد والمتابعة بحذر. المصدر: ORS 811.147؛ دليل سائق أوريغون."},"59":{"q":"تُصنّف مخالفة قانون \"أفسح الطريق\" في أوريغون (عدم الحفاظ على مسافة آمنة من مركبة طوارئ أو مساعدة على جانب الطريق أو سحب أو سيارة إسعاف متوقفة) ضمن أي نوع من المخالفات؟","options":["مخالفة مرورية من الفئة B","مخالفة مرورية من الفئة A","جنحة من الفئة C","مخالفة مرورية من الفئة D"],"explanation":"عدم الحفاظ على مسافة آمنة من مركبة طوارئ أو مساعدة على جانب الطريق أو سحب أو سيارة إسعاف بموجب قانون \"أفسح الطريق\" في أوريغون هو مخالفة مرورية من الفئة B. المصدر: ORS 811.147."},"60":{"q":"في أوريغون، عندما تتوقف حافلة مدرسية على طريق ذي اتجاهين وأضواؤها الحمراء تومض، فعلى أي مسافة يجب أن يتوقف السائق المقترب خلفها؟","options":["20 feet أو أكثر من الحافلة","10 feet أو أكثر من الحافلة","30 feet أو أكثر من الحافلة","50 feet أو أكثر من الحافلة"],"explanation":"تقتضي أوريغون أن يتوقف السائقون على بُعد 20 feet أو أكثر من حافلة مدرسية تُشغّل أضواء تحذير حمراء وامضة، وأن يبقوا متوقفين حتى تتوقف الأضواء عن الوميض. المصدر: ORS 811.155؛ دليل سائق أوريغون."},"61":{"q":"بموجب قانون أوريغون، ما هي الحالة الوحيدة التي لا يُطلب فيها من السائق القادم في الاتجاه المعاكس أن يتوقف لحافلة مدرسية تُظهر أضواءً حمراء وامضة؟","options":["أن تكون الحافلة متوقفة على طريق مختلف، مفصول بحاجز أو جزيرة وسطية مادية","أن تكون الحافلة متوقفة في منطقة سكنية بحد سرعة 25 mph","أن توجد حارة وسطية لليسار ثنائية الاتجاه بين السائق والحافلة","أن يكون الطريق مطلياً بخط مركزي أصفر متصل"],"explanation":"في أوريغون لا يُلزم السائق بالتوقف إلا إذا كانت الحافلة التي تُظهر أضواءً حمراء على طريق مختلف، أي أن الطريق السريع مقسّم بحاجز أو جزيرة وسطية مادية إلى طرق منفصلة. الخط الأصفر المطلي أو حارة الانعطاف الوسطية لا يُنشئان طرقاً منفصلة، لذا يجب أن تتوقف جميع الحارات. المصدر: ORS 811.155؛ دليل سائق أوريغون."},"62":{"q":"ما هو مستوى المخالفة المرورية في أوريغون عند عدم التوقف لأضواء السلامة الحمراء الوامضة لحافلة مدرسية؟","options":["مخالفة مرورية من الفئة A","مخالفة مرورية من الفئة B","مخالفة مرورية من الفئة C","جنحة من الفئة A"],"explanation":"عدم التوقف لأضواء السلامة الخاصة بالحافلة بموجب ORS 811.155 هو مخالفة مرورية من الفئة A، وهي أخطر فئة من فئات المخالفات المرورية في أوريغون. المصدر: ORS 811.155."},"63":{"q":"عندما يتعيّن على سائق CDL في أوريغون التوقف عند معبر سكة حديد في مركبة تحمل لوحات مواد خطرة (HazMat) ولا يوجد خط توقف معلّم، فأين يجب أن تتوقف المركبة؟","options":["ليس أقل من 15 feet ولا أكثر من 50 feet من أقرب سكة","ليس أقل من 10 feet ولا أكثر من 25 feet من أقرب سكة","ليس أقل من 5 feet ولا أكثر من 15 feet من أقرب سكة","ليس أقل من 50 feet ولا أكثر من 100 feet من أقرب سكة"],"explanation":"يجب على سائق مركبة تحمل لوحات HazMat، أو حمولة كلور، أو صهريج شحن مواد خطرة (محمّل أو فارغ) أن يتوقف على بُعد لا يقل عن 15 feet ولا يزيد عن 50 feet من أقرب سكة عند عدم وجود خط توقف. المصدر: دليل السائق التجاري في أوريغون القسم 9؛ ORS 811.460."},"64":{"q":"أثناء عبور سكك الحديد في مركبة تحمل لوحات HazMat في أوريغون، ما الذي تمنعه القاعدة تحديداً؟","options":["تبديل التروس يدوياً أثناء التواجد على السكك","استخدام فرملة المحرك أثناء التواجد على السكك","تشغيل أضواء التحذير الرباعية أثناء التواجد على السكك","إطلاق البوق أثناء التواجد على السكك"],"explanation":"تقتضي قاعدة المعابر عالية الخطورة في أوريغون أن يعبر السائق في ترس لا يتطلب تغيير التروس يدوياً، لذا يجب ألا تبدّل التروس أثناء التواجد على السكك؛ ولا تتابع إلا عندما تكون متأكداً من قدرتك على إخلاء السكك دون توقف. المصدر: ORS 811.460؛ دليل السائق التجاري في أوريغون القسم 9."},"65":{"q":"أيٌّ من هذه المركبات ليس من المركبات \"عالية الخطورة\" التي يقتضي قانون أوريغون توقفها عند كل معبر سكة حديد؟","options":["شاحنة مسطحة فارغة تنقل بضائع عادية","حافلة مدرسية","صهريج شحن محمّل أو فارغ ينقل مواد خطرة","حافلة تجارية تنقل ركاباً"],"explanation":"يُعدّد ORS 811.460 المركبات عالية الخطورة التي يجب أن تتوقف عند المعابر: الحافلات المدرسية، وبعض حافلات الأنشطة المدرسية ونقل العمال، والحافلات التجارية، والمركبات التي تنقل متفجرات/مواد قابلة للاشتعال/مواد أكّالة، وصهاريج المواد الخطرة (محمّلة أو فارغة). أما شاحنة الشحن العادية ذات الحمولة غير الخطرة فلا يُطلب توقفها إلا إذا اقتضت الإشارات ذلك. المصدر: ORS 811.460."},"66":{"q":"في أوريغون، ما هو الحد الأقصى القياسي للسرعة لمركبة تجارية يزيد تصنيف وزنها الإجمالي (GVWR) عن 10,000 pounds ما لم تُعلَن سرعة مختلفة؟","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"ما لم تُعلَن سرعة مختلفة، فإن الحد الأقصى الافتراضي للمركبات التجارية التي يزيد GVWR لها عن 10,000 lbs (أو الجرارات الشاحنة التي يزيد GVWR لها عن 8,000 lbs) هو 55 mph. المصدر: ORS 811.111؛ ORS 810.180."},"67":{"q":"وفقاً لقاعدة أوريغون، فإن أعلى سرعة يجوز لوزارة النقل تحديدها للمركبات التجارية على طريق سريع بين الولايات هي:","options":["65 mph","70 mph","60 mph","75 mph"],"explanation":"يجوز لـ ODOT تحديد سرعات مقررة للطرق بين الولايات لكن لا يمكن أن تتجاوز 65 mph للمركبات التجارية (الحد الأقصى للمركبات الأخرى هو 70 mph). وقد رُفعت بعض مقاطع الطرق بين الولايات في أوريغون إلى 60 mph للشاحنات حيث تسير السيارات بسرعة 65. المصدر: ORS 810.180؛ OAR 734-020-0010."},"68":{"q":"على طريق في أوريغون به حارتان أو أكثر تسيران في الاتجاه نفسه، ما هي المركبات المُلزَمة بالسير في الحارة اليمنى إلا عند التجاوز أو الانعطاف؟","options":["المركبات السكنية (الكامبر)، والمركبات التي تجرّ مقطورة، والمركبات التي يبلغ وزن تسجيلها 10,000 pounds أو أكثر","فقط المركبات ذات ثلاثة محاور أو أكثر","فقط المركبات التي تعرض لوحات HazMat","جميع المركبات التي تسير بأقل من 45 mph"],"explanation":"يقتضي ORS 811.325 أن تستخدم أي مركبة سكنية (كامبر)، وأي مركبة بمقطورة، وأي مركبة يبلغ وزن تسجيلها 10,000 lbs أو أكثر الحارة اليمنى على الطرق ذات الاتجاه الواحد متعددة الحارات، إلا عند التجاوز أو الانعطاف يساراً أو الاستجابة لحالة طوارئ أو تجنب حركة المرور المندمجة أو وفقاً لما توجّه به أجهزة التحكم في المرور. المصدر: ORS 811.325."},"69":{"q":"ما نوع المخالفة عند عدم إبقاء مركبة سكنية (كامبر) أو مقطورة أو شاحنة (+10,000 lbs) في الحارة اليمنى على طريق سريع متعدد الحارات في أوريغون؟","options":["مخالفة مرورية من الفئة B","مخالفة مرورية من الفئة A","مخالفة مرورية من الفئة C","مخالفة مرورية من الفئة D"],"explanation":"مخالفة اشتراط الحارة اليمنى في ORS 811.325 هي مخالفة مرورية من الفئة B. المصدر: ORS 811.325."},"70":{"q":"أيٌّ مما يلي يُعدّ استثناءً قانونياً معترفاً به يسمح لشاحنة في أوريغون (+10,000 lbs) بمغادرة الحارة اليمنى على طريق سريع متعدد الحارات؟","options":["اللحاق بمركبة أخرى تسير في الاتجاه نفسه وتجاوزها","الرغبة في الحفاظ على سرعة انطلاق أعلى","الحفاظ على مسافة أتباع أطول من المركبة التي أمامك","تجنّب تآكل رصف الحارة اليمنى"],"explanation":"يسمح ORS 811.325 بمغادرة الحارة اليمنى للّحاق بمركبة وتجاوزها قانونياً، أو للاستعداد للانعطاف يساراً، أو للاستجابة لظروف طارئة، أو لتجنّب حركة المرور الداخلة من حارات الاندماج/التسارع، أو وفقاً لما توجّه به أجهزة التحكم في المرور. المصدر: ORS 811.325."},"71":{"q":"على طريق سريع مقسّم أو أحادي الاتجاه في أوريغون، أين يجب على سائق CDL وضع مثلثات التحذير الطارئة الثلاثة عند التوقف على الطريق؟","options":["ضمن 10 feet من المؤخرة، وعلى بُعد 100 feet و200 feet باتجاه حركة المرور القادمة","ضمن 25 feet من المؤخرة، وعلى بُعد 50 feet و150 feet باتجاه حركة المرور القادمة","ضمن 10 feet من المقدمة، وعلى بُعد 100 feet و300 feet باتجاه حركة المرور القادمة","ضمن 50 feet من المؤخرة، وعلى بُعد 100 feet و250 feet باتجاه حركة المرور القادمة"],"explanation":"على طريق سريع أحادي الاتجاه أو مقسّم، ضع جهاز تحذير واحداً ضمن 10 feet من المؤخرة باتجاه حركة المرور القادمة، وواحداً على بُعد نحو 100 feet للخلف، وواحداً على بُعد نحو 200 feet للخلف. هذا المعيار الفيدرالي (49 CFR 392.22) يُدرَّس في دليل السائق التجاري في أوريغون. المصدر: دليل السائق التجاري في أوريغون؛ 49 CFR 392.22."},"72":{"q":"على طريق في أوريغون ذي حارتين واتجاهين، بعد توقف مركبة CDL على الجزء المُستخدَم للسير، خلال كم دقيقة يجب أن يكون السائق قد وضع أجهزة التحذير الطارئة؟","options":["خلال 10 minutes","خلال 5 minutes","خلال 15 minutes","خلال 30 minutes"],"explanation":"يجب على سائق CDL وضع أجهزة التحذير (ثلاثة مثلثات أو ما يعادلها) خلال 10 minutes من التوقف على الجزء المُستخدَم للسير أو على كتف الطريق. المصدر: دليل السائق التجاري في أوريغون؛ 49 CFR 392.22."},"73":{"q":"في أوريغون، ما هو الحد الأقصى القانوني لعرض المركبة/الحمولة قبل أن يُطلب تصريح للأبعاد الزائدة؟","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"الحد الأقصى القانوني للعرض في أوريغون هو 8 feet 6 inches؛ والحمولات التي تتجاوز ذلك تتطلب تصريح أبعاد زائدة من شعبة التجارة والامتثال التابعة لـ ODOT. المصدر: ORS 818.080؛ أبعاد المركبات القانونية لدى ODOT."},"74":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة في أوريغون قبل أن يُطلب تصريح للأبعاد الزائدة؟","options":["14 feet 0 inches","13 feet 6 inches","13 feet 0 inches","15 feet 0 inches"],"explanation":"الحد الأقصى القانوني للارتفاع في أوريغون هو 14 feet 0 inches؛ والحمولات التي تتجاوز ذلك تتطلب تصريح أبعاد زائدة. (لاحظ أن العديد من الولايات الأخرى تستخدم 13'6\".) المصدر: ORS 818.080؛ أبعاد المركبات القانونية لدى ODOT."},"75":{"q":"تقتضي أوريغون أن تحمل جميع المركبات التي يزيد وزنها الإجمالي (GVW) عن 10,000 lbs سلاسل إطارات خلال موسم الثلوج:","options":["كلما وُجدت ظروف قد يلزم أو يُطلب فيها استخدامها","فقط عند السفر شرق سلسلة جبال كاسكيد","فقط في عطلات نهاية الأسبوع من ديسمبر حتى فبراير","فقط إذا كانت المركبة تفتقر إلى إطارات مزودة بمسامير"],"explanation":"يقتضي قانون أوريغون أن تحمل المركبات التي يزيد وزنها الإجمالي (GVW) عن 10,000 lbs سلاسل كلما وُجدت ظروف قد يلزم أو يُطلب فيها استخدام السلاسل، وأن تركّبها عندما يكون قانون السلاسل سارياً (عادةً من أكتوبر حتى مارس على الممرات الجبلية). المصدر: شعبة التجارة والامتثال التابعة لـ ODOT، السلاسل وإطارات الجر."},"76":{"q":"خلال أي فترة يكون استخدام الإطارات المزودة بمسامير قانونياً على طرق أوريغون؟","options":["من 1 نوفمبر حتى 31 مارس","من 1 أكتوبر حتى 30 أبريل","من 15 نوفمبر حتى 15 أبريل","من 1 ديسمبر حتى 1 مارس"],"explanation":"الإطارات المزودة بمسامير قانونية في أوريغون فقط من 1 نوفمبر حتى 31 مارس؛ واستخدامها خارج هذه الفترة قد يستوجب غرامة. المصدر: ODOT / Oregon TripCheck؛ أحكام ORS الخاصة بالإطارات المزودة بمسامير."},"77":{"q":"تشتهر أوريغون بميزة مبكرة لإيقاف الشاحنات الهاربة على منحدر شديد في الطريق السريع بين الولايات رقم 5 (Interstate 5). أين بُنيَ واختُبر أول مهبط (سرير) إيقاف للشاحنات بانحدار سالب (هبوطي) في البلاد؟","options":["بالقرب من قمة سيسكيو (Siskiyou Summit) على I-5 في جنوب أوريغون","على منحدر كابدج هيل (Cabbage Hill) في I-84","في غفرنمنت كامب (Government Camp) على US 26 فوق جبل هود","على ممر سانتيام (Santiam Pass) في US 20"],"explanation":"بُنيَ واختُبر أول سرير إيقاف للشاحنات بانحدار سالب (هبوطي) في الولايات المتحدة عام 1977 على طول I-5 بالقرب من قمة سيسكيو (Siskiyou Summit) في جنوب أوريغون، وهو منحدر جبلي شديد الانحدار يُشدَّد فيه على استخدام منحدر الهروب. المصدر: ODOT؛ إرشادات القيادة في الجبال في دليل السائق التجاري في أوريغون."},"78":{"q":"في أوريغون، أي جهة حكومية في الولاية تصدر رخص القيادة التجارية (CDLs) وتدير عملية الاختبار؟","options":["Oregon DMV، وهي جزء من خدمات السائق والمركبات الآلية التابعة لوزارة النقل في أوريغون (ODOT)","شعبة المركبات التجارية بشرطة ولاية أوريغون","المكتب الإقليمي لإدارة سلامة الناقلات الآلية الفيدرالية (FMCSA)","أمين سر ولاية أوريغون، شعبة الشركات والترخيص"],"explanation":"تُصدِر رخص CDL في أوريغون عن طريق Oregon DMV، وهي جزء من خدمات السائق والمركبات الآلية التابعة لوزارة النقل في أوريغون (ODOT). المصدر: صفحة Oregon DMV \"Getting a CDL or CLP\"؛ دليل السائق التجاري في أوريغون."},"79":{"q":"تتطلب المركبة رخصة CDL في أوريغون بناءً على الوزن عندما يبلغ تصنيف وزنها الإجمالي (GVWR) ما لا يقل عن كم رطلاً؟","options":["26,001 pounds","10,001 pounds","18,000 pounds","33,000 pounds"],"explanation":"تتطلب أوريغون رخصة CDL لتشغيل مركبة يبلغ GVWR لها 26,001 pounds أو أكثر (وللتجميعات التي يزيد فيها وزن الوحدة المجرورة عن 10,000 lbs). المصدر: دليل السائق التجاري في أوريغون، القسم 1."},"80":{"q":"إلى جانب الوزن، ما هو حد عدد الركاب الذي يجعل المركبة تتطلب رخصة CDL في أوريغون؟","options":["مصممة لنقل 16 شخصاً أو أكثر، بما في ذلك السائق","مصممة لنقل 9 أشخاص أو أكثر، بما في ذلك السائق","مصممة لنقل 24 شخصاً أو أكثر، باستثناء السائق","مصممة لنقل 12 شخصاً أو أكثر، بما في ذلك السائق"],"explanation":"تُطلب رخصة CDL لمركبة مصممة لنقل 16 شخصاً أو أكثر، بما في ذلك السائق. والمُحفِّز الثالث هو نقل مواد خطرة تتطلب لوحات. المصدر: دليل السائق التجاري في أوريغون، القسم 1؛ 49 CFR 383.5 كما يُطبَّق في أوريغون."},"81":{"q":"عند التقدّم للحصول على رخصة CDL أو تصريح متعلّم تجاري في أوريغون، يجب على المتقدّم أن \"يُصادق ذاتياً\" على نوع التجارة التي سيعمل فيها. ما هي مجموعة الفئات التي تقدّمها أوريغون؟","options":["غير مستثنى بين الولايات، ومستثنى بين الولايات، وغير مستثنى داخل الولاية","HazMat بين الولايات، وHazMat داخل الولاية، وغير HazMat فقط","ناقل فيدرالي، وناقل تابع للولاية، وناقل خاص","تشغيل من الفئة A والفئة B والفئة C"],"explanation":"تقدّم Oregon DMV ثلاث فئات للمصادقة الذاتية: غير مستثنى بين الولايات، ومستثنى بين الولايات، وغير مستثنى داخل الولاية. (المستثنى داخل الولاية هو الفئة الرابعة لدى FMCSA؛ ولا تدرجها أوريغون بشكل منفصل.) المصدر: طلب/مصادقة ذاتية لـ CDL لدى Oregon DMV؛ 49 CFR 383.71."},"82":{"q":"متقدّم رخصة CDL في أوريغون الذي يُصادق ذاتياً بصفته \"غير مستثنى بين الولايات\" مُلزَم بفعل ماذا فيما يتعلق بالأهلية الطبية؟","options":["تزويد DMV بنسخة من شهادة فاحص طبي صالحة لدى DOT والاحتفاظ بشهادة سارية في الملف","حمل البطاقة الطبية الورقية في الشاحنة لكن عدم تسليمها لـ DMV مطلقاً","تقديم إفادة موثّقة بأنه لا حاجة لفحص طبي","اجتياز اختبار قيادة إضافي للياقة البدنية تديره DMV"],"explanation":"يجب على السائق غير المستثنى بين الولايات تزويد Oregon DMV بنسخة من شهادة فاحص طبي صالحة (بطاقة DOT الطبية)، وهو مسؤول عن الاحتفاظ بشهادة سارية في الملف، وإلا خُفِّضت رخصة CDL. المصدر: المصادقة الطبية لـ CDL لدى Oregon DMV؛ 49 CFR 383.71/391.45."},"83":{"q":"مَن المؤهَّل لإجراء فحص DOT الطبي الذي يُنتج شهادة الفاحص الطبي المستخدَمة لرخصة CDL في أوريغون؟","options":["فاحص طبي مُدرَج في السجل الوطني للفاحصين الطبيين المعتمدين لدى FMCSA","أي صيدلي مرخَّص في أوريغون","فاحص في مكتب ميداني تابع لـ Oregon DMV","أي طبيب، ما دام مرخَّصاً في أي ولاية أمريكية"],"explanation":"يجب أن يُجري فحص DOT الطبي فاحص طبي مُدرَج في السجل الوطني للفاحصين الطبيين المعتمدين لدى FMCSA. المصدر: Oregon DMV \"Getting a CDL or CLP\"؛ 49 CFR 390.103."},"84":{"q":"قبل أن يتمكن المتقدّم من إجراء اختبار مهارات CDL في أوريغون، يجب عليه أولاً الحصول على أي وثيقة؟","options":["تصريح متعلّم تجاري (CLP)","رخصة CDL مؤقتة من الفئة C","صلاحية تشغيل فيدرالية بين الولايات (رقم MC)","إعفاء مؤقت من الخروج من الخدمة"],"explanation":"يجب على المتقدّمين الذين يحتاجون إلى اختبار مهارات الحصول أولاً على تصريح متعلّم تجاري (CLP) باجتياز اختبار/اختبارات المعرفة المطلوبة. المصدر: عملية CDL لدى Oregon DMV؛ OAR 735-063-0250 / 735-063-0260."},"85":{"q":"للحصول على تصريح متعلّم تجاري من الفئة A في أوريغون، أي اختبارات معرفة يجب أن يجتازها المتقدّم؟","options":["اختبار المعرفة العامة واختبار المركبات المركّبة (بالإضافة إلى الفرامل الهوائية إن انطبق)","اختبار المعرفة العامة فقط","اختبار المعرفة العامة واختبار المواد الخطرة","اختبار المركبات المركّبة فقط"],"explanation":"يتطلب CLP من الفئة A اجتياز اختبار المعرفة العامة واختبار المركبات المركّبة، بالإضافة إلى اختبار الفرامل الهوائية إذا كانت المركبة مزودة بفرامل هوائية. المصدر: OAR 735-063-0250؛ دليل السائق التجاري في أوريغون."},"86":{"q":"ما هو الحد الأدنى لدرجة النجاح في اختبارات معرفة CDL في أوريغون؟","options":["80 percent من الإجابات صحيحة","70 percent من الإجابات صحيحة","90 percent من الإجابات صحيحة","75 percent من الإجابات صحيحة"],"explanation":"يُشترط الحصول على درجة لا تقل عن 80 percent من الإجابات الصحيحة لاجتياز كل اختبار معرفة لـ CDL في أوريغون (مثلاً 40 من 50 سؤالاً في اختبار المعرفة العامة). المصدر: دليل السائق التجاري في أوريغون / Oregon DMV؛ 49 CFR 383.135."},"87":{"q":"يتكوّن اختبار مهارات CDL في أوريغون من ثلاثة أجزاء يجب أداؤها بترتيب محدد. ما هو ذلك الترتيب؟","options":["فحص المركبة قبل الرحلة، ثم مهارات التحكم الأساسية، ثم القيادة على الطريق","القيادة على الطريق، ثم فحص ما قبل الرحلة، ثم مهارات التحكم الأساسية","مهارات التحكم الأساسية، ثم القيادة على الطريق، ثم فحص ما قبل الرحلة","فحص ما قبل الرحلة، ثم القيادة على الطريق، ثم مهارات التحكم الأساسية"],"explanation":"يُجرى اختبار المهارات بالترتيب: فحص المركبة قبل الرحلة أولاً، ثم مهارات التحكم الأساسية، ثم القيادة على الطريق؛ ويجب اجتياز كل جزء قبل الانتقال إلى التالي. المصدر: OAR 735-063-0260 / OAR 735-060-0120."},"88":{"q":"يجب إكمال تدريب السائقين المبتدئين الفيدرالي (ELDT) قبل الاختبار في أوريغون لأيٍّ مما يلي؟","options":["الحصول على رخصة CDL من الفئة A أو B لأول مرة، أو ترقية الفئة B إلى A، أو تظهيرات الركاب/الحافلة المدرسية/المواد الخطرة لأول مرة","كل تجديد لرخصة CDL، بغض النظر عن الفئة","فقط للسائقين دون سن 21 عاماً","فقط عند إضافة تظهير المقطورات المزدوجة/الثلاثية"],"explanation":"يُطلب ELDT قبل الاختبار للحصول على رخصة CDL من الفئة A أو B لأول مرة، أو ترقية الفئة B إلى الفئة A، أو الحصول على تظهير الركاب أو الحافلة المدرسية أو المواد الخطرة لأول مرة. المصدر: Oregon DMV؛ 49 CFR Part 380 Subpart F."},"89":{"q":"يجب أن يقدّم تدريب السائقين المبتدئين (ELDT) لرخصة CDL في أوريغون كيانٌ مُدرَج أين؟","options":["في سجل مقدّمي التدريب (TPR) لدى FMCSA","في قائمة المدارس الثانوية المعتمدة لدى Oregon DMV","في قائمة أعضاء جمعيات النقل بالشاحنات في أوريغون","لدى مكتب التلمذة الصناعية التابع لوزارة العمل الأمريكية"],"explanation":"يجب إكمال تعليم ELDT من خلال مدرسة أو كيان مُدرَج في سجل مقدّمي التدريب (TPR) لدى FMCSA قبل جدولة اختبار المهارات أو إجراء اختبار معرفة المواد الخطرة. المصدر: Oregon DMV؛ سجل مقدّمي التدريب لدى FMCSA."},"90":{"q":"كم من الوقت يجب الاحتفاظ بتصريح المتعلّم التجاري في أوريغون قبل أن يتمكن حامله من إجراء اختبار مهارات CDL؟","options":["14 days على الأقل","30 days على الأقل","7 days على الأقل","60 days على الأقل"],"explanation":"يجب أن تكون Oregon DMV قد أصدرت CLP غير المنتهي قبل ما لا يقل عن 14 days من اختبار المهارات. المصدر: OAR 735-063-0260."},"91":{"q":"كم تبلغ مدة صلاحية تصريح المتعلّم التجاري (CLP) في أوريغون، وهل يمكن تجديده؟","options":["صالح لمدة سنة واحدة وغير قابل للتجديد","صالح لمدة 180 days ويمكن تجديده مرة واحدة","صالح لمدة سنتين وقابل للتجديد سنوياً","صالح لمدة 90 days وغير قابل للتجديد"],"explanation":"تصريح CLP في أوريغون صالح لمدة سنة واحدة من تاريخ الإصدار وغير قابل للتجديد. المصدر: ORS 807.285."},"92":{"q":"تبقى درجة النجاح في اختبارات معرفة CDL في أوريغون (وفي اختبار مهارات مُكتمل) صالحة لكم من الوقت قبل أن يجب إصدار رخصة CDL؟","options":["ستة أشهر","ثلاثة أشهر","سنة واحدة","ثلاثون يوماً"],"explanation":"تبقى درجة النجاح في اختبار المعرفة صالحة لمدة ستة أشهر، وتبقى درجة النجاح في اختبار مهارات CDL المُكتمل صالحة لمدة ستة أشهر. المصدر: OAR 735-063-0250 وOAR 735-063-0260."},"93":{"q":"بعد الإصدار، كم تبلغ مدة صلاحية رخصة CDL في أوريغون قبل أن يجب تجديدها؟","options":["8 years","4 years","5 years","10 years"],"explanation":"رخصة CDL في أوريغون الصادرة لمواطن أمريكي أو مقيم دائم صالحة لمدة 8 years، وهي نفس الدورة القياسية لرخصة قيادة عادية في أوريغون. المصدر: Oregon DMV؛ ORS Chapter 807."},"94":{"q":"ما هي نافذة تجديد رخصة CDL في أوريغون بالنسبة لتاريخ انتهاء الصلاحية؟","options":["حتى 12 months قبل انتهاء الصلاحية وحتى 2 years بعد انتهاء الصلاحية","فقط في تاريخ انتهاء الصلاحية أو بعده، دون تجديد مبكر","حتى 30 days قبل وحتى 30 days بعد انتهاء الصلاحية","حتى 6 months قبل انتهاء الصلاحية فقط"],"explanation":"يمكن تجديد رخصة CDL في أوريغون حتى 12 months قبل انتهاء صلاحيتها وحتى 2 years بعد انتهائها؛ وبعد ذلك يجب على السائق التقدّم للحصول على رخصة جديدة. المصدر: Oregon DMV \"Renewing a Commercial Driver License\"."},"95":{"q":"ما هي المستندات التي يجب على متقدّم CDL/CLP في أوريغون تقديمها لإثبات الأهلية عند التقديم؟","options":["إثبات الاسم القانوني الكامل، والجنسية الأمريكية أو الإقامة الدائمة القانونية، والهوية، وتاريخ الميلاد، وعنوان الإقامة، ورقم الضمان الاجتماعي","فقط صورة جواز سفر حديثة وبطاقة ائتمان","خطاب موثّق من صاحب العمل وسند ملكية مركبة","إثبات ثلاث سنوات من الخبرة في القيادة التجارية"],"explanation":"يجب على المتقدّمين تقديم إثبات الاسم القانوني الكامل، والجنسية الأمريكية أو الإقامة الدائمة القانونية، والهوية، وتاريخ الميلاد، وعنوان الإقامة، بالإضافة إلى رقم الضمان الاجتماعي. المصدر: Oregon DMV \"Getting a CDL or CLP\"؛ OAR 735-063-0250."},"96":{"q":"عند تجديد رخصة CDL في أوريغون تحمل تظهير المواد الخطرة (HazMat)، ما هو المتطلب الإضافي الذي ينطبق؟","options":["اجتياز اختبار معرفة HazMat والحصول على فحص أمني (تقييم تهديد) حالي من TSA","تقديم خطاب موثّق من الشاحن الأخير في السجل","تسليم رخصة CDL لمدة 30 days أثناء مراجعة الفحص","اجتياز اختبار مهارات ثانٍ على الطريق في مركبة تحمل لوحات"],"explanation":"يتطلب تجديد رخصة CDL تحمل تظهير HazMat اجتياز اختبار معرفة HazMat والحصول على تقييم تهديد أمني (فحص خلفية) حالي من TSA. المصدر: Oregon DMV \"Renewing a CDL\"؛ 49 CFR Part 1572."},"97":{"q":"إذا ترك حامل رخصة CDL في أوريغون شهادة فاحص طبي مطلوبة تنتهي صلاحيتها (لمصادقة ذاتية غير مستثناة)، فماذا تفعل Oregon DMV؟","options":["تخفّض رخصة CDL، مزيلةً امتيازات القيادة التجارية حتى تُودَع شهادة طبية صالحة في الملف","تعلّق امتيازات القيادة العادية (الفئة C) أيضاً","تصدر إعفاءً طبياً تلقائياً لمدة 90 days دون الحاجة إلى أي إجراء","تحيل السائق إلى شرطة ولاية أوريغون لإصدار مخالفة"],"explanation":"إذا انتهت صلاحية الشهادة الطبية لسائق غير مستثنى ولم تكن هناك شهادة سارية في الملف، تخفّض Oregon DMV رخصة CDL، مزيلةً الامتيازات التجارية حتى تُقدَّم شهادة صالحة؛ وتبقى الرخصة العادية. المصدر: المصادقة الطبية لـ CDL لدى Oregon DMV؛ 49 CFR 383.73."}}};
